import type { Spell } from '../../types';

export const ALL_SPELLS: Spell[] = [
  // CANTRIPS
  { id: 'fire-bolt', name: 'Fire Bolt', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn\'t being worn or carried.\n\nThis spell\'s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage', 'ranged'] },
  { id: 'eldritch-blast', name: 'Eldritch Blast', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage.\n\nThe spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', classes: ['warlock'], damageType: 'force', tags: ['damage', 'ranged'] },
  { id: 'sacred-flame', name: 'Sacred Flame', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a Dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['cleric'], damageType: 'radiant', savingThrow: 'dex', tags: ['damage'] },
  { id: 'guidance', name: 'Guidance', level: 0, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.', classes: ['cleric', 'druid'], tags: ['buff', 'utility'] },
  { id: 'mage-hand', name: 'Mage Hand', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.\n\nYou can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.\n\nThe hand can\'t attack, activate magic items, or carry more than 10 pounds.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'prestidigitation', name: 'Prestidigitation', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Up to 1 hour', concentration: false, ritual: false, description: 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within range: You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor. You instantaneously light or snuff out a candle, a torch, or a small campfire. You instantaneously clean or soil an object no larger than 1 cubic foot. You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour. You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour. You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'minor-illusion', name: 'Minor Illusion', level: 0, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a bit of fleece', duration: '1 minute', concentration: false, ritual: false, description: 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.\n\nIf you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else\'s voice, a lion\'s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.\n\nIf you create an image of an object—such as a chair, muddy footprints, or a small chest—it must be no larger than a 5-foot cube. The image can\'t create sound, light, smell, or any other sensory effect.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'illusion'] },
  { id: 'vicious-mockery', name: 'Vicious Mockery', level: 0, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a Wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.\n\nThis spell\'s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', classes: ['bard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'debuff'] },
  { id: 'toll-the-dead', name: 'Toll the Dead', level: 0, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point at one creature you can see within range, and the sound of a dolorous bell fills the air around it for a moment. The target must succeed on a Wisdom saving throw or take 1d8 necrotic damage. If the target is missing any of its hit points, it instead takes 1d12 necrotic damage.\n\nThe spell\'s damage increases by one die when you reach 5th level (2d8 or 2d12), 11th level (3d8 or 3d12), and 17th level (4d8 or 4d12).', classes: ['cleric', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'wis', tags: ['damage'] },
  { id: 'shillelagh', name: 'Shillelagh', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'mistletoe, a shamrock leaf, and a club or quarterstaff', duration: '1 minute', concentration: false, ritual: false, description: 'The wood of a club or quarterstaff you are holding is imbued with nature\'s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon\'s damage die becomes a d8. The weapon also becomes magical, if it isn\'t already. The spell ends if you cast it again or if you let go of the weapon.', classes: ['druid'], tags: ['buff'] },
  { id: 'thunderclap', name: 'Thunderclap', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self (5-foot radius)', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a burst of thunderous sound that can be heard up to 100 feet away. Each creature within range, other than you, must succeed on a Constitution saving throw or take 1d6 thunder damage.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'ray-of-frost', name: 'Ray of Frost', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'wizard'], damageType: 'cold', tags: ['damage', 'control'] },
  { id: 'acid-splash', name: 'Acid Splash', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a bubble of acid. Choose one creature you can see within range, or choose two creatures you can see within range that are within 5 feet of each other. A target must succeed on a Dexterity saving throw or take 1d6 acid damage.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['sorcerer', 'wizard'], damageType: 'acid', savingThrow: 'dex', tags: ['damage'] },
  { id: 'chill-touch', name: 'Chill Touch', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can\'t regain hit points until the start of your next turn. Until then, the hand clings to the target.\n\nIf you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', tags: ['damage', 'debuff'] },
  { id: 'spare-the-dying', name: 'Spare the Dying', level: 0, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.', classes: ['cleric'], tags: ['healing', 'utility'] },
  { id: 'light', name: 'Light', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'M'], materialComponent: 'a firefly or phosphorescent moss', duration: '1 hour', concentration: false, ritual: false, description: 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.\n\nIf you target an object held or worn by a hostile creature, that creature must succeed on a Dexterity saving throw to avoid the spell.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], savingThrow: 'dex', tags: ['utility'] },
  { id: 'thaumaturgy', name: 'Thaumaturgy', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Up to 1 minute', concentration: false, ritual: false, description: 'You manifest a minor wonder, a sign of supernatural power, within range. You create one of the following magical effects within range: Your voice booms up to three times as loud as normal for 1 minute. You cause flames to flicker, brighten, dim, or change color for 1 minute. You cause harmless tremors in the ground for 1 minute. You create an instantaneous sound that originates from a point of your choice within range, such as a rumble of thunder, the cry of a raven, or ominous whispers. You instantaneously cause an unlocked door or window to fly open or slam shut. You alter the appearance of your eyes for 1 minute.', classes: ['cleric'], tags: ['utility'] },
  { id: 'druidcraft', name: 'Druidcraft', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Whispering to the spirits of nature, you create one of the following effects within range: You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. You instantly make a flower blossom, a seed pod open, or a leaf bud bloom. You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint odor of skunk. You light or snuff out a candle, a torch, or a small campfire.', classes: ['druid'], tags: ['utility'] },
  // LEVEL 1
  { id: 'magic-missile', name: 'Magic Missile', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'force', tags: ['damage'] },
  { id: 'burning-hands', name: 'Burning Hands', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a Dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire ignites any flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'cure-wounds', name: 'Cure Wounds', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', classes: ['artificer', 'bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing'] },
  { id: 'healing-word', name: 'Healing Word', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', classes: ['bard', 'cleric', 'druid'], tags: ['healing'] },
  { id: 'shield', name: 'Shield', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you are hit by an attack or targeted by the magic missile spell', range: 'Self', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'reaction'] },
  { id: 'mage-armor', name: 'Mage Armor', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a piece of cured leather', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature who isn\'t wearing armor, and a protective magical force surrounds it until the spell ends. The target\'s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.', classes: ['sorcerer', 'wizard'], tags: ['defense', 'buff'] },
  { id: 'sleep', name: 'Sleep', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of fine sand, rose petals, or a cricket', duration: '1 minute', concentration: false, ritual: false, description: 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).\n\nStarting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['control'] },
  { id: 'charm-person', name: 'Charm Person', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You attempt to charm a humanoid you can see within range. It must make a Wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'social'] },
  { id: 'thunderwave', name: 'Thunderwave', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cube)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of thunderous force sweeps out from you. Each creature in a 15-foot cube originating from you must make a Constitution saving throw. On a failed save, a creature takes 2d8 thunder damage and is pushed 10 feet away from you. On a successful save, the creature takes half as much damage and isn\'t pushed.\n\nIn addition, unsecured objects that are completely within the area of effect are automatically pushed 10 feet away from you by the spell\'s effect, and the spell emits a thunderous boom audible out to 300 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'bless', name: 'Bless', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a sprinkling of holy water', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', classes: ['cleric', 'paladin'], tags: ['buff'] },
  { id: 'hex', name: 'Hex', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'the petrified eye of a newt', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You place a curse on a creature that you can see within range. Until the spell ends, you deal an extra 1d6 necrotic damage to the target whenever you hit it with an attack. Also, choose one ability when you cast the spell. The target has disadvantage on ability checks made with the chosen ability.\n\nIf the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to curse a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['warlock'], damageType: 'necrotic', tags: ['debuff', 'damage'] },
  { id: 'hunters-mark', name: "Hunter's Mark", level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 bonus action', range: '90 feet', components: ['V'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', classes: ['ranger'], tags: ['damage', 'buff'] },
  { id: 'find-familiar', name: 'Find Familiar', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 hour', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: '10 gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.', classes: ['wizard'], tags: ['utility'] },
  { id: 'divine-smite', name: 'Divine Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'The first time you hit with a melee weapon attack during this spell\'s duration, your weapon flares with white-hot intensity, and the attack deals an extra 2d8 radiant damage to the target. The spell then ends. If you hit a fiend or an undead, the attack deals an extra 1d8 radiant damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the extra damage increases by 1d8 for each slot level above 1st (maximum 5d8). The damage increases by another 1d8 if the target is an undead or a fiend (maximum 6d8).', classes: ['paladin'], damageType: 'radiant', tags: ['damage'] },
  { id: 'guiding-bolt', name: 'Guiding Bolt', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['cleric'], damageType: 'radiant', tags: ['damage', 'buff'] },
  { id: 'inflict-wounds', name: 'Inflict Wounds', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', classes: ['cleric'], damageType: 'necrotic', tags: ['damage'] },
  { id: 'detect-magic', name: 'Detect Magic', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', classes: ['artificer', 'bard', 'cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'identify', name: 'Identify', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pearl worth at least 100 gp and an owl feather', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.\n\nIf you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.', classes: ['artificer', 'bard', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'sanctuary', name: 'Sanctuary', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a small silver mirror', duration: '1 minute', concentration: false, ritual: false, description: 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a Wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn\'t protect the warded creature from area effects, such as the explosion of a fireball.\n\nIf the warded creature makes an attack, casts a spell that affects an enemy, or deals damage to another creature, this spell ends.', classes: ['artificer', 'cleric'], savingThrow: 'wis', tags: ['defense', 'utility'] },
  // LEVEL 2
  { id: 'misty-step', name: 'Misty Step', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'scorching-ray', name: 'Scorching Ray', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several. Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage'] },
  { id: 'hold-person', name: 'Hold Person', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a humanoid that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.\n\nA paralyzed creature is incapacitated and can\'t move or speak. The creature automatically fails Strength and Dexterity saving throws. Attack rolls against the creature have advantage. Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd. The humanoids must be within 30 feet of each other when you target them.', classes: ['bard', 'cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'invisibility', name: 'Invisibility', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an eyelash encased in gum arabic', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person. The spell ends for a target that attacks or casts a spell.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', classes: ['artificer', 'bard', 'sorcerer', 'warlock', 'wizard'], tags: ['stealth', 'utility'] },
  { id: 'spiritual-weapon', name: 'Spiritual Weapon', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.\n\nAs a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above 2nd.', classes: ['cleric'], damageType: 'force', tags: ['damage', 'bonus-action'] },
  { id: 'shatter', name: 'Shatter', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a chip of mica', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.\n\nA nonmagical object that isn\'t being worn or carried also takes the damage if it\'s in the spell\'s area.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'lesser-restoration', name: 'Lesser Restoration', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature and can end either one disease or one condition afflicting it. The condition can be blinded, deafened, paralyzed, or poisoned.', classes: ['artificer', 'bard', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['healing', 'utility'] },
  { id: 'prayer-of-healing', name: 'Prayer of Healing', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '10 minutes', range: '30 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  { id: 'mirror-image', name: 'Mirror Image', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it\'s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.\n\nEach time a creature targets you with an attack during the spell\'s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'blur', name: 'Blur', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn\'t rely on sight, as with blindsight, or can see through illusions, as with truesight.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['defense', 'illusion'] },
  { id: 'moonbeam', name: 'Moonbeam', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'several seeds of any moonseed plant and a piece of opalescent feldspar', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A silvery beam of pale light shines down in a 5-foot-radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.\n\nWhen a creature enters the spell\'s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a Constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.\n\nA shapechanger makes its saving throw with disadvantage. If it fails, it also instantly reverts to its original form and can\'t assume a different form until it leaves the spell\'s light.\n\nOn each of your turns after you cast this spell, you can use an action to move the beam up to 60 feet in any direction.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d10 for each slot level above 2nd.', classes: ['druid'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  // LEVEL 3
  { id: 'fireball', name: 'Fireball', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny ball of bat guano and sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.\n\nThe fire spreads around corners. It ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'lightning-bolt', name: 'Lightning Bolt', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (100-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur and a rod of amber, crystal, or glass', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a Dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.\n\nThe lightning ignites flammable objects in the area that aren\'t being worn or carried.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'counterspell', name: 'Counterspell', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 reaction, which you take when you see a creature within 60 feet of you casting a spell', range: '60 feet', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a success, the creature\'s spell fails and has no effect.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['reaction', 'defense', 'counter'] },
  { id: 'dispel-magic', name: 'Dispel Magic', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell\'s level. On a successful check, the spell ends.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell\'s level is equal to or less than the level of the spell slot you used.', classes: ['artificer', 'bard', 'cleric', 'druid', 'paladin', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'counter'] },
  { id: 'fly', name: 'Fly', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a wing feather from any bird', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'haste', name: 'Haste', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a shaving of licorice root', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a willing creature that you can see within range. Until the spell ends, the target\'s speed is doubled, it gains a +2 bonus to AC, it has advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.\n\nWhen the spell ends, the target can\'t move or take actions until after its next turn, as a wave of lethargy sweeps over it.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['buff', 'control'] },
  { id: 'spirit-guardians', name: 'Spirit Guardians', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot radius)', components: ['V', 'S', 'M'], materialComponent: 'a holy symbol', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.\n\nWhen you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature\'s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a Wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.', classes: ['cleric'], damageType: 'radiant', savingThrow: 'wis', tags: ['damage', 'aoe', 'control'] },
  { id: 'revivify', name: 'Revivify', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamonds worth 300 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can\'t return to life a creature that has died of old age, nor can it restore any missing body parts.', classes: ['artificer', 'cleric', 'paladin'], tags: ['healing', 'utility'] },
  { id: 'mass-healing-word', name: 'Mass Healing Word', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.', classes: ['cleric'], tags: ['healing', 'aoe'] },
  // LEVEL 4
  { id: 'banishment', name: 'Banishment', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'an item distasteful to the target', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to send one creature that you can see within range to another place of existence. The target must succeed on a Charisma saving throw or be banished.\n\nIf the target is native to the plane of existence you\'re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.\n\nIf the target is native to a different plane of existence than the one you\'re on, the target is banished with a faint popping noise, returning to its home plane. If the spell ends before 1 minute has passed, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied. Otherwise, the target doesn\'t return.', atHigherLevels: 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.', classes: ['cleric', 'paladin', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'cha', tags: ['control'] },
  { id: 'polymorph', name: 'Polymorph', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a caterpillar cocoon', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a Wisdom saving throw to avoid the effect. The spell has no effect on a shapechanger or a creature with 0 hit points.\n\nThe transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target\'s (or the target\'s level, if it doesn\'t have a challenge rating). The target\'s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast. It retains its alignment and personality.\n\nThe target assumes the hit points of its new form. When it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn\'t reduce the creature\'s normal form to 0 hit points, it isn\'t knocked unconscious.\n\nThe creature is limited in the actions it can perform by the nature of its new form, and it can\'t cast spells, speak, or take any other action that requires hands or speech. The target\'s gear melds into the new form. The creature can\'t activate, use, wield, or otherwise benefit from any of its equipment.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'utility'] },
  { id: 'dimension-door', name: 'Dimension Door', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '500 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."\n\nYou can bring along objects as long as their weight doesn\'t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity. The creature must be within 5 feet of you when you cast this spell.\n\nIf you would arrive in a place already occupied by an object or a creature, you and any creature traveling with you each take 4d6 force damage, and the spell fails to teleport you.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['movement', 'utility'] },
  { id: 'greater-invisibility', name: 'Greater Invisibility', level: 4, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You or a creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target\'s person.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['stealth', 'buff'] },
  // LEVEL 5
  { id: 'hold-monster', name: 'Hold Monster', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, straight piece of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or be paralyzed for the duration. This spell has no effect on undead. At the end of each of its turns, the target can make another Wisdom saving throw. On a success, the spell ends on the target.\n\nA paralyzed creature is incapacitated and can\'t move or speak. The creature automatically fails Strength and Dexterity saving throws. Attack rolls against the creature have advantage. Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th. The creatures must be within 30 feet of each other when you target them.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'cone-of-cold', name: 'Cone of Cold', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot cone)', components: ['V', 'S', 'M'], materialComponent: 'a small crystal or glass cone', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a Constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one.\n\nA creature killed by this spell becomes a frozen statue until it thaws.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', classes: ['sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'mass-cure-wounds', name: 'Mass Cure Wounds', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.', classes: ['bard', 'cleric', 'druid'], tags: ['healing', 'aoe'] },
  { id: 'wall-of-force', name: 'Wall of Force', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powder made by crushing a clear gemstone', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. In any form, the wall is 1/4 inch thick. It lasts for the duration. If the wall cuts through a creature\'s space when it appears, the creature is pushed to one side of the wall (your choice which side).\n\nNothing can physically pass through the wall. It is immune to all damage and can\'t be dispelled by dispel magic. A disintegrate spell destroys the wall instantly, however. The wall also extends into the Ethereal Plane, blocking ethereal travel through the wall.', classes: ['wizard'], tags: ['control', 'utility'] },
  { id: 'flame-strike', name: 'Flame Strike', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'pinch of sulfur', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a Dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.', classes: ['cleric'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  // LEVEL 6
  { id: 'chain-lightning', name: 'Chain Lightning', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.\n\nA target must make a Dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'true-seeing', name: 'True Seeing', level: 6, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an ointment for the eyes that costs 25 gp; is made from mushroom powder, saffron, and fat; and is consumed by the spell', duration: '1 hour', concentration: false, ritual: false, description: 'You give the willing creature you touch the ability to see things as they actually are. For the duration, the creature has truesight, notices secret doors hidden by magic, and can see into the Ethereal Plane, all out to a range of 120 feet.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'detection'] },
  // LEVEL 7
  { id: 'finger-of-death', name: 'Finger of Death', level: 7, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a Constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful one.\n\nA humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command, following your verbal orders to the best of its ability.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'teleport', name: 'Teleport', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can\'t be held or carried by an unwilling creature.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['movement', 'utility'] },
  // LEVEL 8
  { id: 'power-word-stun', name: 'Power Word Stun', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Until ended', concentration: false, ritual: false, description: 'You speak a word of power that overwhelms the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.\n\nThe stunned target must make a Constitution saving throw at the end of each of its turns. On a successful save, the stunning effect ends.', classes: ['sorcerer', 'warlock', 'wizard'], savingThrow: 'con', tags: ['control'] },
  // LEVEL 9
  { id: 'wish', name: 'Wish', level: 9, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.\n\nThe basic use of this spell is to duplicate any other spell of 8th level or lower. You don\'t need to meet any requirements in that spell, including costly components. The spell simply takes effect. Alternatively, you can create one of the following effects of your choice: You create one object of up to 25,000 gp in value that isn\'t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground. You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell. You grant up to ten creatures that you can see immunity to a single spell or other magical effect for 8 hours. You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result.', classes: ['sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'power-word-kill', name: 'Power Word Kill', level: 9, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['damage'] },
  { id: 'meteor-swarm', name: 'Meteor Swarm', level: 9, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '1 mile', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a Dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once. The spell damages objects in the area and ignites flammable objects that aren\'t being worn or carried.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },

  // ── ADDITIONAL CANTRIPS ──────────────────────────────────────────────────
  { id: 'message', name: 'Message', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a short piece of copper wire', duration: '1 round', concentration: false, ritual: false, description: 'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.\n\nYou can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn\'t have to follow a straight line and can travel freely around corners or through openings.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'dancing-lights', name: 'Dancing Lights', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of phosphorus or wychwood, or a glowworm', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can also combine the four lights into one glowing vaguely humanoid form of Medium size. Whichever form you choose, each light sheds dim light in a 10-foot radius.\n\nAs a bonus action on your turn, you can move the lights up to 60 feet to a new spot within range. A light must be within 20 feet of another light created by this spell, and a light winks out if it exceeds the spell\'s range.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility', 'light'] },
  { id: 'shocking-grasp', name: 'Shocking Grasp', level: 0, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can\'t take reactions until the start of its next turn.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['sorcerer', 'wizard'], damageType: 'lightning', tags: ['damage', 'melee'] },
  { id: 'poison-spray', name: 'Poison Spray', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a Constitution saving throw or take 1d12 poison damage.\n\nThis spell\'s damage increases by 1d12 when you reach 5th level (2d12), 11th level (3d12), and 17th level (4d12).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage'] },
  { id: 'true-strike', name: 'True Strike', level: 0, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['S'], duration: 'Concentration, up to 1 round', concentration: true, ritual: false, description: 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target\'s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn\'t ended.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'resistance', name: 'Resistance', level: 0, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a miniature cloak', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one saving throw of its choice. It can roll the die before or after making the saving throw. The spell then ends.', classes: ['cleric', 'druid'], tags: ['buff'] },
  { id: 'mending', name: 'Mending', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'two lodestones', duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell repairs a single break or tear in an object you touch, such as a broken chain link, two halves of a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no larger than 1 foot in any dimension, you mend it, leaving no trace of the former damage.\n\nThis spell can physically repair a magic item or construct, but the spell can\'t restore magic to such an object.', classes: ['bard', 'cleric', 'druid', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'blade-ward', name: 'Blade Ward', level: 0, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'You extend your hand and trace a sigil of warding in the air. Until the end of your next turn, you have resistance against bludgeoning, piercing, and slashing damage dealt by weapon attacks.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['defense'] },
  { id: 'friends', name: 'Friends', level: 0, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['S', 'M'], materialComponent: 'a small amount of makeup applied to the face as this spell is cast', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'For the duration, you have advantage on all Charisma checks directed at one creature of your choice that isn\'t hostile toward you. When the spell ends, the creature realizes that you used magic to influence its mood and becomes hostile toward you. A creature prone to violence might attack you. Another creature might seek retribution in other ways (at the DM\'s discretion), depending on the nature of your interaction with it.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['social', 'enchantment'] },
  { id: 'produce-flame', name: 'Produce Flame', level: 0, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: false, description: 'A flickering flame appears in your hand. The flame remains there for the duration and harms neither you nor your equipment. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The spell ends if you dismiss it as an action or if you cast it again.\n\nYou can also attack with the flame, although doing so ends the spell. When you cast this spell, or as an action on a later turn, you can hurl the flame at a creature within 30 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 fire damage.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['druid'], damageType: 'fire', tags: ['damage', 'light'] },
  { id: 'infestation', name: 'Infestation', level: 0, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a living flea', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause a cloud of mites, fleas, and other parasites to appear momentarily on one creature you can see within range. The target must succeed on a Constitution saving throw, or it takes 1d6 poison damage and moves 5 feet in a random direction if it can move and its speed is at least 5 feet. Roll a d4 for the direction: 1, north; 2, south; 3, east; or 4, west. This movement doesn\'t provoke opportunity attacks, and if the direction rolled is blocked, the target doesn\'t move.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage'] },
  { id: 'frostbite', name: 'Frostbite', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause numbing frost to form on one creature that you can see within range. The target must make a Constitution saving throw. On a failed save, the target takes 1d6 cold damage, and it has disadvantage on the next weapon attack roll it makes before the end of its next turn.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage'] },
  { id: 'word-of-radiance', name: 'Word of Radiance', level: 0, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '5 feet', components: ['V', 'M'], materialComponent: 'a holy symbol', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a divine word, and burning radiance erupts from you. Each creature of your choice that you can see within range must succeed on a Constitution saving throw or take 1d6 radiant damage.\n\nThe spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['cleric'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },

  // ── ADDITIONAL LEVEL 1 SPELLS ────────────────────────────────────────────
  { id: 'armor-of-agathys', name: 'Armor of Agathys', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a cup of water', duration: '1 hour', concentration: false, ritual: false, description: 'A protective magical force surrounds you, manifesting as a spectral frost that covers you and your gear. You gain 5 temporary hit points for the duration. If a creature hits you with a melee attack while you have these hit points, the creature takes 5 cold damage.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, both the temporary hit points and the cold damage increase by 5 for each slot level above 1st.', atHigherLevels: 'Both the temporary hit points and cold damage increase by 5 for each slot level above 1st.', classes: ['warlock'], damageType: 'cold', tags: ['defense', 'temp-hp'] },
  { id: 'command', name: 'Command', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: '1 round', concentration: false, ritual: false, description: 'You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn\'t understand your language, or if your command is directly harmful to it.\n\nSome typical commands and their effects follow. You might issue a command other than one described here. If you do so, the DM determines how the target behaves. Drop. The target drops whatever it is holding and then ends its turn. Flee. The target spends its turn moving away from you by the fastest available means. Grovel. The target falls prone and then ends its turn. Halt. The target doesn\'t move and takes no actions. Approach. The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st.', atHigherLevels: 'Affect one additional creature for each slot level above 1st.', classes: ['cleric', 'paladin'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'comprehend-languages', name: 'Comprehend Languages', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a pinch of soot and salt', duration: '1 hour', concentration: false, ritual: true, description: 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text.\n\nThis spell doesn\'t decode secret messages in a text or a glyph, such as an arcane sigil, that isn\'t part of a written language.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'disguise-self', name: 'Disguise Self', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You make yourself—including your clothing, armor, weapons, and other belongings on your person—look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can\'t change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you.\n\nThe changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel your head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.\n\nTo discern that you are disguised, a creature can use its action to inspect your appearance and must succeed on an Intelligence (Investigation) check against your spell save DC.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['illusion', 'utility'] },
  { id: 'entangle', name: 'Entangle', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Grasping weeds and vines sprout from the ground in a 20-foot square starting from a point within range. For the duration, these plants turn the ground in the area into difficult terrain.\n\nA creature in the area when you cast the spell must succeed on a Strength saving throw or be restrained by the entangling plants until the spell ends. A creature restrained by the plants can use its action to make a Strength check against your spell save DC. On a success, it frees itself.\n\nWhen the spell ends, the conjured plants wilt away.', classes: ['druid'], savingThrow: 'str', tags: ['control', 'difficult-terrain'] },
  { id: 'faerie-fire', name: 'Faerie Fire', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius.\n\nAny attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can\'t benefit from being invisible.', classes: ['artificer', 'bard', 'druid'], savingThrow: 'dex', tags: ['control', 'buff'] },
  { id: 'feather-fall', name: 'Feather Fall', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 reaction', range: '60 feet', components: ['V', 'M'], materialComponent: 'a small feather or piece of down', duration: '1 minute', concentration: false, ritual: false, description: 'Choose up to five falling creatures within range. A falling creature\'s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['utility', 'reaction'] },
  { id: 'fog-cloud', name: 'Fog Cloud', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the radius of the fog increases by 20 feet for each slot level above 1st.', atHigherLevels: 'The radius of the fog increases by 20 feet for each slot level above 1st.', classes: ['druid', 'ranger', 'sorcerer', 'wizard'], tags: ['control', 'obscurement'] },
  { id: 'goodberry', name: 'Goodberry', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a sprig of mistletoe', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Up to ten berries appear in your hand and are infused with magic for the duration. A creature can use its action to eat one berry. Eating a berry restores 1 hit point, and the berry provides enough nourishment to sustain a creature for one day.\n\nThe berries lose their potency if they have not been consumed within 24 hours of the casting of this spell.', classes: ['druid', 'ranger'], tags: ['healing', 'utility'] },
  { id: 'hellish-rebuke', name: 'Hellish Rebuke', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 reaction', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a Dexterity saving throw. It takes 2d10 fire damage on a failed save, or half as much damage on a successful one.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d10 for each slot level above 1st.', classes: ['warlock'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'reaction'] },
  { id: 'longstrider', name: 'Longstrider', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dirt', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a creature. The target\'s speed increases by 10 feet until the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', atHigherLevels: 'Target one additional creature for each slot level above 1st.', classes: ['artificer', 'bard', 'druid', 'ranger', 'wizard'], tags: ['buff', 'movement'] },
  { id: 'protection-from-evil-good', name: 'Protection from Evil and Good', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'holy water or powdered silver and iron, which the spell consumes', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead.\n\nThe protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can\'t be charmed, frightened, or possessed by them. If the target is already charmed, frightened, or possessed by such a creature, the target has advantage on any new saving throw against the relevant effect.', classes: ['cleric', 'paladin', 'warlock', 'wizard'], tags: ['defense', 'abjuration'] },
  { id: 'speak-with-animals', name: 'Speak with Animals', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: true, description: 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day. You might be able to persuade a beast to perform a small favor for you, at the DM\'s discretion.', classes: ['bard', 'druid', 'ranger'], tags: ['utility', 'ritual'] },
  { id: 'tashas-hideous-laughter', name: "Tasha's Hideous Laughter", level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'tiny tarts and a feather that is waved in the air', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a Wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn\'t affected.\n\nAt the end of each of its turns, and each time it takes damage, the target can make another Wisdom saving throw. The target has advantage on the saving throw if it\'s triggered by damage. On a success, the spell ends.', classes: ['bard', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'unseen-servant', name: 'Unseen Servant', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of string and a bit of wood', duration: '1 hour', concentration: false, ritual: true, description: 'This spell creates an invisible, mindless, shapeless, Medium force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 hit point, and a Strength of 2, and it can\'t attack. If it drops to 0 hit points, the spell ends.\n\nOnce on each of your turns as a bonus action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human servant could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring wine. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.', classes: ['bard', 'warlock', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'witch-bolt', name: 'Witch Bolt', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a twig from a tree that has been struck by lightning', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A beam of crackling, blue energy lances out toward a creature within range, forming a sustained arc of lightning between you and the target. Make a ranged spell attack against that creature. On a hit, the target takes 1d12 lightning damage, and on each of your turns for the duration, you can use your action to deal 1d12 lightning damage to the target automatically. The spell ends if you use your action to do anything else. The spell also ends if the target is ever outside the spell\'s range or if it has total cover from you.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, the initial damage increases by 1d12 for each slot level above 1st.', atHigherLevels: 'Initial damage increases by 1d12 for each slot level above 1st.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'lightning', tags: ['damage', 'sustained'] },
  { id: 'false-life', name: 'False Life', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a small amount of alcohol or distilled spirits', duration: '1 hour', concentration: false, ritual: false, description: 'Bolstering yourself with a necromantic facsimile of life, you gain 1d4+4 temporary hit points for the duration.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you gain 5 additional temporary hit points for each slot level above 1st.', atHigherLevels: 'Gain 5 additional temporary hit points for each slot level above 1st.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['defense', 'temp-hp'] },
  { id: 'expeditious-retreat', name: 'Expeditious Retreat', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], tags: ['movement', 'buff'] },
  { id: 'silent-image', name: 'Silent Image', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fleece', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn\'t accompanied by sound, smell, or other sensory effects.\n\nYou can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['illusion', 'utility'] },
  { id: 'animal-friendship', name: 'Animal Friendship', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a morsel of food', duration: '24 hours', concentration: false, ritual: false, description: 'This spell lets you convince a beast that you mean it no harm. Choose a beast that you can see within range. It must see and hear you. If the beast\'s Intelligence is 4 or higher, the spell fails. Otherwise, the beast must succeed on a Wisdom saving throw or be charmed by you for the spell\'s duration. If you or one of your companions harms the target, the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional beast for each slot level above 1st.', atHigherLevels: 'Affect one additional beast for each slot level above 1st.', classes: ['bard', 'druid', 'ranger'], savingThrow: 'wis', tags: ['social', 'enchantment'] },

  // ── ADDITIONAL LEVEL 2 SPELLS ────────────────────────────────────────────
  { id: 'aid', name: 'Aid', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny strip of white cloth', duration: '8 hours', concentration: false, ritual: false, description: 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target\'s hit point maximum and current hit points increase by 5 for the duration.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, a target\'s hit points increase by an additional 5 for each slot level above 2nd.', atHigherLevels: 'Each target\'s hit points increase by an additional 5 for each slot level above 2nd.', classes: ['artificer', 'cleric', 'paladin'], tags: ['buff', 'healing'] },
  { id: 'blindness-deafness', name: 'Blindness/Deafness', level: 2, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: '1 minute', concentration: false, ritual: false, description: 'You can blind or deafen a foe. Choose one creature that you can see within range to make a Constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a Constitution saving throw. On a success, the spell ends.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', atHigherLevels: 'Target one additional creature for each slot level above 2nd.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'debuff'] },
  { id: 'darkness', name: 'Darkness', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'M'], materialComponent: 'bat fur and a drop of pitch or piece of coal', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can\'t see through this magical darkness, and nonmagical light can\'t illuminate it.\n\nIf the point you choose is on an object you are holding or one that isn\'t being worn or carried, the darkness emanates from the object and moves with it. Completely covering the source of the darkness with an opaque object, such as a bowl or a helm, blocks the darkness.\n\nIf any of this spell\'s area overlaps with an area of light created by a spell of 2nd level or lower, the spell that created the light is dispelled.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['control', 'obscurement'] },
  { id: 'darkvision', name: 'Darkvision', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'either a pinch of dried carrot or an agate', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'enhance-ability', name: 'Enhance Ability', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'fur or a feather from a beast', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: "You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends.\n\nBear's Endurance: The target has advantage on Constitution checks. It also gains 2d6 temporary hit points, which are lost when the spell ends.\n\nBull's Strength: The target has advantage on Strength checks, and his or her carrying capacity doubles.\n\nCat's Grace: The target has advantage on Dexterity checks. It also doesn't take damage from falling 20 feet or less if it isn't incapacitated.\n\nEagle's Splendor: The target has advantage on Charisma checks.\n\nFox's Cunning: The target has advantage on Intelligence checks.\n\nOwl's Wisdom: The target has advantage on Wisdom checks.", classes: ['artificer', 'bard', 'cleric', 'druid', 'sorcerer', 'wizard'], tags: ['buff', 'utility'] },
  { id: 'enlarge-reduce', name: 'Enlarge/Reduce', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powdered iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or a non-magical object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect.\n\nEnlarge: The target\'s size doubles in all dimensions, and its weight is multiplied by eight. This growth increases its size by one category— from Medium to Large, for example. The target also has advantage on Strength checks and Strength saving throws. The target\'s weapons also grow to match its new size. While these weapons are enlarged, the target\'s attacks with them deal 1d4 extra damage.\n\nReduce: The target\'s size is halved in all dimensions, and its weight is reduced to one-eighth of normal. This reduction decreases its size by one category. The target also has disadvantage on Strength checks and Strength saving throws. The target\'s weapons also shrink to match its new size. While these weapons are reduced, the target\'s attacks with them deal 1d4 less damage (this can\'t reduce the damage below 1).', classes: ['artificer', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'buff', 'debuff'] },
  { id: 'pass-without-trace', name: 'Pass Without Trace', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'ashes from a burned leaf of mistletoe and a sprig of spruce', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can\'t be tracked except by magical means. A creature that receives this bonus leaves behind no tracks or other traces of its passage.', classes: ['druid', 'ranger'], tags: ['stealth', 'buff'] },
  { id: 'see-invisibility', name: 'See Invisibility', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a pinch of talc and a small sprinkling of powdered silver', duration: '1 hour', concentration: false, ritual: false, description: 'For the duration, you see invisible creatures and objects as if they were visible, and you can see into the Ethereal Plane. Ethereal creatures and objects appear ghostly and translucent.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['utility', 'detection'] },
  { id: 'silence', name: 'Silence', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it. Casting a spell that includes a verbal component is impossible there.', classes: ['bard', 'cleric', 'ranger'], tags: ['control', 'ritual'] },
  { id: 'suggestion', name: 'Suggestion', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'M'], materialComponent: "a snake's tongue and either a bit of honeycomb or a drop of sweet oil", duration: 'Concentration, up to 8 hours', concentration: true, ritual: false, description: 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can\'t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act automatically negates the effect of the spell.\n\nThe target must make a Wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment', 'social'] },
  { id: 'web', name: 'Web', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of spiderweb', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area.\n\nIf the webs aren\'t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the conjured web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.\n\nEach creature that starts its turn in the webs or that enters them during its turn must make a Dexterity saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.\n\nA creature restrained by the webs can use its action to make a Strength check against your spell save DC. If it succeeds, it is no longer restrained.', classes: ['artificer', 'sorcerer', 'wizard'], savingThrow: 'dex', tags: ['control', 'difficult-terrain'] },
  { id: 'heat-metal', name: 'Heat Metal', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of iron and a flame', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose a manufactured metal object, such as a metal weapon or a suit of heavy or medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 fire damage when you cast the spell. Until the spell ends, you can use a bonus action on each of your subsequent turns to cause this damage again.\n\nIf a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a Constitution saving throw or drop the object if it can. If it doesn\'t drop the object, it has disadvantage on attack rolls and ability checks until the start of your next turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 2nd.', classes: ['artificer', 'druid'], damageType: 'fire', savingThrow: 'con', tags: ['damage', 'control'] },
  { id: 'levitate', name: 'Levitate', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds. An unwilling creature that succeeds on a Constitution saving throw is unaffected.\n\nThe target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target\'s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can use your action to move the target, which must remain within the spell\'s range.\n\nWhen the spell ends, the target floats gently to the ground if it is still aloft.', classes: ['artificer', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'utility'] },

  // ── ADDITIONAL LEVEL 3 SPELLS ────────────────────────────────────────────
  { id: 'animate-dead', name: 'Animate Dead', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 minute', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of blood, a piece of flesh, and a pinch of bone dust', duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse (the DM has the creature\'s game statistics).\n\nOn each of your turns, you can use a bonus action to mentally command any creature you made with this spell if the creature is within 60 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.\n\nThe creature is under your control for 24 hours, after which it stops obeying any command you\'ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature again before the current 24-hour period ends. This use of the spell reasserts your control over up to four creatures you have animated with this spell, rather than animating a new one.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you animate or reassert control over two additional undead creatures for each slot level above 3rd. Each of the creatures must come from a different corpse or pile of bones.', classes: ['cleric', 'wizard'], tags: ['necromancy', 'summoning'] },
  { id: 'bestow-curse', name: 'Bestow Curse', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch a creature, and that creature must succeed on a Wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options:\n\n• Choose one ability score. While cursed, the target has disadvantage on ability checks and saving throws made with that ability score.\n• While cursed, the target has disadvantage on attack rolls against you.\n• While cursed, the target must make a Wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing.\n• While the target is cursed, your attacks and spells deal an extra 1d8 necrotic damage to the target.\n\nAt Higher Levels: If you cast this spell using a spell slot of 4th level or higher, the duration is 10 minutes. If you use a spell slot of 5th level or higher, the duration is 8 hours.', atHigherLevels: '4th level: 10 minutes. 5th+ level: 8 hours. Both without concentration.', classes: ['cleric', 'wizard'], savingThrow: 'wis', tags: ['debuff', 'curse'] },
  { id: 'call-lightning', name: 'Call Lightning', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can\'t see a point in the air where the storm cloud could appear (for example, if you are in a room that can\'t accommodate the cloud).\n\nWhen you cast the spell, choose a point you can see within range. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a Dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one.\n\nOn each of your turns until the spell ends, you can use your action to call down lightning in this way again, targeting the same point or a different one.\n\nIf you are outdoors in stormy conditions when you cast this spell, the spell gives you control over the existing storm instead of creating a new one. Under such conditions, the spell\'s damage increases by 1d10.', atHigherLevels: 'When you cast this spell using a spell slot of 4th or higher level, the damage increases by 1d10 for each slot level above 3rd.', classes: ['druid'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'aoe', 'sustained'] },
  { id: 'fear', name: 'Fear', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a white feather or the heart of a hen', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You project a phantasmal image of a creature\'s worst fears. Each creature in a 30-foot cone must succeed on a Wisdom saving throw or drop whatever it is holding and become frightened for the duration.\n\nWhile frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns, unless there is nowhere to move. If the creature ends its turn in a location where it doesn\'t have line of sight to you, the creature can make a Wisdom saving throw. On a successful save, the spell ends for that creature.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'fear'] },
  { id: 'hypnotic-pattern', name: 'Hypnotic Pattern', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['S', 'M'], materialComponent: 'a glowing stick of incense or a crystal vial filled with phosphorescent material', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a Wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.\n\nThe spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'plant-growth', name: 'Plant Growth', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action or 8 hours', range: '150 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell channels vitality into plants within a specific area. There are two possible uses for the spell, granting either immediate or long-term benefits.\n\nIf you cast this spell using 1 action, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.\n\nIf you cast this spell over 8 hours, you enrich the land. All plants in a half-mile radius centered on a point within range become enriched for 1 year. The plants yield twice the normal amount of food when harvested.', classes: ['bard', 'druid', 'ranger'], tags: ['control', 'difficult-terrain', 'utility'] },
  { id: 'protection-from-energy', name: 'Protection from Energy', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.', classes: ['artificer', 'cleric', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['defense', 'resistance'] },
  { id: 'sending', name: 'Sending', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Unlimited', components: ['V', 'S', 'M'], materialComponent: 'a short piece of fine copper wire', duration: '1 round', concentration: false, ritual: false, description: 'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.\n\nYou can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn\'t arrive.', classes: ['bard', 'cleric', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'slow', name: 'Slow', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of molasses', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a Wisdom saving throw or be affected by this spell for the duration.\n\nAn affected target\'s speed is halved, it takes a −2 penalty to AC and Dexterity saving throws, and it can\'t use reactions. On its turn, it can use either an action or a bonus action, not both. Regardless of the creature\'s abilities or magic items, it can\'t make more than one melee or ranged attack during its turn.\n\nIf the creature attempts to cast a spell with a casting time of 1 action, roll a d20. On an 11 or higher, the spell doesn\'t take effect until the creature\'s next turn, and the creature must use its action on that turn to complete the spell. If it can\'t, the spell is wasted.', classes: ['sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'debuff'] },
  { id: 'speak-with-dead', name: 'Speak with Dead', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'burning incense', duration: '10 minutes', concentration: false, ritual: false, description: 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can\'t be undead. The spell fails if the corpse was the target of this spell within the last 10 days.\n\nUntil the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are hostile to it or it recognizes you as an enemy.', classes: ['bard', 'cleric'], tags: ['utility', 'necromancy', 'ritual'] },
  { id: 'stinking-cloud', name: 'Stinking Cloud', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a rotten egg or several skunk cabbage leaves', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration.\n\nEach creature that is completely within the cloud at the start of its turn must make a Constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling. Creatures that don\'t need to breathe or are immune to poison automatically succeed on this saving throw.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['control', 'aoe'] },
  { id: 'tongues', name: 'Tongues', level: 3, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'M'], materialComponent: 'a small clay model of a ziggurat', duration: '1 hour', concentration: false, ritual: false, description: 'This spell grants the creature you touch the ability to understand any spoken language it hears. Moreover, when the target speaks, any creature that knows at least one language and can hear the target understands what it says.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'vampiric-touch', name: 'Vampiric Touch', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.\n\nAt Higher Levels: When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', atHigherLevels: 'Damage increases by 1d6 for each slot level above 3rd.', classes: ['warlock', 'wizard'], damageType: 'necrotic', tags: ['damage', 'healing', 'melee'] },
  { id: 'leomund-tiny-hut', name: "Leomund's Tiny Hut", level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a small crystal bead', duration: '8 hours', concentration: false, ritual: true, description: 'A 10-foot-radius immobile dome of force springs into existence around and above you and remains stationary for the duration. The spell ends if you leave its area.\n\nNine creatures of Medium size or smaller can fit inside the dome with you. The spell fails if its area includes a larger creature or more than nine creatures. Creatures and objects within the dome when you cast this spell can move through it freely. All other creatures and objects are barred from passing through it. Spells and other magical effects can\'t extend through the dome or be cast through it. The atmosphere inside the space is comfortable and dry, regardless of the weather outside.\n\nUntil the spell ends, you can command the interior to become dimly lit or dark. The dome is opaque from the outside, of any color you choose, but it is transparent from the inside.', classes: ['bard', 'wizard'], tags: ['utility', 'ritual', 'protection'] },
  { id: 'daylight', name: 'Daylight', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet.\n\nIf you chose a point on an object you are holding or one that isn\'t being worn or carried, the light shines from the object with and moves with it. Completely covering the affected object with an opaque object, such as a bowl or a helm, blocks the light.\n\nIf any of this spell\'s area overlaps with an area of magical darkness created by a spell of 3rd level or lower, the spell that created the darkness is dispelled.', classes: ['cleric', 'druid', 'paladin', 'ranger', 'sorcerer'], tags: ['utility', 'light'] },

  // ── ADDITIONAL LEVEL 4 SPELLS ────────────────────────────────────────────
  { id: 'arcane-eye', name: 'Arcane Eye', level: 4, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of bat fur', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You create an invisible, magical eye within range that hovers in the air for the duration.\n\nYou mentally receive visual information from the eye, which has normal vision and darkvision out to 30 feet. The eye can look in every direction.\n\nAs an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can\'t enter another plane of existence. A solid barrier blocks the eye\'s movement, but the eye can pass through an opening as small as 1 inch in diameter.', classes: ['artificer', 'wizard'], tags: ['utility', 'scouting'] },
  { id: 'compulsion', name: 'Compulsion', level: 4, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Creatures of your choice that you can see within range and that can hear you must make a Wisdom saving throw. A target automatically succeeds on this saving throw if it can\'t be charmed. On a failed save, a target is affected by this spell. Until the spell ends, you can use a bonus action on each of your turns to designate a direction that is horizontal to you. Each affected target must use as much of its movement as possible to move in that direction on its next turn. It can take its action before it moves. After moving in this way, it can make another Wisdom saving throw to try to end the effect.', classes: ['bard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'death-ward', name: 'Death Ward', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '8 hours', concentration: false, ritual: false, description: 'You touch a creature and grant it a measure of protection from death.\n\nThe first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.\n\nIf the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spells ends.', classes: ['cleric', 'paladin'], tags: ['defense', 'buff'] },
  { id: 'evards-black-tentacles', name: "Evard's Black Tentacles", level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: "a piece of tentacle from a giant octopus or a giant squid", duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain.\n\nWhen a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends. A creature that starts its turn in the area and is already restrained by the tentacles takes 3d6 bludgeoning damage.\n\nA creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.', classes: ['wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['control', 'aoe'] },
  { id: 'freedom-of-movement', name: 'Freedom of Movement', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a leather strap, bound around the arm or a similar appendage', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a willing creature. For the duration, the target\'s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target\'s speed nor cause the target to be paralyzed or restrained.\n\nThe target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled. Finally, being underwater imposes no penalties on the target\'s movement or attacks.', classes: ['artificer', 'bard', 'cleric', 'druid', 'ranger'], tags: ['buff', 'movement'] },
  { id: 'ice-storm', name: 'Ice Storm', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dust and a few drops of water', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a Dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one.\n\nHailstones turn the storm\'s area of effect into difficult terrain until the end of your next turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.', atHigherLevels: 'Bludgeoning damage increases by 1d8 for each slot level above 4th.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'stoneskin', name: 'Stoneskin', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamond dust worth 100 gp, which the spell consumes', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'This spell turns the flesh of a willing creature you touch as hard as stone. Until the spell ends, the target has resistance to nonmagical bludgeoning, piercing, and slashing damage.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['defense', 'resistance'] },
  { id: 'wall-of-fire', name: 'Wall of Fire', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a small piece of phosphorus', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a wall of fire on a solid surface within range. The wall can be up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.\n\nWhen the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.\n\nOne side of the wall, selected by you when you cast this spell, deals 5d8 fire damage to each creature that ends its turn within 10 feet of that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn.\n\nAt Higher Levels: When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 4th.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },

  // ── ADDITIONAL LEVEL 5 SPELLS ────────────────────────────────────────────
  { id: 'animate-objects', name: 'Animate Objects', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Objects come to life at your command. Choose up to ten nonmagical objects within range that are not being worn or carried. Medium targets count as two objects, Large targets count as four objects, Huge targets count as eight objects. You can\'t animate any object larger than Huge. Each target animates and becomes a creature under your control until the spell ends or until reduced to 0 hit points.\n\nAs a bonus action, you can mentally command any creature you made with this spell if the creature is within 500 feet of you.\n\nAt Higher Levels: If you cast this spell using a spell slot of 6th level or higher, you can animate two additional objects for each slot level above 5th.', atHigherLevels: 'Animate two additional objects for each slot level above 5th.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['summoning', 'control'] },
  { id: 'dominate-person', name: 'Dominate Person', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to beguile a humanoid that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. While the target is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey.\n\nAt Higher Levels: When you cast this spell using a 6th-level spell slot, the duration is 10 minutes. When you use a 7th-level spell slot, the duration is 1 hour. When you use a spell slot of 8th level or higher, the duration is 8 hours.', atHigherLevels: '6th level: 10 min. 7th level: 1 hour. 8th+: 8 hours.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'greater-restoration', name: 'Greater Restoration', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'diamond dust worth at least 100 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You imbue a creature you touch with positive energy to undo a debilitating effect. You can reduce the target\'s exhaustion level by one, or end one of the following effects on the target:\n\n• One effect that charmed or petrified the target\n• One curse, including the target\'s attunement to a cursed magic item\n• Any reduction to one of the target\'s ability scores\n• One effect reducing the target\'s hit point maximum', classes: ['artificer', 'bard', 'cleric', 'druid'], tags: ['healing', 'utility'] },
  { id: 'raise-dead', name: 'Raise Dead', level: 5, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 500 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature\'s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point.\n\nThis spell also neutralizes any poisons and cures nonmagical diseases that affected the creature at the time it died. This spell doesn\'t, however, remove magical diseases, curses, or similar effects; if these aren\'t first removed prior to casting the spell, they take effect when the creature returns to life.\n\nThe spell can\'t return an undead creature to life.\n\nComing back from the dead is an ordeal. The target takes a −4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.', classes: ['bard', 'cleric', 'paladin'], tags: ['healing', 'necromancy'] },
  { id: 'scrying', name: 'Scrying', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a focus worth at least 1,000 gp, such as a crystal ball, a silver mirror, or a font filled with holy water', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a Wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it.\n\nOn a successful save, the target isn\'t affected, and you can\'t use this spell against it again for 24 hours.\n\nOn a failed save, the spell creates an invisible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration.', classes: ['bard', 'cleric', 'druid', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['utility', 'detection', 'divination'] },
  { id: 'steel-wind-strike', name: 'Steel Wind Strike', level: 5, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a melee weapon worth at least 1 sp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You flourish the weapon used in the casting and then vanish to strike like the wind. Choose up to five creatures you can see within range. Make a melee spell attack against each target. On a hit, a target takes 6d10 force damage.\n\nYou can then teleport to an unoccupied space you can see within 5 feet of one of the targets you hit or missed.', classes: ['ranger', 'wizard'], damageType: 'force', tags: ['damage', 'teleportation'] },
  { id: 'telekinesis', name: 'Telekinesis', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below.\n\nCreature: You can try to move a Huge or smaller creature. Make an ability check with your spellcasting ability contested by the creature\'s Strength check. If you win the contest, you move the creature up to 30 feet in any direction, including upward but not beyond the range of this spell. Until the end of your next turn, the creature is restrained in your telekinetic grip.\n\nObject: You can try to move an object that weighs up to 1,000 pounds.', classes: ['sorcerer', 'wizard'], tags: ['control', 'utility'] },

  // ── ADDITIONAL CANTRIPS ────────────────────────────────────────────────
  { id: 'booming-blade', name: 'Booming Blade', level: 0, school: 'Evocation', sourceBook: 'TCE', alsoIn: ['SCAG'], castingTime: '1 action', range: 'Self (5-foot radius)', components: ['S', 'M'], materialComponent: 'a melee weapon worth at least 1 sp', duration: '1 round', concentration: false, ritual: false, description: 'You brandish the weapon used in the spell\'s casting and make a melee attack with it against one creature within 5 feet of you. On a hit, the target takes the weapon attack\'s normal damage, and it becomes sheathed in booming energy until the start of your next turn. If the target willingly moves 5 feet or more before then, the target takes 1d8 thunder damage, and the spell ends.\n\nThis spell\'s damage increases when you reach certain levels. At 5th level, the melee attack deals an extra 1d8 thunder damage to the target on a hit, and the damage the target takes for moving increases to 2d8. Both damage rolls increase by 1d8 at 11th level (2d8 and 3d8) and again at 17th level (3d8 and 4d8).', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], damageType: 'thunder', tags: ['damage', 'melee'] },
  { id: 'green-flame-blade', name: 'Green-Flame Blade', level: 0, school: 'Evocation', sourceBook: 'TCE', alsoIn: ['SCAG'], castingTime: '1 action', range: 'Self (5-foot radius)', components: ['S', 'M'], materialComponent: 'a melee weapon worth at least 1 sp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You brandish the weapon used in the spell\'s casting and make a melee attack with it against one creature within 5 feet of you. On a hit, the target suffers the weapon attack\'s normal effects, and you can cause green fire to leap from the target to a different creature of your choice that you can see within 5 feet of it. The second creature takes fire damage equal to your spellcasting ability modifier.\n\nAt 5th level, the melee attack deals an extra 1d8 fire damage to the target on a hit, and the fire damage to the second creature increases to 1d8 + your spellcasting ability modifier. Both damage rolls increase by 1d8 at 11th level (2d8 and 2d8) and 17th level (3d8 and 3d8).', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], damageType: 'fire', tags: ['damage', 'melee'] },
  { id: 'sword-burst', name: 'Sword Burst', level: 0, school: 'Conjuration', sourceBook: 'TCE', alsoIn: ['SCAG'], castingTime: '1 action', range: 'Self (5-foot radius)', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a momentary circle of spectral blades that sweep around you. Each creature within range, other than you, must succeed on a Dexterity saving throw or take 1d6 force damage.\n\nDamage increases by 1d6 at 5th, 11th, and 17th level.', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], damageType: 'force', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'create-bonfire', name: 'Create Bonfire', level: 0, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a bonfire on ground that you can see within range. Until the spell ends, the bonfire fills a 5-foot cube. Any creature in the bonfire\'s space when you cast the spell must succeed on a Dexterity saving throw or take 1d8 fire damage. A creature must also make the save when it enters the bonfire\'s space for the first time on a turn or ends its turn there.\n\nThe spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'control'] },
  { id: 'control-flames', name: 'Control Flames', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['S'], duration: 'Instantaneous or 1 hour', concentration: false, ritual: false, description: 'You choose nonmagical flame that you can see within range and that fits within a 5-foot cube. You affect it in one of the following ways: expand to twice its size, extinguish it, double or halve its light, or cause simple shapes to appear within it.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'gust', name: 'Gust', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You seize the air and compel it to create one of the following effects at a point you can see within range: a Medium or smaller creature must succeed on a Strength save or be pushed 5 feet; you create a small gust that moves a light object; or you create a harmless sensory effect.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['utility', 'control'] },
  { id: 'magic-stone', name: 'Magic Stone', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Touch', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You touch one to three pebbles and imbue them with magic. You or someone else can make a ranged spell attack with one of the pebbles by throwing it or hurling it with a sling. If thrown, it has a range of 60 feet. On a hit, the target takes 1d6 + your spellcasting ability modifier bludgeoning damage.', classes: ['druid', 'warlock'], damageType: 'bludgeoning', tags: ['damage'] },
  { id: 'mold-earth', name: 'Mold Earth', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['S'], duration: 'Instantaneous or 1 hour', concentration: false, ritual: false, description: 'You choose a portion of dirt or stone that you can see within range and that fits within a 5-foot cube. You manipulate it: move loose earth, change its color/texture, or cause shapes to appear.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'shape-water', name: 'Shape Water', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['S'], duration: 'Instantaneous or 1 hour', concentration: false, ritual: false, description: 'You choose an area of water that you can see within range and that fits within a 5-foot cube. You manipulate it: move the water, change its flow, freeze it, change its color, or form simple shapes.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'primal-savagery', name: 'Primal Savagery', level: 0, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You channel primal magic to cause your teeth or fingernails to sharpen, ready to deliver a corrosive attack. Make a melee spell attack against one creature within 5 feet of you. On a hit, the target takes 1d10 acid damage. After you make the attack, your teeth or fingernails return to normal.\n\nThe spell\'s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', classes: ['druid'], damageType: 'acid', tags: ['damage', 'melee'] },
  // GGR Cantrips
  { id: 'encode-thoughts', name: 'Encode Thoughts', level: 0, school: 'Enchantment', sourceBook: 'GGR', castingTime: '1 action', range: 'Self', components: ['S'], duration: 'Up to 8 hours', concentration: false, ritual: false, description: 'Putting a finger to your head, you pull a memory, an idea, or a message from your mind and transform it into a tangible string of glowing energy called a thought strand, which persists for the duration or until you cast this spell again. The thought strand appears in an unoccupied space within 5 feet of you as a Tiny, weightless, semisolid object that can be held and carried like a ribbon. It is otherwise stationary.\n\nIf you cast this spell while concentrating on a spell or an ability that allows you to read or manipulate the thoughts of others (such as detect thoughts or modify memory), you can transform the thoughts or memories you read, rather than your own, into a thought strand.\n\nCasting this spell while holding a thought strand allows you to instantly receive whatever memory, idea, or message the thought strand contains. (Casting detect thoughts on the strand has the same effect.)', classes: ['wizard'], tags: ['utility', 'social'] },
  // ── ADDITIONAL LEVEL 1 SPELLS ──────────────────────────────────────────
  { id: 'grease', name: 'Grease', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of pork rind or butter', duration: '1 minute', concentration: false, ritual: false, description: 'Slick grease covers the ground in a 10-foot square centered on a point within range and turns it into difficult terrain for the duration.\n\nWhen the grease appears, each creature standing in its area must succeed on a Dexterity saving throw or fall prone. A creature that enters the area or ends its turn there must also succeed on a Dexterity saving throw or fall prone.', classes: ['artificer', 'wizard'], savingThrow: 'dex', tags: ['control', 'aoe'] },
  { id: 'absorb-elements', name: 'Absorb Elements', level: 1, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '1 reaction, which you take when you take acid, cold, fire, lightning, or thunder damage', range: 'Self', components: ['S'], duration: '1 round', concentration: false, ritual: false, description: 'The spell captures some of the incoming energy, lessening its effect on you and storing it for your next melee attack. You have resistance to the triggering damage type until the start of your next turn. Also, the first time you hit with a melee attack on your next turn, the target takes an extra 1d6 damage of the triggering type.\n\nDamage increases by 1d6 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d6 for each slot level above 1st.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['defense', 'damage'] },
  { id: 'alarm', name: 'Alarm', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny bell and a piece of fine silver wire', duration: '8 hours', concentration: false, ritual: true, description: 'You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area.', classes: ['artificer', 'ranger', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'arms-of-hadar', name: 'Arms of Hadar', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (10-foot radius)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You invoke the power of Hadar, the Dark Hunger. Tendrils of dark energy erupt from you. Each creature within 10 feet must make a Strength saving throw. On a failed save, a target takes 2d6 necrotic damage and can\'t take reactions until its next turn. On a successful save, half damage and no other effect.\n\nDamage increases by 1d6 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d6 for each slot level above 1st.', classes: ['warlock'], damageType: 'necrotic', savingThrow: 'str', tags: ['damage', 'aoe'] },
  { id: 'bane', name: 'Bane', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of blood', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Up to three creatures of your choice that you can see within range must each make a Charisma saving throw. Whenever a target that fails this save makes an attack roll or a saving throw before the spell ends, the target must roll a d4 and subtract the number rolled from the attack roll or save.\n\nWhen you cast this spell using a spell slot of 2nd level or higher, target one additional creature for each slot level above 1st.', atHigherLevels: 'Target one additional creature for each slot level above 1st.', classes: ['bard', 'cleric'], savingThrow: 'cha', tags: ['debuff'] },
  { id: 'catapult', name: 'Catapult', level: 1, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose one object weighing 1 to 5 pounds within range that isn\'t being worn or carried. The object flies in a straight line up to 90 feet in a direction you choose. The first creature in the line must succeed on a Dexterity saving throw or take 3d8 bludgeoning damage.\n\nDamage increases by 1d8 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 1st.', classes: ['artificer', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage'] },
  { id: 'cause-fear', name: 'Cause Fear', level: 1, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You awaken the sense of mortality in one creature you can see within range. A construct or an undead is immune. The target must succeed on a Wisdom saving throw or become frightened of you until the spell ends. The frightened target can repeat the saving throw at the end of each of its turns.\n\nTarget one additional creature for each slot level above 1st.', atHigherLevels: 'Target one additional creature for each slot level above 1st.', classes: ['warlock', 'wizard'], savingThrow: 'wis', tags: ['debuff', 'control'] },
  { id: 'chaos-bolt', name: 'Chaos Bolt', level: 1, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl an undulating, warbling mass of chaotic energy at one creature in range. Make a ranged spell attack. On a hit, the target takes 2d8 + 1d6 damage. Roll the 2d8: the type is determined by the roll (acid, cold, fire, force, lightning, poison, psychic, or thunder). If the two d8s roll the same number, the energy leaps to another creature.\n\nEach d8 rolled adds 1d6 damage at higher levels.', atHigherLevels: 'Each slot above 1st adds 1d6 damage.', classes: ['sorcerer'], damageType: 'force', tags: ['damage'] },
  { id: 'chromatic-orb', name: 'Chromatic Orb', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 50 gp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hurl a 4-inch-diameter sphere of energy at a creature you can see within range. You choose acid, cold, fire, lightning, poison, or thunder for the type of orb you create, then make a ranged spell attack. On a hit, the target takes 3d8 damage of the type you chose.\n\nDamage increases by 1d8 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d8 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'fire', tags: ['damage'] },
  { id: 'color-spray', name: 'Color Spray', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (15-foot cone)', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powder or sand colored red, yellow, and blue', duration: '1 round', concentration: false, ritual: false, description: 'A dazzling array of flashing colored light springs from your hand. Roll 6d10; the total is how many hit points of creatures this spell can affect. Creatures in a 15-foot cone are affected in ascending order of their current hit points (ignoring unconscious creatures and creatures that can\'t see). Each creature affected is blinded until the end of your next turn. Subtract its hit points from the total before moving on.\n\nRoll an additional 2d10 for each slot above 1st.', atHigherLevels: 'Roll an additional 2d10 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], tags: ['debuff', 'aoe'] },
  { id: 'divine-favor', name: 'Divine Favor', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.', classes: ['paladin'], damageType: 'radiant', tags: ['buff'] },
  { id: 'earth-tremor', name: 'Earth Tremor', level: 1, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self (10-foot radius)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause a tremor in the ground in a 10-foot radius. Each creature other than you in that area must make a Dexterity saving throw. On a failed save, a creature takes 1d6 bludgeoning damage and is knocked prone. If the ground is loose earth or stone, it becomes difficult terrain.\n\nDamage increases by 1d6 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d6 for each slot level above 1st.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'ensnaring-strike', name: 'Ensnaring Strike', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a weapon attack before this spell ends, a writhing mass of thorny vines appears at the point of impact, and the target must succeed on a Strength saving throw or be restrained by the magical vines until the spell ends. A Large or larger creature has advantage on this saving throw. If the target succeeds on the save, the vines shrivel away.\n\nWhile restrained by this spell, the target takes 1d6 piercing damage at the start of each of its turns. A creature restrained by the vines or one that can touch the creature can use its action to make a Strength check against your spell save DC. On a success, the target is freed.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['ranger'], damageType: 'piercing', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'find-steed', name: 'Find Steed', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You summon a spirit that assumes the form of an unusually intelligent, strong, and loyal steed, creating a long-lasting bond with it. Appearing in an unoccupied space within range, the steed takes on a form that you choose: a warhorse, a pony, a camel, an elk, or a mastiff.', classes: ['paladin'], tags: ['summoning'] },
  { id: 'hail-of-thorns', name: 'Hail of Thorns', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a ranged weapon attack before the spell ends, this spell creates a rain of thorns that sprouts from your ranged weapon or ammunition. Each creature within 5 feet of the target must make a Dexterity saving throw. A creature takes 1d10 piercing damage on a failed save, or half as much damage on a successful one.\n\nDamage increases by 1d10 for each slot level above 1st (max 6d10).', atHigherLevels: 'Damage increases by 1d10 per slot above 1st (max 6d10).', classes: ['ranger'], damageType: 'piercing', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'heroism', name: 'Heroism', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns.\n\nTarget one additional creature for each slot level above 1st.', atHigherLevels: 'Target one additional creature for each slot level above 1st.', classes: ['bard', 'paladin'], tags: ['buff'] },
  { id: 'ice-knife', name: 'Ice Knife', level: 1, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['S', 'M'], materialComponent: 'a drop of water or piece of ice', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a shard of ice and fling it at one creature within range. Make a ranged spell attack. On a hit, the target takes 1d10 piercing damage. Hit or miss, the shard then explodes. The target and each creature within 5 feet must succeed on a Dexterity saving throw or take 2d6 cold damage.\n\nDamage increases at higher slots.', atHigherLevels: 'The cold damage increases by 1d6 for each slot level above 1st. The piercing damage does not increase.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'illusory-script', name: 'Illusory Script', level: 1, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['S', 'M'], materialComponent: 'a lead-based ink worth at least 10 gp', duration: '10 days', concentration: false, ritual: true, description: 'You write on parchment, paper, or some other suitable writing material and imbue it with a potent illusion. To you and others you designate, the writing appears normal, but to others, the writing appears as if it were written in an unknown or magical script.', classes: ['bard', 'warlock', 'wizard'], tags: ['utility', 'ritual', 'illusion'] },
  { id: 'jump', name: 'Jump', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a grasshopper\'s hind leg', duration: '1 minute', concentration: false, ritual: false, description: 'You touch a creature. The creature\'s jump distance is tripled until the spell ends.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'purify-food-and-drink', name: 'Purify Food and Drink', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: true, description: 'All nonmagical food and drink within a 5-foot-radius sphere centered on a point of your choice within range is purified and rendered free of poison and disease.', classes: ['cleric', 'druid', 'paladin'], tags: ['utility', 'ritual'] },
  { id: 'ray-of-sickness', name: 'Ray of Sickness', level: 1, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A ray of sickening greenish energy lashes out toward a creature within range. Make a ranged spell attack. On a hit, the target takes 2d8 poison damage and must make a Constitution saving throw or be poisoned until the end of your next turn.\n\nDamage increases by 1d8 for each slot level above 1st.', atHigherLevels: 'Damage increases by 1d8 per slot above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage', 'debuff'] },
  { id: 'searing-smite', name: 'Searing Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a melee weapon attack during the spell\'s duration, your weapon flares with white-hot intensity, and the attack deals an extra 1d6 fire damage to the target and causes the target to ignite in flames. At the start of each of its turns until the spell ends, the target must make a Constitution saving throw. On a failed saving throw, it takes 1d6 fire damage. On a successful save, the spell ends. If the target or a creature within 5 feet of it uses an action to put out the flames, or if some other effect douses the flames (such as the target being submerged in water), the spell ends.\n\nThe spell also sheds bright light in a 10-foot radius and dim light for an additional 10 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the initial extra damage dealt by the attack increases by 1d6 for each slot level above 1st.', classes: ['paladin'], damageType: 'fire', savingThrow: 'con', tags: ['damage', 'smite'] },
  { id: 'shield-of-faith', name: 'Shield of Faith', level: 1, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a small parchment with a bit of holy text written on it', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.', classes: ['cleric', 'paladin'], tags: ['buff', 'defense'] },
  { id: 'snare', name: 'Snare', level: 1, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '1 minute', range: 'Touch', components: ['S', 'M'], materialComponent: '25 feet of rope', duration: '8 hours', concentration: false, ritual: false, description: 'You create a magic trap by tracing a circle with rope on solid ground. When a Small, Medium, or Large creature moves into the circle, the trap activates. The target must succeed on a Dexterity saving throw or be hoisted into the air and restrained.', classes: ['artificer', 'druid', 'ranger', 'wizard'], savingThrow: 'dex', tags: ['control', 'utility'] },
  { id: 'tensers-floating-disk', name: 'Tenser\'s Floating Disk', level: 1, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of mercury', duration: '1 hour', concentration: false, ritual: true, description: 'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk can hold up to 500 pounds and follows you.', classes: ['wizard'], tags: ['utility', 'ritual'] },
  { id: 'thunderous-smite', name: 'Thunderous Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The first time you hit with a melee weapon attack during this spell\'s duration, your weapon rings with thunder and the attack deals an extra 2d6 thunder damage. The target must succeed on a Strength saving throw or be pushed 10 feet and knocked prone.', classes: ['paladin'], damageType: 'thunder', savingThrow: 'str', tags: ['damage', 'smite'] },
  { id: 'wrathful-smite', name: 'Wrathful Smite', level: 1, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit with a melee weapon attack during this spell\'s duration, your attack deals an extra 1d6 psychic damage. Additionally, if the target is a creature, it must make a Wisdom saving throw or be frightened of you until the spell ends. As an action, the frightened creature can make a Wisdom check against your spell save DC to steel its resolve and end this spell.', classes: ['paladin'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'smite'] },
  { id: 'zephyr-strike', name: 'Zephyr Strike', level: 1, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You move like the wind. Until the spell ends, your movement doesn\'t provoke opportunity attacks. Once before the spell ends, you can give yourself advantage on one weapon attack roll. That attack deals an extra 1d8 force damage on a hit, and your speed is increased by 30 feet until the end of that turn.', classes: ['ranger'], damageType: 'force', tags: ['buff'] },

  // ── ADDITIONAL LEVEL 2 SPELLS ──────────────────────────────────────────
  { id: 'aganazzars-scorcher', name: 'Aganazzar\'s Scorcher', level: 2, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a red dragon\'s scale', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A line of roaring flame 30 feet long and 5 feet wide emanates from you in a direction you choose. Each creature in the line must make a Dexterity saving throw, taking 3d8 fire damage on a failed save, or half as much on a successful one.\n\nDamage increases by 1d8 for each slot level above 2nd.', atHigherLevels: 'Damage increases by 1d8 per slot above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'branding-smite', name: 'Branding Smite', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit with a weapon attack during this spell\'s duration, your weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target, which becomes visible if invisible, and the target sheds dim light in a 5-foot radius.\n\nDamage increases by 1d6 per slot above 2nd.', atHigherLevels: 'Damage increases by 1d6 per slot above 2nd.', classes: ['paladin'], damageType: 'radiant', tags: ['damage', 'smite'] },
  { id: 'calm-emotions', name: 'Calm Emotions', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a Charisma saving throw; a creature can choose to fail. If fails, you can suppress any effect causing a target to be charmed or frightened, or make the target indifferent about creatures of your choice.', classes: ['bard', 'cleric'], savingThrow: 'cha', tags: ['control', 'aoe'] },
  { id: 'cloud-of-daggers', name: 'Cloud of Daggers', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a sliver of glass', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You fill the air with spinning daggers in a cube 5 feet on each side, centered on a point you choose within range. A creature takes 4d4 slashing damage when it enters the spell\'s area for the first time on a turn or starts its turn there.\n\nDamage increases by 2d4 for each slot level above 2nd.', atHigherLevels: 'Damage increases by 2d4 per slot above 2nd.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'slashing', tags: ['damage', 'aoe', 'control'] },
  { id: 'continual-flame', name: 'Continual Flame', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'ruby dust worth 50 gp, which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: false, description: 'A flame, equivalent in brightness to a torch, springs forth from an object that you touch. The effect looks like a regular flame, but it creates no heat and doesn\'t use oxygen. A continual flame can be covered or hidden but not smothered or quenched.', classes: ['artificer', 'cleric', 'wizard'], tags: ['utility'] },
  { id: 'cordon-of-arrows', name: 'Cordon of Arrows', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '5 feet', components: ['V', 'S', 'M'], materialComponent: 'four or more arrows or bolts', duration: '8 hours', concentration: false, ritual: false, description: 'You plant four pieces of nonmagical ammunition in the ground within range and lay magic upon them. Until the spell ends, whenever a creature other than you comes within 30 feet of the ammunition for the first time on a turn or ends its turn there, one piece flies up to strike it. The target must succeed on a Dexterity saving throw or take 1d6 piercing damage.', classes: ['ranger'], damageType: 'piercing', savingThrow: 'dex', tags: ['damage', 'utility'] },
  { id: 'detect-thoughts', name: 'Detect Thoughts', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a copper piece', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'For the duration, you can read the thoughts of certain creatures. When you cast the spell and as your action on each turn until it ends, you can focus your mind on any one creature within 30 feet of you. You initially learn the surface thoughts of the creature.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['utility', 'divination'] },
  { id: 'dust-devil', name: 'Dust Devil', level: 2, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dust', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose an unoccupied 5-foot cube of air that you can see. An elemental force resembling a dust devil appears there for the duration. Any creature that ends its turn within 5 feet must make a Strength saving throw or take 1d8 bludgeoning damage and be pushed up to 10 feet.\n\nDamage increases by 1d8 per slot above 2nd.', atHigherLevels: 'Damage increases by 1d8 per slot above 2nd.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'earthbind', name: 'Earthbind', level: 2, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '300 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose one creature you can see within range. Yellow strips of magical energy loop around the creature. The target must succeed on a Strength saving throw, or its flying speed (if any) is reduced to 0 for the spell\'s duration.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'str', tags: ['control'] },
  { id: 'enthrall', name: 'Enthrall', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You weave a distracting string of words, causing creatures of your choice that you can see within range to make a Wisdom saving throw. On a failed save, a target has disadvantage on Wisdom (Perception) checks made to perceive any creature other than you until the spell ends.', classes: ['bard', 'warlock'], savingThrow: 'wis', tags: ['control'] },
  { id: 'flame-blade', name: 'Flame Blade', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'leaf of sumac', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke the blade again as a bonus action.\n\nYou can use your action to make a melee spell attack with the fiery blade. On a hit, the target takes 3d6 fire damage.\n\nThe flaming blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for every two slot levels above 2nd.', classes: ['druid'], damageType: 'fire', tags: ['damage', 'melee'] },
  { id: 'flaming-sphere', name: 'Flaming Sphere', level: 2, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of tallow, a pinch of brimstone, and a dusting of powdered iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a Dexterity saving throw. The creature takes 2d6 fire damage on a failed save, or half as much damage on a successful one.\n\nAs a bonus action, you can move the sphere up to 30 feet. If you ram the sphere into a creature, that creature must make the saving throw against the sphere\'s damage, and the sphere stops moving this turn.\n\nWhen you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. The sphere ignites flammable objects not being worn or carried, and it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.', atHigherLevels: 'Damage increases by 1d6 per slot above 2nd.', classes: ['druid', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'control'] },
  { id: 'gust-of-wind', name: 'Gust of Wind', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a legume seed', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the spell\'s duration. Each creature that starts its turn in the line must succeed on a Strength saving throw or be pushed 15 feet away from you in a direction following the line.\n\nAny creature in the line must spend 2 feet of movement for every 1 foot it moves when moving closer to you.\n\nThe gust disperses gas or vapor, and it extinguishes candles, torches, and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them.\n\nAs a bonus action on each of your turns before the spell ends, you can change the direction in which the line blasts from you.', classes: ['druid', 'sorcerer', 'wizard'], savingThrow: 'str', tags: ['control', 'aoe'] },
  { id: 'healing-spirit', name: 'Healing Spirit', level: 2, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You call forth a nature spirit to soothe the wounded. The intangible spirit appears in a space that is a 5-foot cube. Until the spell ends, whenever you or a creature you can see moves into the spirit\'s space for the first time on a turn or starts its turn there, you can cause the spirit to restore 1d6 hit points to that creature.\n\nHealing increases by 1d6 per slot above 2nd.', atHigherLevels: 'Healing increases by 1d6 per slot above 2nd.', classes: ['druid', 'ranger'], tags: ['healing'] },
  { id: 'knock', name: 'Knock', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access. A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'magic-weapon', name: 'Magic Weapon', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls.\n\nThe bonus increases to +2 at 4th level or higher, and to +3 at 6th level or higher.', atHigherLevels: '+2 bonus at 4th level, +3 at 6th level.', classes: ['artificer', 'paladin', 'wizard'], tags: ['buff'] },
  { id: 'maximilians-earthen-grasp', name: 'Maximilian\'s Earthen Grasp', level: 2, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a miniature hand sculpted from clay', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You choose a 5-foot-square unoccupied space on the ground that you can see within range. A Medium hand made from compacted soil rises there and reaches for one creature you can see within 5 feet of it. The target must make a Strength saving throw. On a failed save, the target takes 2d6 bludgeoning damage and is restrained until the spell ends.\n\nAs an action, you can cause the hand to crush the restrained target, which must make a Strength saving throw. The target takes 2d6 bludgeoning damage on a failed save, or half as much damage on a successful one.\n\nTo break out, the restrained target can use its action to make a Strength check against your spell save DC. On a success, the target escapes and is no longer restrained by the hand.\n\nAs a bonus action, you can move the hand up to 5 feet and then reach for the same creature or a different one.', classes: ['sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'melfs-acid-arrow', name: 'Melf\'s Acid Arrow', level: 2, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'powdered rhubarb leaf and an adder\'s stomach', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A shimmering green arrow streaks toward a target within range and bursts in a spray of acid. Make a ranged spell attack. On a hit, the target takes 4d4 acid damage immediately and 2d4 acid damage at the end of its next turn. On a miss, the arrow splashes the target with acid for half initial damage and no damage at the end of its next turn.\n\nDamage increases by 1d4 for both effects per slot above 2nd.', atHigherLevels: 'Damage increases by 1d4 for both per slot above 2nd.', classes: ['wizard'], damageType: 'acid', tags: ['damage'] },
  { id: 'mind-spike', name: 'Mind Spike', level: 2, school: 'Divination', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You drive a spike of psychic energy into the mind of one creature you can see. The target must make a Wisdom saving throw. On a failed save, it takes 3d8 psychic damage, and you always know the target\'s location for the duration. Half damage and no other effects on success.\n\nDamage increases by 1d8 per slot above 2nd.', atHigherLevels: 'Damage increases by 1d8 per slot above 2nd.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'divination'] },
  { id: 'phantasmal-force', name: 'Phantasmal Force', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fleece', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You craft an illusion that takes root in the mind of a creature that you can see within range. The target must make an Intelligence saving throw. On a failed save, you create a phantasmal object, creature, or other visible phenomenon of your choice that is no larger than a 10-foot cube and that is perceivable only to the target for the duration. This spell has no effect on undead or constructs.\n\nThe phantasm includes sound, temperature, and other stimuli, also evident only to the creature. The target can use its action to examine the phantasm with an Intelligence (Investigation) check against your spell save DC. If the check succeeds, the target realizes that the phantasm is an illusion, and the spell ends.\n\nWhile a target is affected by the spell, the target treats the phantasm as if it were real. The target rationalizes any illogical outcomes from interacting with the phantasm. For example, a target attempting to walk across a phantasmal bridge that spans a chasm falls once it steps onto the bridge. If the target survives the fall, it still believes that the bridge exists and comes up with some other explanation for why it fell — it was pushed, it slipped, or a strong wind might have knocked it off.\n\nAn affected target is so convinced of the phantasm\'s reality that it can even take damage from the illusion. A phantasm created to appear as a creature can attack the target. Similarly, a phantasm created to appear as fire, a pool of acid, or lava can burn the target. Each round on your turn, the phantasm can deal 1d6 psychic damage to the target if it is in the phantasm\'s area or within 5 feet of the phantasm, provided that the illusion is of a creature or hazard that could logically deal damage, such as by attacking. The target perceives the damage as a type appropriate to the illusion.', classes: ['bard', 'sorcerer', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'illusion'] },
  { id: 'protection-from-poison', name: 'Protection from Poison', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You touch a creature. If it is poisoned, you neutralize the poison. If more than one poison afflicts the target, you neutralize one poison that you know is present, or you neutralize one at random. For the duration, the target has advantage on saving throws against being poisoned, and it has resistance to poison damage.', classes: ['artificer', 'cleric', 'druid', 'paladin', 'ranger'], tags: ['buff', 'defense'] },
  { id: 'pyrotechnics', name: 'Pyrotechnics', level: 2, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose an area of flame that you can see. You can extinguish the fire in that area, and you create either fireworks or smoke. Fireworks: a burst of multicolored light blossoms; creatures within 10 feet of the flame must make a Constitution save or be blinded until the end of your next turn. Smoke: thick black smoke spreads in a 20-foot radius.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['utility', 'control'] },
  { id: 'ray-of-enfeeblement', name: 'Ray of Enfeeblement', level: 2, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A black beam of enervating energy springs from your finger toward a creature within range. Make a ranged spell attack against the target. On a hit, the target deals only half damage with weapon attacks that use Strength until the spell ends.\n\nAt the end of each of the target\'s turns, it can make a Constitution saving throw against the spell. On a success, the spell ends.', classes: ['warlock', 'wizard'], savingThrow: 'con', tags: ['debuff'] },
  { id: 'rope-trick', name: 'Rope Trick', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'powdered corn extract and a twisted loop of parchment', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a length of rope that is up to 60 feet long. One end of the rope then rises into the air until the whole rope hangs perpendicular to the ground. At the upper end of the rope, an invisible entrance opens to an extradimensional space that lasts until the spell ends.', classes: ['artificer', 'wizard'], tags: ['utility'] },
  { id: 'shadow-blade', name: 'Shadow Blade', level: 2, school: 'Illusion', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You weave together threads of shadow to create a sword of solidified gloom in your hand. This magic sword lasts until the spell ends. It counts as a simple melee weapon with which you are proficient. It deals 2d8 psychic damage on a hit and has the finesse, light, and thrown properties (range 20/60). In addition, when you use the sword to attack a target that is in dim light or darkness, you make the attack roll with advantage.\n\nIf you drop the weapon or throw it, it dissipates at the end of the turn. Thereafter, while the spell persists, you can use a bonus action to cause the sword to reappear in your hand.', atHigherLevels: 'When you cast this spell using a 3rd- or 4th-level spell slot, the damage increases to 3d8. When you cast it using a 5th- or 6th-level spell slot, the damage increases to 4d8. When you cast it using a spell slot of 7th level or higher, the damage increases to 5d8.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'psychic', tags: ['damage', 'buff'] },
  { id: 'skywrite', name: 'Skywrite', level: 2, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Sight', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: true, description: 'You cause up to ten words to form in a part of the sky you can see. The words appear to be made of cloud and remain in place for the spell\'s duration. The words dissipate when the spell ends.', classes: ['bard', 'druid', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'snillocs-snowball-swarm', name: 'Snilloc\'s Snowball Swarm', level: 2, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of ice or a small white rock chip', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A flurry of magic snowballs erupts from a point you choose. Each creature in a 5-foot-radius sphere centered on that point must make a Dexterity saving throw, taking 3d6 cold damage on a failed save, or half as much on a successful one.\n\nDamage increases by 1d6 per slot above 2nd.', atHigherLevels: 'Damage increases by 1d6 per slot above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'spike-growth', name: 'Spike Growth', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'seven sharp thorns or seven small twigs', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'The ground in a 20-foot radius centered on a point within range twists and sprouts hard spikes and thorns. The area becomes difficult terrain for the duration. When a creature moves into or within the area, it takes 2d4 piercing damage for every 5 feet it travels.', classes: ['druid', 'ranger'], damageType: 'piercing', tags: ['damage', 'control', 'aoe'] },
  { id: 'warding-bond', name: 'Warding Bond', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pair of platinum rings worth at least 50 gp each', duration: '1 hour', concentration: false, ritual: false, description: 'This spell wards a willing creature you touch and creates a mystic connection between you and the target. While the target is within 60 feet, it gains a +1 bonus to AC and saving throws, and resistance to all damage. Each time it takes damage, you take the same amount.', classes: ['cleric'], tags: ['buff', 'defense'] },
  { id: 'zone-of-truth', name: 'Zone of Truth', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: false, description: 'You create a magical zone in a 15-foot-radius sphere centered on a point of your choice within range. A creature that enters the spell\'s area for the first time on a turn or starts its turn there must make a Charisma saving throw. On a failed save, a creature can\'t speak a deliberate lie while in the radius.', classes: ['bard', 'cleric', 'paladin'], savingThrow: 'cha', tags: ['utility', 'control'] },

  // ── ADDITIONAL LEVEL 3 SPELLS ──────────────────────────────────────────
  { id: 'aura-of-vitality', name: 'Aura of Vitality', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Healing energy radiates from you in an aura with a 30-foot radius. Until the spell ends, the aura moves with you. You can use a bonus action to cause one creature in the aura (including you) to regain 2d6 hit points.', classes: ['paladin'], tags: ['healing'] },
  { id: 'beacon-of-hope', name: 'Beacon of Hope', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'This spell bestows hope and vitality. Choose any number of creatures within range. For the duration, each target has advantage on Wisdom saving throws and death saving throws, and regains the maximum number of hit points possible from any healing.', classes: ['cleric'], tags: ['buff', 'healing'] },
  { id: 'blink', name: 'Blink', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'Roll a d20 at the end of each of your turns for the duration. On a roll of 11 or higher, you vanish from your current plane of existence and appear in the Ethereal Plane. At the start of your next turn, you return to an unoccupied space within 10 feet of where you vanished.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['utility', 'defense'] },
  { id: 'clairvoyance', name: 'Clairvoyance', level: 3, school: 'Divination', sourceBook: 'PHB', castingTime: '10 minutes', range: '1 mile', components: ['V', 'S', 'M'], materialComponent: 'a focus worth at least 100 gp', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create an invisible sensor within range in a location familiar to you or in an obvious location. The sensor remains in place for the duration. You can see or hear through the sensor.', classes: ['bard', 'cleric', 'sorcerer', 'wizard'], tags: ['utility', 'divination'] },
  { id: 'conjure-animals', name: 'Conjure Animals', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You summon fey spirits that take the form of beasts and appear in unoccupied spaces that you can see within range. Choose one: one beast of CR 2 or lower, two beasts of CR 1 or lower, four beasts of CR 1/2 or lower, or eight beasts of CR 1/4 or lower.\n\nMore beasts appear at higher slots.', atHigherLevels: 'More beasts appear at higher slots.', classes: ['druid', 'ranger'], tags: ['summoning'] },
  { id: 'create-food-and-water', name: 'Create Food and Water', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create 45 pounds of food and 30 gallons of water on the ground or in containers within range, enough to sustain up to fifteen humanoids or five steeds for 24 hours.', classes: ['cleric', 'paladin'], tags: ['utility'] },
  { id: 'crusaders-mantle', name: 'Crusader\'s Mantle', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Holy power radiates from you in an aura with a 30-foot radius, awakening boldness in friendly creatures. Until the spell ends, the aura moves with you. While in the aura, each nonhostile creature (including you) deals an extra 1d4 radiant damage when it hits with a weapon attack.', classes: ['paladin'], damageType: 'radiant', tags: ['buff'] },
  { id: 'elemental-weapon', name: 'Elemental Weapon', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A nonmagical weapon you touch becomes a magic weapon. Choose acid, cold, fire, lightning, or thunder. The weapon has a +1 bonus to attack rolls and deals an extra 1d4 damage of the chosen type.\n\nWhen you cast this spell using a spell slot of 5th or 6th level, the bonus to attack and damage rolls increases to +2, and the extra damage increases to 2d4. When you use a spell slot of 7th level or higher, the bonus increases to +3 and the extra damage increases to 3d4.', atHigherLevels: 'At 5th–6th level: +2 bonus and 2d4 extra damage. At 7th level and above: +3 bonus and 3d4 extra damage.', classes: ['artificer', 'paladin'], damageType: 'fire', tags: ['buff'] },
  { id: 'enemies-abound', name: 'Enemies Abound', level: 3, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You reach into the mind of one creature you can see and force it to make an Intelligence saving throw. On a failed save, the target loses the ability to distinguish friend from foe, regarding all creatures it can see as enemies until the spell ends.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'int', tags: ['control'] },
  { id: 'erupting-earth', name: 'Erupting Earth', level: 3, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of obsidian', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose a point you can see on the ground within range. A fountain of churned earth and stone erupts in a 20-foot cube centered on that point. Each creature in that area must make a Dexterity saving throw, taking 3d12 bludgeoning damage on a failed save, or half as much on a successful one. The area becomes difficult terrain.\n\nDamage increases by 1d12 per slot above 3rd.', atHigherLevels: 'Damage increases by 1d12 per slot above 3rd.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'feign-death', name: 'Feign Death', level: 3, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pinch of graveyard dirt', duration: '1 hour', concentration: false, ritual: true, description: 'You touch a willing creature and put it into a cataleptic state that is indistinguishable from death. The target is blinded and incapacitated, with speed dropped to 0. The target has resistance to all damage except psychic, and is immune to disease and poison damage.', classes: ['bard', 'cleric', 'druid', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'flame-arrows', name: 'Flame Arrows', level: 3, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You touch a quiver containing arrows or bolts. When a target is hit by a ranged weapon attack using a piece of ammunition drawn from the quiver, the target takes an extra 1d6 fire damage. The spell\'s magic ends on the piece of ammunition when it hits or misses. The spell ends after 12 pieces of ammunition have been drawn.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], damageType: 'fire', tags: ['buff'] },
  { id: 'gaseous-form', name: 'Gaseous Form', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a bit of gauze and a wisp of smoke', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You transform a willing creature you touch, along with everything it\'s wearing and carrying, into a misty cloud for the duration. The spell ends if the creature drops to 0 hit points. The target has a flying speed of 10 feet, can pass through small holes, has resistance to nonmagical damage, and has advantage on Strength, Dexterity, and Constitution saves.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'glyph-of-warding', name: 'Glyph of Warding', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'incense and powdered diamond worth at least 200 gp, consumed by the spell', duration: 'Until dispelled or triggered', concentration: false, ritual: false, description: 'When you cast this spell, you inscribe a glyph that harms other creatures, either on a surface or within an object. The glyph can either explode for damage or store a spell of 3rd level or lower.', classes: ['artificer', 'bard', 'cleric', 'wizard'], tags: ['utility', 'control'] },
  { id: 'hunger-of-hadar', name: 'Hunger of Hadar', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a pickled octopus tentacle', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You open a gateway to the dark between the stars. A 20-foot-radius sphere of blackness and bitter cold appears, centered on a point within range. Any creature that starts its turn in the area takes 2d6 cold damage. Any creature that ends its turn there must make a Dexterity save or take 2d6 acid damage.', classes: ['warlock'], damageType: 'cold', tags: ['damage', 'aoe', 'control'] },
  { id: 'intellect-fortress', name: 'Intellect Fortress', level: 3, school: 'Abjuration', sourceBook: 'TCE', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'For the duration, you or one willing creature you can see within range has resistance to psychic damage, as well as advantage on Intelligence, Wisdom, and Charisma saving throws.\n\nTarget one additional creature per slot above 3rd.', atHigherLevels: 'Target one additional creature per slot above 3rd.', classes: ['artificer', 'bard', 'sorcerer', 'warlock', 'wizard'], tags: ['buff', 'defense'] },
  { id: 'life-transference', name: 'Life Transference', level: 3, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You sacrifice some of your health to mend another\'s injuries. You take 4d8 necrotic damage, and one creature you can see within range regains a number of hit points equal to twice the necrotic damage you take.\n\nDamage and healing increase by 1d8 per slot above 3rd.', atHigherLevels: 'Damage and healing increase by 1d8 per slot above 3rd.', classes: ['cleric', 'wizard'], damageType: 'necrotic', tags: ['healing'] },
  { id: 'major-image', name: 'Major Image', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fleece', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot cube. The image appears at a spot you can see within range and lasts for the duration. It seems real, including sounds, smells, and temperature.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['illusion'] },
  { id: 'meld-into-stone', name: 'Meld into Stone', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '8 hours', concentration: false, ritual: true, description: 'You step into a stone object or surface large enough to fully contain your body, melding yourself and all the equipment you carry with the stone for the duration.', classes: ['cleric', 'druid'], tags: ['utility', 'ritual'] },
  { id: 'nondetection', name: 'Nondetection', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pinch of diamond dust worth 25 gp, sprinkled over the target', duration: '8 hours', concentration: false, ritual: false, description: 'For the duration, you hide a target from divination magic. The target can be a willing creature or a place or object no larger than 10 feet in any dimension. The target can\'t be targeted by divination magic or perceived through magical scrying sensors.', classes: ['bard', 'ranger', 'wizard'], tags: ['defense'] },
  { id: 'phantom-steed', name: 'Phantom Steed', level: 3, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: true, description: 'A Large quasi-real, horselike creature appears on the ground in an unoccupied space of your choice within range. The horse can be ridden only by you. The horse uses the statistics for a riding horse, except it has a speed of 100 feet and can travel 10 miles in an hour.', classes: ['wizard'], tags: ['utility', 'ritual', 'summoning'] },
  { id: 'remove-curse', name: 'Remove Curse', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'At your touch, all curses affecting one creature or object end. If the object is a cursed magic item, its curse remains, but the spell breaks its owner\'s attunement to the object so it can be removed or discarded.', classes: ['cleric', 'paladin', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'sleet-storm', name: 'Sleet Storm', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dust and a few drops of water', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Until the spell ends, freezing rain and sleet fall in a 20-foot-tall cylinder with a 40-foot radius centered on a point within range. The area is heavily obscured, exposed flames are doused, and the ground is difficult terrain. A creature that enters the area for the first time on a turn or starts its turn there must make a Dexterity save or fall prone.', classes: ['druid', 'sorcerer', 'wizard'], savingThrow: 'dex', tags: ['control', 'aoe'] },
  { id: 'summon-lesser-demons', name: 'Summon Lesser Demons', level: 3, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a vial of blood from a humanoid killed in the past 24 hours', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You utter foul words, summoning demons from the chaos of the Abyss. Roll on a table to determine the type and number of demons summoned. The demons are hostile to all creatures.', classes: ['warlock', 'wizard'], tags: ['summoning'] },
  { id: 'thunder-step', name: 'Thunder Step', level: 3, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You teleport yourself to an unoccupied space you can see within range. Immediately after you disappear, a thunderous boom sounds, and each creature within 10 feet of the space you left must make a Constitution save, taking 3d10 thunder damage on a failed save, or half as much on a successful one.\n\nDamage increases by 1d10 per slot above 3rd.', atHigherLevels: 'Damage increases by 1d10 per slot above 3rd.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'teleportation'] },
  { id: 'tidal-wave', name: 'Tidal Wave', level: 3, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of water', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You conjure up a wave of water that crashes down on an area within range. The area can be up to 30 feet long, up to 10 feet wide, and up to 10 feet tall. Each creature in that area must make a Dexterity saving throw. On a failed save, a creature takes 4d8 bludgeoning damage and is knocked prone.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'wall-of-sand', name: 'Wall of Sand', level: 3, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a handful of sand', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You conjure up a wall of swirling sand. The wall is up to 30 feet long, 10 feet high, and 10 feet thick, and it vanishes when the spell ends. It blocks line of sight, and any creature that ends its turn in the wall has its speed reduced to 0.', classes: ['wizard'], tags: ['control', 'aoe'] },
  { id: 'wall-of-water', name: 'Wall of Water', level: 3, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of water', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create a wall of water on the ground at a point you can see within range. You can make the wall up to 30 feet long, 10 feet high, and 1 foot thick. The wall lasts for the duration. The wall provides a measure of cover and slows projectiles and creatures.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['control'] },
  { id: 'water-breathing', name: 'Water Breathing', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a short reed or piece of straw', duration: '24 hours', concentration: false, ritual: true, description: 'This spell grants up to ten willing creatures you can see within range the ability to breathe underwater until the spell ends. Affected creatures also retain their normal mode of respiration.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'water-walk', name: 'Water Walk', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of cork', duration: '1 hour', concentration: false, ritual: true, description: 'This spell grants the ability to move across any liquid surface — such as water, acid, mud, snow, quicksand, or lava — as if it were harmless solid ground. Up to ten willing creatures of your choice can be affected.', classes: ['artificer', 'cleric', 'druid', 'ranger', 'sorcerer'], tags: ['utility', 'ritual'] },
  { id: 'wind-wall', name: 'Wind Wall', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny fan and a feather of exotic origin', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A wall of strong wind rises from the ground at a point you choose within range. You can make the wall up to 50 feet long, 15 feet high, and 1 foot thick. The wall lasts for the duration. Gases and vapors can\'t pass through it. Ranged weapon attacks that pass through the wall have disadvantage.', classes: ['druid', 'ranger'], tags: ['control'] },

  // ── ADDITIONAL LEVEL 4 SPELLS ──────────────────────────────────────────
  { id: 'blight', name: 'Blight', level: 4, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a Constitution save, taking 8d8 necrotic damage on failure, or half as much on success. This spell has no effect on undead or constructs. Plants automatically fail and take maximum damage.\n\nDamage increases by 1d8 per slot above 4th.', atHigherLevels: 'Damage increases by 1d8 per slot above 4th.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'confusion', name: 'Confusion', level: 4, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'three nut shells', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'This spell assaults and twists creatures\' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere must succeed on a Wisdom saving throw or be affected. An affected target can\'t take reactions and must roll a d10 at the start of each of its turns for behavior.\n\nRadius increases by 5 feet per slot above 4th.', atHigherLevels: 'Radius increases by 5 feet per slot above 4th.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'aoe'] },
  { id: 'conjure-minor-elementals', name: 'Conjure Minor Elementals', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You summon elementals that appear in unoccupied spaces that you can see within range. Choose one of the following options: one elemental of CR 2 or lower, two elementals of CR 1 or lower, four elementals of CR 1/2 or lower, or eight elementals of CR 1/4 or lower.', classes: ['druid', 'wizard'], tags: ['summoning'] },
  { id: 'conjure-woodland-beings', name: 'Conjure Woodland Beings', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'one holly berry per creature summoned', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You summon fey creatures that appear in unoccupied spaces within range. Choose one of the following options: one fey creature of CR 2 or lower, two fey of CR 1 or lower, four fey of CR 1/2 or lower, or eight fey of CR 1/4 or lower.', classes: ['druid', 'ranger'], tags: ['summoning'] },
  { id: 'control-water', name: 'Control Water', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of water and a pinch of dust', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, you control any freestanding water inside an area you choose that is a cube up to 100 feet on a side. You can choose from the following effects when you cast this spell: rise and overflow, part water, redirect flow, or whirlpool.', classes: ['cleric', 'druid', 'wizard'], tags: ['control', 'utility'] },
  { id: 'divination', name: 'Divination', level: 4, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'incense and a sacrificial offering appropriate to your religion, together worth at least 25 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: true, description: 'Your magic and an offering put you in contact with a god or a god\'s servants. You ask one question concerning a specific goal, event, or activity to occur within 7 days. The DM offers a truthful reply.', classes: ['cleric'], tags: ['utility', 'ritual', 'divination'] },
  { id: 'dominate-beast', name: 'Dominate Beast', level: 4, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to beguile a beast that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. You have a telepathic link with it.\n\nDuration increases at higher slot levels.', atHigherLevels: '5th: 10 minutes. 6th: 1 hour. 7th+: 8 hours.', classes: ['druid', 'sorcerer'], savingThrow: 'wis', tags: ['control'] },
  { id: 'elemental-bane', name: 'Elemental Bane', level: 4, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose one creature you can see within range, and choose one of the following damage types: acid, cold, fire, lightning, or thunder. The target must succeed on a Constitution save or lose resistance to the chosen type, and the next time it takes that damage type, it takes an extra 2d6 damage.\n\nTarget one additional creature per slot above 4th.', atHigherLevels: 'Target one additional creature per slot above 4th.', classes: ['artificer', 'druid', 'warlock', 'wizard'], savingThrow: 'con', tags: ['debuff'] },
  { id: 'fabricate', name: 'Fabricate', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '10 minutes', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, and clothes from flax or wool.', classes: ['artificer', 'wizard'], tags: ['utility'] },
  { id: 'find-greater-steed', name: 'Find Greater Steed', level: 4, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '10 minutes', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You summon a spirit that assumes the form of a loyal, majestic mount. Appearing in an unoccupied space within range, the spirit takes on a form you choose: a griffon, a pegasus, a peryton, a dire wolf, a rhinoceros, or a saber-toothed tiger.', classes: ['paladin'], tags: ['summoning'] },
  { id: 'fire-shield', name: 'Fire Shield', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a bit of phosphorus or a firefly', duration: '10 minutes', concentration: false, ritual: false, description: 'Thin and wispy flames wreathe your body for the duration. The flames provide bright light and dim light. You can choose between a warm shield (resistance to cold) and a chill shield (resistance to fire). A creature within 5 feet that hits you with a melee attack takes 2d8 damage of the opposite type.', classes: ['wizard'], damageType: 'fire', tags: ['defense', 'damage'] },
  { id: 'giant-insect', name: 'Giant Insect', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You transform up to ten centipedes, three spiders, five wasps, or one scorpion within range into giant versions of their natural forms for the duration. The giant insects follow your commands.', classes: ['druid'], tags: ['summoning', 'control'] },
  { id: 'grasping-vine', name: 'Grasping Vine', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You conjure a vine that sprouts from the ground in an unoccupied space of your choice within range. When you cast the spell, you can direct the vine to lash out at a creature within 30 feet of it. That creature must succeed on a Dexterity saving throw or be pulled 20 feet directly toward the vine.', classes: ['druid', 'ranger'], savingThrow: 'dex', tags: ['control'] },
  { id: 'guardian-of-faith', name: 'Guardian of Faith', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: '8 hours', concentration: false, ritual: false, description: 'A Large spectral guardian appears and hovers for the duration in an unoccupied space of your choice. Any creature hostile to you that moves to a space within 10 feet of the guardian for the first time on a turn must succeed on a Dexterity save or take 20 radiant damage.', classes: ['cleric'], damageType: 'radiant', savingThrow: 'dex', tags: ['damage', 'control'] },
  { id: 'guardian-of-nature', name: 'Guardian of Nature', level: 4, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A nature spirit answers your call and transforms you into a powerful guardian. The form lasts for the duration. Choose one of the following forms: Primal Beast or Great Tree. Each provides various benefits.', classes: ['druid', 'ranger'], tags: ['buff'] },
  { id: 'hallucinatory-terrain', name: 'Hallucinatory Terrain', level: 4, school: 'Illusion', sourceBook: 'PHB', castingTime: '10 minutes', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a stone, a twig, and a bit of green plant', duration: '24 hours', concentration: false, ritual: false, description: 'You make natural terrain in a 150-foot cube look, sound, and smell like some other sort of natural terrain. Thus, an open field could become a swamp, or a rocky hill could become a forested glen.', classes: ['bard', 'druid', 'warlock', 'wizard'], tags: ['illusion'] },
  { id: 'leomunds-secret-chest', name: 'Leomund\'s Secret Chest', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an exquisite chest worth at least 5,000 gp and a Tiny replica worth at least 50 gp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You hide a chest, and all its contents, on the Ethereal Plane. You must touch the chest and the miniature replica that serves as a material component. You can use an action to recall the chest.', classes: ['artificer', 'wizard'], tags: ['utility'] },
  { id: 'locate-creature', name: 'Locate Creature', level: 4, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur from a bloodhound', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Describe or name a creature that is familiar to you. You sense the direction to the creature\'s location, as long as that creature is within 1,000 feet of you.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard'], tags: ['utility', 'divination'] },
  { id: 'mordenkainens-faithful-hound', name: 'Mordenkainen\'s Faithful Hound', level: 4, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny silver whistle, a piece of bone, and a thread', duration: '8 hours', concentration: false, ritual: false, description: 'You conjure a phantom watchdog in an unoccupied space within range, where it remains for the duration. The hound is invisible to all but you and can\'t be harmed. It barks if it detects creatures within 30 feet and can make bite attacks.', classes: ['wizard'], damageType: 'piercing', tags: ['summoning'] },
  { id: 'mordenkainens-private-sanctum', name: 'Mordenkainen\'s Private Sanctum', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a thin sheet of lead, a piece of opaque glass, a wad of cotton or cloth, and powdered chrysolite', duration: '24 hours', concentration: false, ritual: false, description: 'You make an area within range magically secure. The area is a cube that can be as small as 5 feet to as large as 100 feet on each side. Various magical effects guard the area such as preventing scrying, blocking divination, and preventing teleportation.', classes: ['wizard'], tags: ['utility', 'defense'] },
  { id: 'otilukes-resilient-sphere', name: 'Otiluke\'s Resilient Sphere', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a hemispherical piece of clear crystal and a matching hemispherical piece of gum arabic', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A sphere of shimmering force encloses a creature or object of Large size or smaller within range. An unwilling creature must make a Dexterity save. The sphere encloses the target for the duration. Nothing can pass through.', classes: ['artificer', 'wizard'], savingThrow: 'dex', tags: ['control'] },
  { id: 'phantasmal-killer', name: 'Phantasmal Killer', level: 4, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You tap into the nightmares of a creature you can see and create an illusory manifestation of its deepest fears. The target must make a Wisdom save. On a failed save, the target becomes frightened for the duration. At the end of each of its turns, it must succeed on another save or take 4d10 psychic damage.\n\nDamage increases by 1d10 per slot above 4th.', atHigherLevels: 'Damage increases by 1d10 per slot above 4th.', classes: ['wizard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'control'] },
  { id: 'staggering-smite', name: 'Staggering Smite', level: 4, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a melee weapon attack during the spell\'s duration, your weapon pierces both body and mind. The attack deals an extra 4d6 psychic damage to the target. The target must make a Wisdom save or have disadvantage on attack rolls and ability checks, and not take reactions, until the end of its next turn.', classes: ['paladin'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'smite'] },
  { id: 'stone-shape', name: 'Stone Shape', level: 4, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'soft clay, which must be worked into roughly the desired shape of the stone object', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a stone object of Medium size or smaller, or a section of stone no more than 5 feet in any dimension, and form it into any shape that suits your purpose.', classes: ['artificer', 'cleric', 'druid', 'wizard'], tags: ['utility'] },
  { id: 'summon-aberration', name: 'Summon Aberration', level: 4, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a pickled tentacle and an eyeball in a platinum-inlaid vial worth at least 400 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth an aberrant spirit. It manifests in an unoccupied space within range. Choose its type: Beholderkin, Slaadi, or Star Spawn.\n\nAt higher levels, it uses higher stat blocks.', atHigherLevels: 'Higher CR per slot above 4th.', classes: ['warlock', 'wizard'], tags: ['summoning'] },
  { id: 'summon-construct', name: 'Summon Construct', level: 4, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'an ornate stone or metal lockbox worth at least 400 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth the spirit of a construct. It manifests in an unoccupied space within range. Choose its material: Clay, Metal, or Stone.', classes: ['artificer', 'wizard'], tags: ['summoning'] },
  { id: 'summon-elemental', name: 'Summon Elemental', level: 4, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'air, a pebble, ash, and water inside a gold-inlaid vial worth at least 400 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth an elemental spirit. It manifests in an unoccupied space within range. Choose its element: Air, Earth, Fire, or Water.', classes: ['druid', 'ranger', 'wizard'], tags: ['summoning'] },

  // ── ADDITIONAL LEVEL 5 SPELLS ──────────────────────────────────────────
  { id: 'antilife-shell', name: 'Antilife Shell', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (10-foot radius)', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A shimmering barrier extends out from you in a 10-foot radius and moves with you, remaining centered on you for the duration. The barrier prevents creatures other than undead and constructs from passing or reaching through it.', classes: ['druid'], tags: ['defense'] },
  { id: 'awaken', name: 'Awaken', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '8 hours', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'an agate worth at least 1,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'After spending the casting time tracing magical pathways within a precious gemstone, you touch a Huge or smaller beast or plant. The target must have either no Intelligence score or one of 3 or less. The target gains an Intelligence of 10, the ability to speak one language you know, and the ability to move its limbs/roots.', classes: ['bard', 'druid'], tags: ['utility'] },
  { id: 'bigbys-hand', name: 'Bigby\'s Hand', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'an eggshell and a snakeskin glove', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a Large hand of shimmering, translucent force in an unoccupied space that you can see within range. The hand lasts for the spell\'s duration. You can use a bonus action to control the hand, making it punch (4d8 force damage), push, grapple, or shield.', classes: ['artificer', 'sorcerer', 'wizard'], damageType: 'force', tags: ['damage', 'control'] },
  { id: 'circle-of-power', name: 'Circle of Power', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Divine energy radiates from you, distorting and diffusing magical energy within 30 feet of you. Until the spell ends, the sphere moves with you. For the duration, each friendly creature in the area (including you) has advantage on saving throws against spells and other magical effects.', classes: ['paladin'], tags: ['buff', 'defense'] },
  { id: 'commune', name: 'Commune', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'incense and a vial of holy or unholy water', duration: '1 minute', concentration: false, ritual: true, description: 'You contact your deity or a divine proxy and ask up to three questions that can be answered with a yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question.', classes: ['cleric'], tags: ['utility', 'ritual', 'divination'] },
  { id: 'commune-with-nature', name: 'Commune with Nature', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: true, description: 'You briefly become one with nature and gain knowledge of the surrounding territory. In the outdoors, the spell gives you knowledge of the land within 3 miles of you. You instantly gain knowledge of up to three facts of your choice about: terrain and bodies of water, prevalent plants/animals/people, powerful celestials, elementals, fey, fiends, or undead, and buildings.', classes: ['druid', 'ranger'], tags: ['utility', 'ritual', 'divination'] },
  { id: 'conjure-elemental', name: 'Conjure Elemental', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'burning incense for air, soft clay for earth, sulfur and phosphorus for fire, or water and sand for water', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth an elemental servant. Choose an area of air, earth, fire, or water that fills a 10-foot cube within range. An elemental of CR 5 or lower appropriate to the area you chose appears in an unoccupied space within 10 feet of it.', classes: ['druid', 'wizard'], tags: ['summoning'] },
  { id: 'conjure-volley', name: 'Conjure Volley', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'one piece of ammunition or one thrown weapon', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You fire a piece of nonmagical ammunition or throw a nonmagical weapon into the air to create a cone of identical projectiles. Each creature in a 40-foot-radius, 20-foot-high cylinder must make a Dex save, taking 8d8 damage of the appropriate type on a failed save, or half as much on a success.', classes: ['ranger'], damageType: 'piercing', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'contact-other-plane', name: 'Contact Other Plane', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V'], duration: '1 minute', concentration: false, ritual: true, description: 'You mentally contact a demigod, the spirit of a long-dead sage, or some other mysterious entity from another plane. You must make a DC 15 Intelligence saving throw or take 6d6 psychic damage and be insane until you finish a long rest. On success, you can ask up to five questions before the spell ends.', classes: ['warlock', 'wizard'], damageType: 'psychic', tags: ['utility', 'ritual', 'divination'] },
  { id: 'contagion', name: 'Contagion', level: 5, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '7 days', concentration: false, ritual: false, description: 'Your touch inflicts disease. Make a melee spell attack against a creature within your reach. On a hit, you afflict the creature with a disease of your choice. At the end of each of the target\'s turns, it must make a Constitution saving throw. After failing three of these saves, the disease takes hold.', classes: ['cleric', 'druid'], savingThrow: 'con', tags: ['damage', 'debuff'] },
  { id: 'control-winds', name: 'Control Winds', level: 5, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '300 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You take control of the air in a 100-foot cube that you can see within range. Choose one of the following effects when you cast this spell: gusts, downdraft, or updraft. The effects last for the duration.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['control'] },
  { id: 'creation', name: 'Creation', level: 5, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny piece of matter of the same type of the item you plan to create', duration: 'Special', concentration: false, ritual: false, description: 'You pull wisps of shadow material from the Shadowfell to create a nonliving object of vegetable matter within range: soft goods, rope, wood, and so on. The object lasts based on its material.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['utility'] },
  { id: 'danse-macabre', name: 'Danse Macabre', level: 5, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of bone and a piece of thread', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Threads of dark power leap from your fingers to animate up to five Small or Medium corpses within range. Each corpse becomes a zombie or skeleton (your choice) under your control. You can use a bonus action to command them.', classes: ['warlock', 'wizard'], tags: ['summoning'] },
  { id: 'destructive-wave', name: 'Destructive Wave', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You strike the ground, creating a burst of divine energy that ripples outward from you. Each creature you choose within 30 feet of you must succeed on a Constitution saving throw or take 5d6 thunder damage, as well as 5d6 radiant or necrotic damage (your choice), and be knocked prone. A creature that succeeds on its saving throw takes half as much damage and isn\'t knocked prone.', classes: ['paladin'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'dispel-evil-and-good', name: 'Dispel Evil and Good', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'holy water or powdered silver and iron worth at least 100 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Shimmering energy surrounds and protects you from fey, undead, and creatures originating from beyond the Material Plane. Such creatures have disadvantage on attack rolls against you. You can also dismiss such creatures or break enchantments.', classes: ['cleric', 'paladin'], tags: ['buff', 'defense'] },
  { id: 'dream', name: 'Dream', level: 5, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 minute', range: 'Special', components: ['V', 'S', 'M'], materialComponent: 'a handful of sand, a dab of ink, and a writing quill plucked from a sleeping bird', duration: '8 hours', concentration: false, ritual: false, description: 'This spell shapes a creature\'s dreams. Choose a creature known to you as the target. The target must be on the same plane of existence as you. You enter a trance and become aware of a phantasmal messenger that you send.', classes: ['bard', 'warlock', 'wizard'], tags: ['utility', 'illusion'] },
  { id: 'enervation', name: 'Enervation', level: 5, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A tendril of dark energy snakes out from your fingertips and latches on to a creature you can see within range, draining life from it. The target must make a Dexterity saving throw. On a successful save, the target takes 2d8 necrotic damage, and the spell ends. On a failed save, the target takes 4d8 necrotic damage, and until the spell ends, you can use your action on each of your turns to automatically deal 4d8 necrotic damage to the target. The spell ends if you use your action to do anything else, if the target is ever outside the spell\'s range, or if the target has total cover from you.\n\nWhenever the spell deals damage to a target, you regain hit points equal to half the amount of necrotic damage the target takes.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'dex', tags: ['damage'] },
  { id: 'far-step', name: 'Far Step', level: 5, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You teleport up to 60 feet to an unoccupied space you can see. On each of your turns before the spell ends, you can use a bonus action to teleport in this way again.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['teleportation'] },
  { id: 'geas', name: 'Geas', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 minute', range: '60 feet', components: ['V'], duration: '30 days', concentration: false, ritual: false, description: 'You place a magical command on a creature that you can see within range, forcing it to carry out some service or refrain from some action. If the creature understands you, it must succeed on a Wisdom save or become charmed. The creature takes 5d10 psychic damage if it acts contrary to your command.', classes: ['bard', 'cleric', 'druid', 'paladin', 'wizard'], damageType: 'psychic', savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'hallow', name: 'Hallow', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '24 hours', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'herbs, oils, and incense worth at least 1,000 gp, which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: false, description: 'You touch a point and infuse an area around it with holy or unholy power. The area can have a radius up to 60 feet. Affected creatures of a chosen type cannot enter the area and creatures within gain additional effects.', classes: ['cleric'], tags: ['utility', 'aoe'] },
  { id: 'holy-weapon', name: 'Holy Weapon', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You imbue a weapon you touch with holy power. Until the spell ends, the weapon emits bright light in a 30-foot radius and dim light for an additional 30 feet. In addition, weapon attacks made with it deal an extra 2d8 radiant damage on a hit. If the weapon isn\'t already a magic weapon, it becomes one for the duration.\n\nAs a bonus action on your turn, you can dismiss this spell and cause the weapon to emit a burst of radiance. When you do so, each creature of your choice that you can see within 30 feet of the weapon must make a Constitution saving throw. On a failed save, a creature takes 4d8 radiant damage and is blinded for 1 minute. On a successful save, a creature takes half as much damage and isn\'t blinded. At the end of each of its turns, a blinded creature can make a Constitution saving throw, ending the effect on itself on a success.', classes: ['cleric', 'paladin'], damageType: 'radiant', savingThrow: 'con', tags: ['buff'] },
  { id: 'infernal-calling', name: 'Infernal Calling', level: 5, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 minute', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a ruby worth at least 999 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Uttering a dark incantation, you summon a devil from the Nine Hells. You choose the type of devil to summon, but it must be one whose challenge rating is no higher than your spell\'s level. The devil isn\'t under your control.', classes: ['warlock', 'wizard'], tags: ['summoning'] },
  { id: 'insect-plague', name: 'Insect Plague', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a few grains of sugar, some kernels of grain, and a smear of fat', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Swarming, biting locusts fill a 20-foot-radius sphere centered on a point you choose within range. The sphere spreads around corners. When the cloud appears and at the end of each of your turns, each creature in the area must make a Constitution save, taking 4d10 piercing damage on a failure.', classes: ['cleric', 'druid', 'sorcerer'], damageType: 'piercing', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'legend-lore', name: 'Legend Lore', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'incense worth at least 250 gp, which the spell consumes, and four ivory strips worth at least 50 gp each', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Name or describe a person, place, or object. The spell brings to your mind a brief summary of the significant lore about the thing you named.', classes: ['bard', 'cleric', 'wizard'], tags: ['utility', 'divination'] },
  { id: 'maelstrom', name: 'Maelstrom', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'paper or leaf in the shape of a funnel', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A mass of 5-foot-deep water appears and swirls in a 30-foot radius centered on a point you can see within range. The point must be on ground or in water. Until the spell ends, that area is difficult terrain. Any creature that enters the area or starts its turn there must make a Strength save or take 6d6 bludgeoning damage and be pulled 10 feet toward the center.', classes: ['druid'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'mislead', name: 'Mislead', level: 5, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You become invisible at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends if you attack or cast a spell.', classes: ['bard', 'wizard'], tags: ['illusion', 'utility'] },
  { id: 'modify-memory', name: 'Modify Memory', level: 5, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to reshape another creature\'s memories. One creature that you can see must make a Wisdom save. If you are fighting the creature, it has advantage on the save. On a failed save, you can modify the target\'s memories of an event within the last 24 hours.', classes: ['bard', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'negative-energy-flood', name: 'Negative Energy Flood', level: 5, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'M'], materialComponent: 'a broken bone and a square of black silk', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send ribbons of necrotic energy at one creature within range. The target must make a Constitution save, taking 5d12 necrotic damage on failed save, or half as much on success. A target killed by this damage rises up as a zombie at the start of your next turn.', classes: ['warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'passwall', name: 'Passwall', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of sesame seeds', duration: '1 hour', concentration: false, ritual: false, description: 'A passage appears at a point of your choice that you can see on a wooden, plaster, or stone surface within range. The passage is 5 feet wide, 8 feet tall, and 20 feet deep. When the spell ends, anyone still inside is shunted to the nearest unoccupied space.', classes: ['wizard'], tags: ['utility'] },
  { id: 'planar-binding', name: 'Planar Binding', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 hour', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a jewel worth at least 1,000 gp, which the spell consumes', duration: '24 hours', concentration: false, ritual: false, description: 'With this spell, you attempt to bind a celestial, an elemental, a fey, or a fiend to your service. The creature must make a Charisma save. On a failed save, it is bound to serve you for 24 hours.', classes: ['bard', 'cleric', 'druid', 'wizard'], savingThrow: 'cha', tags: ['control'] },
  { id: 'rarys-telepathic-bond', name: 'Rary\'s Telepathic Bond', level: 5, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'pieces of eggshell from two different kinds of creatures', duration: '1 hour', concentration: false, ritual: true, description: 'You forge a telepathic link among up to eight willing creatures of your choice within range. Until the spell ends, the targets can communicate telepathically through the bond.', classes: ['wizard'], tags: ['utility', 'ritual'] },
  { id: 'seeming', name: 'Seeming', level: 5, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '8 hours', concentration: false, ritual: false, description: 'This spell allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. The illusion can\'t make a creature appear like a different type, only different in body proportions.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['illusion'] },
  { id: 'skill-empowerment', name: 'Skill Empowerment', level: 5, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Your magic deepens a creature\'s understanding of its own talent. You touch one willing creature and give it expertise in one skill of your choice; until the spell ends, the creature doubles its proficiency bonus for ability checks it makes that use the chosen skill.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['buff'] },
  { id: 'summon-celestial', name: 'Summon Celestial', level: 5, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a golden reliquary worth at least 500 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a celestial spirit. It manifests in an unoccupied space within range. Choose Avenger or Defender.', classes: ['cleric', 'paladin'], tags: ['summoning'] },
  { id: 'summon-draconic-spirit', name: 'Summon Draconic Spirit', level: 5, school: 'Conjuration', sourceBook: 'FToD', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a vial of dragon\'s blood worth at least 500 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a draconic spirit. It manifests in an unoccupied space within range. Choose its essence: Chromatic, Gem, or Metallic.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['summoning'] },
  { id: 'swift-quiver', name: 'Swift Quiver', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a quiver containing at least one piece of ammunition', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You transmute your quiver so it produces an endless supply of nonmagical ammunition. On each of your turns until the spell ends, you can use a bonus action to make two attacks with a weapon that uses ammunition from the quiver.', classes: ['ranger'], tags: ['buff'] },
  { id: 'synaptic-static', name: 'Synaptic Static', level: 5, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You choose a point within range and cause psychic energy to explode there. Each creature in a 20-foot-radius sphere centered on that point must make an Intelligence saving throw. A creature with an Intelligence score of 2 or lower can\'t be affected by this spell. A target takes 8d6 psychic damage on a failed save, or half as much damage on a successful one.\n\nAfter a failed save, a target has muddled thoughts for 1 minute. During that time, it rolls a d6 and subtracts the number rolled from all its attack rolls and ability checks, as well as its Constitution saving throws to maintain concentration. The target can make an Intelligence saving throw at the end of each of its turns, ending the effect on itself on a success.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'aoe', 'debuff'] },
  { id: 'teleportation-circle', name: 'Teleportation Circle', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '10 feet', components: ['V', 'M'], materialComponent: 'rare chalks and inks infused with precious gems worth 50 gp, which the spell consumes', duration: '1 round', concentration: false, ritual: false, description: 'As you cast the spell, you draw a 10-foot-diameter circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know. A shimmering portal opens within the circle for 1 round.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['teleportation'] },
  { id: 'transmute-rock', name: 'Transmute Rock', level: 5, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'clay and water', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You choose an area of stone or mud that you can see and that fits within a 40-foot cube and is within range. You manipulate it: transmute rock to mud or mud to rock.', classes: ['artificer', 'druid', 'wizard'], tags: ['utility', 'control'] },
  { id: 'tree-stride', name: 'Tree Stride', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You gain the ability to enter a tree and move from inside it to inside another tree of the same kind within 500 feet. Both trees must be living and at least the same size as you.', classes: ['druid', 'ranger'], tags: ['teleportation'] },
  { id: 'wall-of-light', name: 'Wall of Light', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a hand mirror', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A shimmering wall of bright light appears at a point you choose within range. The wall is 10 feet thick, 60 feet long, 10 feet high. When the wall appears, each creature in its area must make a Constitution save, taking 4d8 radiant damage on failure. The wall sheds bright light.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'control'] },
  { id: 'wall-of-stone', name: 'Wall of Stone', level: 5, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a small block of granite', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A nonmagical wall of solid stone springs into existence at a point you choose within range. The wall is 6 inches thick and is composed of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another. If the wall is concentrated on for the full duration, it becomes permanent.', classes: ['artificer', 'druid', 'sorcerer', 'wizard'], tags: ['control'] },
  { id: 'wrath-of-nature', name: 'Wrath of Nature', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You call out to the spirits of nature to rouse them against your enemies. Choose a point within range; a 60-foot cube extends from that point. The plants and ground turn against creatures other than you in the area, gaining various harmful effects.', classes: ['druid', 'ranger'], tags: ['damage', 'control'] },

  // ── LEVEL 6 SPELLS ────────────────────────────────────────────────────
  { id: 'arcane-gate', name: 'Arcane Gate', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '500 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create linked teleportation portals that remain open for the duration. Choose two points on the ground that you can see, one within 10 feet of you and one within 500 feet of you. A circular portal, 10 feet in diameter, opens over each point.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['teleportation'] },
  { id: 'blade-barrier', name: 'Blade Barrier', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create a vertical wall of whirling, razor-sharp blades made of magical energy. The wall appears within range and lasts for the duration. You can make a straight wall up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter, 20 feet high, and 5 feet thick. The wall provides three-quarters cover to creatures behind it, and its space is difficult terrain.\n\nWhen a creature enters the wall\'s area for the first time on a turn or starts its turn there, the creature must make a Dexterity saving throw. On a failed save, the creature takes 6d10 slashing damage. On a successful save, the creature takes half as much damage.', classes: ['cleric'], damageType: 'slashing', savingThrow: 'dex', tags: ['damage', 'aoe', 'control'] },
  { id: 'bones-of-the-earth', name: 'Bones of the Earth', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You cause up to six pillars of stone to burst from places on the ground that you can see within range. Each pillar is a cylinder 5 feet in diameter and up to 30 feet tall. The ground where a pillar appears must be wide enough for its diameter. If a creature is in the pillar\'s space when it bursts, it must make a Dex save or take 6d6 bludgeoning damage.', classes: ['druid'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'control'] },
  { id: 'circle-of-death', name: 'Circle of Death', level: 6, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'the powder of a crushed black pearl worth at least 500 gp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A sphere of negative energy ripples out in a 60-foot-radius sphere from a point within range. Each creature in that area must make a Constitution save, taking 8d6 necrotic damage on a failed save, or half as much on success.\n\nDamage increases by 2d6 per slot above 6th.', atHigherLevels: 'Damage increases by 2d6 per slot above 6th.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'conjure-fey', name: 'Conjure Fey', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You summon a fey creature of CR 6 or lower, or a fey spirit that takes the form of a beast of CR 6 or lower. It appears in an unoccupied space that you can see within range.', classes: ['druid', 'warlock'], tags: ['summoning'] },
  { id: 'contingency', name: 'Contingency', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a statuette of yourself carved from ivory and decorated with gems worth at least 1,500 gp', duration: '10 days', concentration: false, ritual: false, description: 'Choose a spell of 5th level or lower that you can cast, that has a casting time of 1 action, and that can target you. You cast that spell — called the contingent spell — as part of casting Contingency, expending spell slots for both, but the contingent spell doesn\'t come into effect. It triggers when a chosen circumstance occurs.', classes: ['wizard'], tags: ['utility'] },
  { id: 'create-undead', name: 'Create Undead', level: 6, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 minute', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'one clay pot filled with grave dirt, one clay pot filled with brackish water, and one 150 gp black onyx stone for each corpse', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You can cast this spell only at night. Choose up to three corpses of Medium or Small humanoids within range. Each corpse becomes a ghoul under your control. You can use an action to control them within 120 feet for 24 hours.', classes: ['cleric', 'warlock', 'wizard'], tags: ['summoning'] },
  { id: 'disintegrate', name: 'Disintegrate', level: 6, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a lodestone and a pinch of dust', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A thin green ray springs from your pointing finger to a target that you can see within range. The target can be a creature, an object, or a creation of magical force. A creature targeted must make a Dexterity save. On a failed save, the target takes 10d6 + 40 force damage. If reduced to 0 hit points, it is disintegrated.\n\nDamage increases by 3d6 per slot above 6th.', atHigherLevels: 'Damage increases by 3d6 per slot above 6th.', classes: ['sorcerer', 'wizard'], damageType: 'force', savingThrow: 'dex', tags: ['damage'] },
  { id: 'drawmijs-instant-summons', name: 'Drawmij\'s Instant Summons', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a sapphire worth 1,000 gp', duration: 'Until dispelled', concentration: false, ritual: true, description: 'You touch an object weighing 10 pounds or less. It vanishes into an extradimensional space. You can use an action to speak the item\'s name and summon it back to your hand from anywhere.', classes: ['wizard'], tags: ['utility', 'ritual'] },
  { id: 'eyebite', name: 'Eyebite', level: 6, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'For the spell\'s duration, your eyes become an inky void imbued with dread power. One creature of your choice within 60 feet of you that you can see must succeed on a Wisdom saving throw or be affected by one of the following effects of your choice for the duration. On each of your turns until the spell ends, you can use your action to target another creature but can\'t target a creature again if it has succeeded on a saving throw against this casting of eyebite.\n\nAsleep. The target falls unconscious. It wakes up if it takes any damage or if another creature uses its action to shake the sleeper awake.\n\nPanicked. The target is frightened of you. On each of its turns, the frightened creature must take the Dash action and move away from you by the safest and shortest available route, unless there is nowhere to move. If the target moves to a place at least 60 feet away from you where it can no longer see you, this effect ends.\n\nSickened. The target has disadvantage on attack rolls and ability checks. At the end of each of its turns, it can make another Wisdom saving throw. If it succeeds, the effect ends.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'debuff'] },
  { id: 'find-the-path', name: 'Find the Path', level: 6, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a set of divinatory tools worth at least 100 gp', duration: 'Concentration, up to 1 day', concentration: true, ritual: false, description: 'This spell allows you to find the shortest, most direct physical route to a specific fixed location that you are familiar with. As long as you and the destination are on the same plane, you know where it lies and the most direct route.', classes: ['bard', 'cleric', 'druid'], tags: ['utility', 'divination'] },
  { id: 'flesh-to-stone', name: 'Flesh to Stone', level: 6, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of lime, water, and earth', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to turn one creature that you can see within range into stone. If the target\'s body is made of flesh, it must make a Constitution save. On a failed save, it is restrained. On three failed saves, it is petrified for the duration.', classes: ['warlock', 'wizard'], savingThrow: 'con', tags: ['control'] },
  { id: 'forbiddance', name: 'Forbiddance', level: 6, school: 'Abjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a sprinkling of holy water, rare incense, and powdered ruby worth at least 1,000 gp', duration: '1 day', concentration: false, ritual: true, description: 'You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet. For the duration, creatures can\'t teleport into the area or use planar travel, and the area is also warded against creatures of your chosen type.', classes: ['cleric'], tags: ['utility', 'ritual', 'defense'] },
  { id: 'globe-of-invulnerability', name: 'Globe of Invulnerability', level: 6, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (10-foot radius)', components: ['V', 'S', 'M'], materialComponent: 'a glass or crystal bead that shatters when the spell ends', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'An immobile, faintly shimmering barrier springs into existence in a 10-foot radius around you and remains for the duration. Any spell of 5th level or lower cast from outside the barrier can\'t affect creatures or objects within it.', classes: ['sorcerer', 'wizard'], tags: ['defense'] },
  { id: 'guards-and-wards', name: 'Guards and Wards', level: 6, school: 'Abjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'burning incense, a small measure of brimstone and oil, a knotted string, a small amount of umber hulk blood, and a small silver rod worth at least 10 gp', duration: '24 hours', concentration: false, ritual: false, description: 'You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and shaped as you desire. Effects include fog, gusts of wind, webs, confusion in corridors, and door wards.', classes: ['bard', 'wizard'], tags: ['utility', 'defense'] },
  { id: 'harm', name: 'Harm', level: 6, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You unleash a virulent disease on a creature you can see within range. The target must make a Constitution saving throw. On a failed save, it takes 14d6 necrotic damage, or half as much on success. The damage can\'t reduce the target\'s hit points below 1. If the target fails the save, its hit point maximum is reduced for 1 hour.', classes: ['cleric'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage'] },
  { id: 'heal', name: 'Heal', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Choose a creature that you can see within range. A surge of positive energy washes through the creature, causing it to regain 70 hit points. This spell also ends blindness, deafness, and any diseases affecting the target.\n\nHealing increases by 10 hit points per slot above 6th.', atHigherLevels: 'Healing increases by 10 hit points per slot above 6th.', classes: ['cleric', 'druid'], tags: ['healing'] },
  { id: 'heroes-feast', name: 'Heroes\' Feast', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a gem-encrusted bowl worth at least 1,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You bring forth a great feast, including magnificent food and drink. The feast takes 1 hour to consume and disappears at the end of that time, and the beneficial effects don\'t set in until this hour is over. Up to twelve creatures can partake, gaining poison/fear immunity, advantage on Wisdom saves, max HP increase by 2d10, and 2d10 temp HP.', classes: ['bard', 'cleric', 'druid'], tags: ['buff', 'healing'] },
  { id: 'investiture-of-flame', name: 'Investiture of Flame', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Flames race across your body, igniting your clothes but causing you no harm. Until the spell ends, you shed light, have immunity to fire damage and resistance to cold damage, and creatures within 5 feet at the end of your turn take 1d10 fire damage. You can also produce a flame jet.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'fire', tags: ['buff', 'damage'] },
  { id: 'investiture-of-ice', name: 'Investiture of Ice', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, ice rimes your body, and you gain various effects: immunity to cold damage, resistance to fire damage, ground in a 10-foot radius is icy difficult terrain, and you can use an action to make a 15-foot cone of cold (4d6 cold damage, Con save half).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'cold', tags: ['buff', 'damage'] },
  { id: 'investiture-of-stone', name: 'Investiture of Stone', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, bits of rock spread across your body. You gain resistance to nonmagical bludgeoning, piercing, and slashing damage. You can move across difficult terrain made of rubble, rocks, or earth without spending extra movement. You can also use an action to topple foes.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], tags: ['buff'] },
  { id: 'investiture-of-wind', name: 'Investiture of Wind', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Until the spell ends, wind whirls around you, and you gain various effects: ranged weapon attacks have disadvantage, you gain a flying speed of 60 feet, and you can use an action to create a 15-foot cube of wind (3d10 bludgeoning damage).', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'bludgeoning', tags: ['buff'] },
  { id: 'magic-jar', name: 'Magic Jar', level: 6, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a gem, crystal, reliquary, or some other ornamental container worth at least 500 gp', duration: 'Until dispelled', concentration: false, ritual: false, description: 'Your body falls into a catatonic state as your soul leaves it and enters the container. While your soul inhabits the container, you can attempt to possess any humanoid within 100 feet.', classes: ['wizard'], tags: ['control'] },
  { id: 'mass-suggestion', name: 'Mass Suggestion', level: 6, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'M'], materialComponent: 'a snake\'s tongue and either a bit of honeycomb or a drop of sweet oil', duration: '24 hours', concentration: false, ritual: false, description: 'You suggest a course of activity, limited to a sentence or two, and magically influence up to twelve creatures of your choice within range who can hear and understand you. Creatures that can\'t be charmed are immune. Each target must succeed on a Wisdom save or follow the course.\n\nDuration extends at higher slot levels.', atHigherLevels: '7th: 10 days. 8th: 30 days. 9th: a year and a day.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'mental-prison', name: 'Mental Prison', level: 6, school: 'Illusion', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to bind a creature within an illusory cell that only it perceives. One creature you can see within range must make an Intelligence save. On a failed save, the target is incapacitated and unable to move, restrained by an illusion. The target takes 5d10 psychic damage if it appears to move. When the spell ends, it takes 10d10 psychic damage.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'control'] },
  { id: 'move-earth', name: 'Move Earth', level: 6, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'an iron blade and a small bag containing a mixture of soils', duration: 'Concentration, up to 2 hours', concentration: true, ritual: false, description: 'Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You could raise or lower the area\'s elevation, create or fill in a trench, or transform a flat plain into a hill.', classes: ['druid', 'sorcerer', 'wizard'], tags: ['utility', 'control'] },
  { id: 'otilukes-freezing-sphere', name: 'Otiluke\'s Freezing Sphere', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a small crystal sphere', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A frigid globe of cold energy streaks from your fingertips to a point within range, where it explodes in a 60-foot-radius sphere. Each creature within the area must make a Constitution save, taking 10d6 cold damage on failure.', classes: ['wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'otto-irresistible-dance', name: 'Otto\'s Irresistible Dance', level: 6, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose one creature that you can see within range. The target begins a comic dance in place: shuffling, tapping its feet, and capering. The target must use all its movement to dance without leaving its space and has disadvantage on attacks and saves. While the target is dancing, other creatures have advantage on attack rolls against it.', classes: ['bard', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'planar-ally', name: 'Planar Ally', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '10 minutes', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a primordial, a demon prince, or some other being of cosmic power. That entity sends a celestial, an elemental, or a fiend loyal to it to aid you.', classes: ['cleric'], tags: ['summoning'] },
  { id: 'primordial-ward', name: 'Primordial Ward', level: 6, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You have resistance to acid, cold, fire, lightning, and thunder damage for the spell\'s duration. You can use a reaction to convert one of those resistances to immunity until the start of your next turn.', classes: ['druid'], tags: ['buff', 'defense'] },
  { id: 'programmed-illusion', name: 'Programmed Illusion', level: 6, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of fleece and jade dust worth at least 25 gp', duration: 'Until dispelled', concentration: false, ritual: false, description: 'You create an illusion of an object, a creature, or some other visible phenomenon within range that activates when a specific condition occurs. The illusion can be up to a 30-foot cube and lasts for the duration.', classes: ['bard', 'wizard'], tags: ['illusion'] },
  { id: 'scatter', name: 'Scatter', level: 6, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'The air teleports up to five creatures of your choice that you can see within range to unoccupied spaces that you can see within 120 feet of you. An unwilling creature must succeed on a Wisdom save to resist being teleported.', classes: ['sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['teleportation', 'control'] },
  { id: 'soul-cage', name: 'Soul Cage', level: 6, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 reaction, which you take when a humanoid you can see within 60 feet of you dies', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny silver cage worth 100 gp', duration: '8 hours', concentration: false, ritual: false, description: 'This spell snatches the soul of a humanoid as it dies. The soul remains in the cage until you use it for a benefit (steal life, query soul, borrow experience, eyes of the dead) or until the spell ends.', classes: ['warlock', 'wizard'], tags: ['utility'] },
  { id: 'sunbeam', name: 'Sunbeam', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a magnifying glass', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A beam of brilliant light flashes out from your hand in a 5-foot-wide, 60-foot-long line. Each creature in the line must make a Constitution saving throw. On a failed save, a creature takes 6d8 radiant damage and is blinded until your next turn. On a successful save, it takes half as much damage and isn\'t blinded by this spell. Undead and oozes have disadvantage on this saving throw.\n\nYou can create a new line of radiance as your action on any turn until the spell ends.\n\nFor the duration, a mote of brilliant radiance shines in your hand. It sheds bright light in a 30-foot radius and dim light for an additional 30 feet. This light is sunlight.\n\nAt the start of each of your turns after you cast this spell, the beam can persist — any creature that is blinded by the spell can make a Constitution saving throw at the end of each of its turns, ending the blindness on a success.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'tenser-transformation', name: 'Tenser\'s Transformation', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a few hairs from a bull', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You endow yourself with endurance and martial prowess. Until the spell ends, you gain 50 temporary hit points, proficiency in all weapons and saving throws, advantage on attack rolls with melee weapons, and your hit deals an extra 2d12 force damage.', classes: ['wizard'], damageType: 'force', tags: ['buff'] },
  { id: 'wall-of-ice', name: 'Wall of Ice', level: 6, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a small piece of quartz', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create a wall of ice on a solid surface within range. The wall is 1 foot thick and up to 10 feet tall and 40 feet long, or it\'s a hemispherical dome up to 20 feet in diameter.\n\nWhen the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 10d6 cold damage, or 5d6 cold damage on a successful save.\n\nThe wall is an object that can be damaged and thus breached. It has AC 12 and 30 hit points per 10-foot section, and it is vulnerable to fire damage. Reducing a 10-foot section of wall to 0 hit points destroys it and leaves behind a sheet of frigid air in the space the section occupied. A creature moving through the sheet of frigid air for the first time on a turn must make a Constitution saving throw. That creature takes 5d6 cold damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, the damage the wall deals when it appears increases by 2d6, and the damage from passing through the sheet of frigid air increases by 1d6, for each slot level above 6th.', classes: ['wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },
  { id: 'wall-of-thorns', name: 'Wall of Thorns', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a handful of thorns', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create a wall of tough, pliable, tangled brush bristling with needle-sharp thorns. The wall appears within range on a solid surface and lasts for the duration. You can make a straight wall up to 60 feet long, 10 feet high, and 5 feet thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 5 feet thick. The wall blocks line of sight.\n\nWhen the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 7d8 piercing damage, or half as much damage on a successful save.\n\nA creature can move through the wall, albeit slowly and painfully. For every 1 foot a creature moves through the wall, it must spend 4 feet of movement. Furthermore, the first time a creature enters the wall on a turn or ends its turn there, the creature must make a Dexterity saving throw. It takes 7d8 piercing damage on a failed save, or half as much damage on a successful one.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, both types of damage increase by 1d8 for each slot level above 6th.', classes: ['druid'], damageType: 'piercing', savingThrow: 'dex', tags: ['damage', 'control'] },
  { id: 'wind-walk', name: 'Wind Walk', level: 6, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'fire and holy water', duration: '8 hours', concentration: false, ritual: false, description: 'You and up to ten willing creatures you can see within range assume a gaseous form for the duration, appearing as wisps of cloud. In this form, a creature has a flying speed of 300 feet and resistance to nonmagical damage.', classes: ['druid'], tags: ['utility', 'teleportation'] },
  { id: 'word-of-recall', name: 'Word of Recall', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '5 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You and up to five willing creatures within 5 feet of you instantly teleport to a previously designated sanctuary. You and any creatures that teleport with you appear in the nearest unoccupied space to the spot you designated when you prepared your sanctuary.', classes: ['cleric'], tags: ['teleportation'] },

  // ── LEVEL 7 SPELLS ────────────────────────────────────────────────────
  { id: 'conjure-celestial', name: 'Conjure Celestial', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '90 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You summon a celestial of CR 4 or lower, which appears in an unoccupied space that you can see within range. The celestial disappears when it drops to 0 hit points or when the spell ends.\n\nAt 9th level: CR 5 or lower.', atHigherLevels: 'At 9th level: CR 5 or lower.', classes: ['cleric'], tags: ['summoning'] },
  { id: 'crown-of-stars', name: 'Crown of Stars', level: 7, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'Seven star-like motes of light appear and orbit your head until the spell ends. You can use a bonus action to send one of the motes streaking toward one creature or object within 120 feet of you. Make a ranged spell attack; on a hit, the target takes 4d12 radiant damage. The motes also shed light.\n\nIncreases by two motes per slot above 7th.', atHigherLevels: 'Two extra motes per slot above 7th.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'radiant', tags: ['damage'] },
  { id: 'delayed-blast-fireball', name: 'Delayed Blast Fireball', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a tiny ball of bat guano and sulfur', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A beam of yellow light flashes from your pointing finger, then condenses to linger at a chosen point within range as a glowing bead. When the spell ends, the bead detonates with a low roar. Each creature in a 20-foot-radius sphere centered on that point must make a Dexterity saving throw, taking 12d6 fire damage on a failed save.\n\nDamage increases by 1d6 per round of delay.', atHigherLevels: 'Damage increases by 1d6 per slot above 7th.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'divine-word', name: 'Divine Word', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You utter a divine word, imbued with the power that shaped the world at the dawn of creation. Choose any number of creatures within range. Each creature that can hear you must make a Charisma save. On a failed save, a creature suffers an effect based on its current hit points: 50 HP or fewer — deafened for 1 minute; 40 HP or fewer — blinded and deafened for 10 minutes; 30 HP or fewer — blinded, deafened, and stunned for 1 hour; 20 HP or fewer — killed instantly. A celestial, elemental, fey, or fiend that fails its save is also forced back to its home plane and can\'t return for 24 hours.', classes: ['cleric'], savingThrow: 'cha', tags: ['damage', 'control'] },
  { id: 'draconic-transformation', name: 'Draconic Transformation', level: 7, school: 'Transmutation', sourceBook: 'FToD', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a statuette of a dragon worth at least 500 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'With a roar, you draw on the magic of dragons to transform yourself, taking on draconic features. You gain a flying speed of 60 feet, blindsight to 30 feet, and can exhale a breath weapon (6d8 force damage). When you make an attack, you can replace one with a draconic breath attack.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'force', tags: ['buff', 'damage'] },
  { id: 'ashardalons-stride', name: "Ashardalon's Stride", level: 3, school: 'Transmutation', sourceBook: 'FToD', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: "The billowing flames of a dragon blast from your feet, granting you explosive speed. For the duration, your speed increases by 20 feet and moving doesn't provoke opportunity attacks. When you move within 5 feet of a creature or an object that isn't being worn or carried, it takes 1d6 fire damage from your trail of heat. A creature or object can take this damage only once during a turn.", atHigherLevels: 'When cast with a 4th-level or higher slot, your speed increases by an additional 5 feet for each slot level above 3rd, and the spell deals an additional 1d6 fire damage for each slot level above 3rd.', classes: ['artificer', 'ranger', 'sorcerer', 'wizard'], damageType: 'fire', tags: ['buff', 'damage'] },
  { id: 'nathairs-mischief', name: "Nathair's Mischief", level: 2, school: 'Illusion', sourceBook: 'FToD', castingTime: '1 action', range: '60 feet', components: ['S', 'M'], materialComponent: 'a piece of crust from an apple pie', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: "You fill a 20-foot cube centered on a point within range with fey and draconic magic. Roll a d4 at the start of each of your turns until the spell ends. You can move the cube up to 10 feet before you roll. On a 1, each creature in the cube must succeed on a Wisdom saving throw or be charmed by you until the start of your next turn. On a 2, each creature in the cube must succeed on a Dexterity saving throw or be blinded until the start of your next turn. On a 3, each creature in the cube must succeed on a Wisdom saving throw or begin giggling until the start of your next turn — a giggling creature is incapacitated and uses all its movement to move in a random direction. On a 4, drops of molasses hover in the cube, making it difficult terrain until the start of your next turn.", classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'raulothims-psychic-lance', name: "Raulothim's Psychic Lance", level: 4, school: 'Enchantment', sourceBook: 'FToD', castingTime: '1 action', range: '120 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: "You unleash a shimmering lance of psychic power from your forehead at a creature that you can see within range. Alternatively, you can utter a creature's name. If the named target is within range, it becomes the spell's target even if you can't see it. If the named target isn't within range, the lance dissipates without effect. The target must make an Intelligence saving throw. On a failed save, the target takes 7d6 psychic damage and is incapacitated until the start of your next turn. On a successful save, it takes half as much damage and isn't incapacitated.", atHigherLevels: 'The damage increases by 1d6 for each slot level above 4th.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'control'] },
  { id: 'rimes-binding-ice', name: "Rime's Binding Ice", level: 2, school: 'Evocation', sourceBook: 'FToD', castingTime: '1 action', range: 'Self (30-foot cone)', components: ['S', 'M'], materialComponent: 'a vial of meltwater', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A burst of cold energy emanates from you in a 30-foot cone. Each creature in that area must make a Constitution saving throw. On a failed save, a creature takes 3d8 cold damage and is hindered by ice formations for 1 minute, or until it or another creature within reach uses an action to break away the ice. A hindered creature has its speed reduced to 0. On a successful save, a creature takes half as much damage and isn\'t hindered by ice.', atHigherLevels: 'The cold damage increases by 1d8 for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'control'] },
  { id: 'fizbans-platinum-shield', name: "Fizban's Platinum Shield", level: 6, school: 'Abjuration', sourceBook: 'FToD', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a platinum-plated dragon scale worth at least 500 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: "You create a field of silvery light that surrounds a creature of your choice within range (you can choose yourself). The field sheds dim light out to 5 feet. While surrounded by the field, a creature gains the following benefits: the creature has half cover; the creature has resistance to acid, cold, fire, lightning, and poison damage; and if the creature is subjected to an effect that allows it to make a Dexterity saving throw to take only half damage, the creature instead takes no damage if it succeeds on the saving throw, and only half damage if it fails (Evasion). As a bonus action on subsequent turns, you can move the field to another creature within 60 feet of the field.", classes: ['sorcerer', 'wizard'], tags: ['buff', 'protection'] },
  { id: 'etherealness', name: 'Etherealness', level: 7, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Up to 8 hours', concentration: false, ritual: false, description: 'You step into the border regions of the Ethereal Plane, in the area where it overlaps with your current plane. You remain in the Border Ethereal for the duration. During this time, you can move in any direction.', classes: ['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'teleportation'] },
  { id: 'fire-storm', name: 'Fire Storm', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A storm made up of sheets of roaring flame appears in a location you choose within range. The area consists of up to ten 10-foot cubes, which you can arrange as you wish. Each creature in the area must make a Dexterity save, taking 7d10 fire damage on a failed save, or half as much on a successful one.', classes: ['cleric', 'druid', 'sorcerer'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'forcecage', name: 'Forcecage', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '100 feet', components: ['V', 'S', 'M'], materialComponent: 'ruby dust worth 1,500 gp', duration: '1 hour', concentration: false, ritual: false, description: 'An immobile, invisible, cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose. A creature inside the cage when the spell is cast can\'t leave it by nonmagical means.', classes: ['bard', 'warlock', 'wizard'], tags: ['control'] },
  { id: 'mirage-arcane', name: 'Mirage Arcane', level: 7, school: 'Illusion', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Sight', components: ['V', 'S'], duration: '10 days', concentration: false, ritual: false, description: 'You make terrain in an area up to 1 square mile look, sound, smell, and even feel like some other sort of terrain. The terrain\'s general shape remains the same, but interior structures and features change. Creatures that enter the area perceive the illusion as real.', classes: ['bard', 'druid', 'wizard'], tags: ['illusion'] },
  { id: 'mordenkainens-magnificent-mansion', name: 'Mordenkainen\'s Magnificent Mansion', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a miniature portal carved from ivory, a small piece of polished marble, and a tiny silver spoon, each item worth at least 5 gp', duration: '24 hours', concentration: false, ritual: false, description: 'You conjure an extradimensional dwelling in range that lasts for the duration. The dwelling has an entrance and consists of furnished rooms. Servants attend to all who enter.', classes: ['bard', 'wizard'], tags: ['utility'] },
  { id: 'mordenkainens-sword', name: 'Mordenkainen\'s Sword', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a miniature platinum sword worth 250 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a sword-shaped plane of force that hovers within range. When you cast it and as a bonus action on subsequent turns, you can make a melee spell attack against a target of your choice within 5 feet of the sword. On a hit, the target takes 3d10 force damage.', classes: ['bard', 'wizard'], damageType: 'force', tags: ['damage'] },
  { id: 'plane-shift', name: 'Plane Shift', level: 7, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a forked, metal rod worth at least 250 gp, attuned to a particular plane of existence', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms.', classes: ['cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], tags: ['teleportation'] },
  { id: 'power-word-pain', name: 'Power Word Pain', level: 7, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Until dispelled', concentration: false, ritual: false, description: 'You speak a word of power that causes waves of intense pain to assail one creature you can see within range. If the target has 100 hit points or fewer, it is subject to crippling pain: speed is halved, disadvantage on attack rolls, ability checks, and saving throws, and must make Con save when casting spells.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['control', 'debuff'] },
  { id: 'prismatic-spray', name: 'Prismatic Spray', level: 7, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'Eight multicolored rays of light flash from your hand. Each ray is a different color. Each creature in a 60-foot cone must make a Dexterity save. Roll a d8 for each creature to determine which color ray affects it (each ray dealing a different damage type or effect).', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'project-image', name: 'Project Image', level: 7, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '500 miles', components: ['V', 'S', 'M'], materialComponent: 'a small replica of you made from materials worth at least 5 gp', duration: 'Concentration, up to 1 day', concentration: true, ritual: false, description: 'You create an illusory copy of yourself that lasts for the duration. The copy can appear at any location within range that you have seen before. The illusion looks and sounds like you but is intangible.', classes: ['bard', 'wizard'], tags: ['illusion'] },
  { id: 'regenerate', name: 'Regenerate', level: 7, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a prayer wheel and holy water', duration: '1 hour', concentration: false, ritual: false, description: 'You touch a creature and stimulate its natural healing ability. The target regains 4d8 + 15 hit points. For the duration of the spell, the target regains 1 hit point at the start of each of its turns. Severed body members are restored.', classes: ['bard', 'cleric', 'druid'], tags: ['healing'] },
  { id: 'resurrection', name: 'Resurrection', level: 7, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 1,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a dead creature that has been dead for no more than a century, that didn\'t die of old age, and that isn\'t undead. The target returns to life with all its hit points.', classes: ['bard', 'cleric'], tags: ['healing'] },
  { id: 'reverse-gravity', name: 'Reverse Gravity', level: 7, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '100 feet', components: ['V', 'S', 'M'], materialComponent: 'a lodestone and iron filings', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'This spell reverses gravity in a 50-foot-radius, 100-foot-high cylinder centered on a point within range. All creatures and objects that aren\'t somehow anchored fall upward and reach the top of the area when you cast the spell.', classes: ['druid', 'sorcerer', 'wizard'], savingThrow: 'dex', tags: ['control', 'aoe'] },
  { id: 'sequester', name: 'Sequester', level: 7, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a powder composed of diamond, emerald, ruby, and sapphire dust worth at least 5,000 gp', duration: 'Until dispelled', concentration: false, ritual: false, description: 'By means of this spell, a willing creature or an object can be hidden away, safe from detection for the duration. When you cast the spell and touch the target, it becomes invisible and put into a state of suspended animation if living.', classes: ['wizard'], tags: ['utility'] },
  { id: 'simulacrum', name: 'Simulacrum', level: 7, school: 'Illusion', sourceBook: 'PHB', castingTime: '12 hours', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'snow or ice in quantities sufficient to make a life-size copy of the duplicated creature; some hair, fingernail clippings, or other piece of that creature\'s body placed inside the snow or ice; and powdered ruby worth 1,500 gp, sprinkled over the duplicate and consumed by the spell', duration: 'Until dispelled', concentration: false, ritual: false, description: 'You shape an illusory duplicate of one beast or humanoid that is within range for the entire casting time. The duplicate is a creature, partially real and partially illusory, that obeys your spoken commands.', classes: ['wizard'], tags: ['summoning', 'illusion'] },
  { id: 'symbol', name: 'Symbol', level: 7, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'mercury, phosphorus, and powdered diamond and opal with a total value of at least 1,000 gp, which the spell consumes', duration: 'Until dispelled or triggered', concentration: false, ritual: false, description: 'When you cast this spell, you inscribe a harmful glyph either on a surface or within an object that can be closed to conceal the glyph. The glyph manifests one of several effects (death, discord, fear, hopelessness, insanity, pain, sleep, stunning) when triggered.', classes: ['bard', 'cleric', 'wizard'], tags: ['utility', 'control'] },
  { id: 'temple-of-the-gods', name: 'Temple of the Gods', level: 7, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 hour', range: 'Sight', components: ['V', 'S', 'M'], materialComponent: 'a gold brick worth 5 gp', duration: '24 hours', concentration: false, ritual: false, description: 'You cause a temple to shimmer into existence on ground you can see within range. The temple is dedicated to a god, pantheon, or philosophy that you worship. The temple lasts for the duration, and various magical effects guard the temple.', classes: ['cleric'], tags: ['utility', 'defense'] },
  { id: 'whirlwind', name: 'Whirlwind', level: 7, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '300 feet', components: ['V', 'S', 'M'], materialComponent: 'a piece of straw', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A whirlwind howls down to a point on the ground that you can see within range. The whirlwind is a 10-foot-radius, 30-foot-high cylinder centered on that point. Each creature in the area must make a Dexterity save, taking 10d6 bludgeoning damage on failed save, and is flung.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'aoe', 'control'] },

  // ── LEVEL 8 SPELLS ────────────────────────────────────────────────────
  { id: 'abi-dalzims-horrid-wilting', name: 'Abi-Dalzim\'s Horrid Wilting', level: 8, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a bit of sponge', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You draw the moisture from every creature in a 30-foot cube. Each creature in that area must make a Constitution saving throw. Constructs and undead aren\'t affected, and plants and water elementals make this saving throw with disadvantage. A creature takes 12d8 necrotic damage on a failed save, or half on success.', classes: ['sorcerer', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'animal-shapes', name: 'Animal Shapes', level: 8, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Concentration, up to 24 hours', concentration: true, ritual: false, description: 'Your magic turns others into beasts. Choose any number of willing creatures that you can see within range. You transform each target into the form of a Large or smaller beast with a CR of 4 or lower.', classes: ['druid'], tags: ['utility', 'buff'] },
  { id: 'antimagic-field', name: 'Antimagic Field', level: 8, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (10-foot radius)', components: ['V', 'S', 'M'], materialComponent: 'a pinch of powdered iron or iron filings', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'A 10-foot-radius invisible sphere of antimagic surrounds you. This area is divorced from the magical energy that suffuses the multiverse. Within the sphere, spells can\'t be cast, summoned creatures disappear, and magic items become mundane.', classes: ['cleric', 'wizard'], tags: ['defense'] },
  { id: 'antipathy-sympathy', name: 'Antipathy/Sympathy', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 hour', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'either a lump of alum soaked in vinegar for the antipathy effect or a drop of honey for the sympathy effect', duration: '10 days', concentration: false, ritual: false, description: 'This spell attracts or repels creatures of your choice. You target something within range, either a Huge or smaller object or creature or an area that is no larger than a 200-foot cube. Choose antipathy (repels) or sympathy (attracts).', classes: ['bard', 'druid', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'clone', name: 'Clone', level: 8, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 1,000 gp and at least 1 cubic inch of flesh of the creature that is to be cloned, which the spell consumes, and a vessel worth at least 2,000 gp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'This spell grows an inert duplicate of a living creature as a safeguard against death. The clone forms inside a sealed vessel and grows to full size and maturity after 120 days. When the original creature dies, its soul transfers to the clone.', classes: ['wizard'], tags: ['utility'] },
  { id: 'control-weather', name: 'Control Weather', level: 8, school: 'Transmutation', sourceBook: 'PHB', castingTime: '10 minutes', range: 'Self (5-mile radius)', components: ['V', 'S', 'M'], materialComponent: 'burning incense and bits of earth and wood mixed in water', duration: 'Concentration, up to 8 hours', concentration: true, ritual: false, description: 'You take control of the weather within 5 miles of you for the duration. You must be outdoors. When you cast the spell, you change the current weather conditions. You can change precipitation, temperature, and wind.', classes: ['cleric', 'druid', 'wizard'], tags: ['control', 'utility'] },
  { id: 'demiplane', name: 'Demiplane', level: 8, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['S'], duration: '1 hour', concentration: false, ritual: false, description: 'You create a shadowy door on a flat solid surface that you can see within range. The door is large enough to allow Medium creatures to pass through unhindered. When opened, the door leads to a demiplane that appears to be an empty room 30 feet in each dimension.', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['utility'] },
  { id: 'dominate-monster', name: 'Dominate Monster', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You attempt to beguile a creature that you can see within range. It must succeed on a Wisdom saving throw or be charmed by you for the duration. If you or creatures friendly to you are fighting it, it has advantage on the saving throw.\n\nDuration is 8 hours when cast at 9th level.', atHigherLevels: 'Duration is 8 hours at 9th level.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'enchantment'] },
  { id: 'earthquake', name: 'Earthquake', level: 8, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '500 feet', components: ['V', 'S', 'M'], materialComponent: 'a pinch of dirt, a piece of rock, and a lump of clay', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a seismic disturbance at a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point. Each creature on the ground in that area must make a Dexterity saving throw. On a failed save, the creature is knocked prone.\n\nThe spell also creates the following effects:\n\nDifficult Terrain. The ground in the area becomes difficult terrain. Each creature on the ground in the area must also make a Dexterity saving throw. A creature falls prone on a failed save.\n\nFissures. Fissures open throughout the spell\'s area at the start of your next turn after you cast the spell. A total of 1d6 such fissures open in locations chosen by the DM. Each is 1d10 × 10 feet deep, 10 feet wide, and extends from one edge of the spell\'s area to the opposite side. A creature standing on a spot where a fissure opens must succeed on a Dexterity saving throw or fall in. A creature that successfully saves moves with the fissure\'s edge as it opens.\n\nStructures. The tremor deals 50 bludgeoning damage to any structure in contact with the ground in the area when you cast the spell and at the start of each of your turns until the spell ends. If a structure drops to 0 hit points, it collapses and potentially damages nearby creatures.\n\nConcentration. Each creature that is concentrating on a spell while in the spell\'s area must make a Constitution saving throw. On a failed save, that creature\'s concentration is broken.', classes: ['cleric', 'druid', 'sorcerer'], savingThrow: 'dex', tags: ['damage', 'aoe', 'control'] },
  { id: 'feeblemind', name: 'Feeblemind', level: 8, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a handful of clay, crystal, glass, or mineral spheres', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 4d6 psychic damage and must make an Intelligence saving throw.\n\nOn a failed save, the creature\'s Intelligence and Charisma scores become 1. The creature can\'t cast spells, activate magic items, understand language, or communicate in any intelligible way. The creature can, however, identify its friends, follow them, and even protect them.\n\nAt the end of every 30 days, the creature can repeat its saving throw against this spell. On a successful save, the spell ends.\n\nThe spell can also be ended by greater restoration, heal, or wish.', classes: ['bard', 'druid', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'debuff'] },
  { id: 'glibness', name: 'Glibness', level: 8, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: '1 hour', concentration: false, ritual: false, description: 'Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.', classes: ['bard', 'warlock'], tags: ['buff'] },
  { id: 'holy-aura', name: 'Holy Aura', level: 8, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a tiny reliquary worth at least 1,000 gp containing a sacred relic, such as a snippet of cloth from a saint\'s robe or a piece of parchment from a religious text', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Divine light washes out from you and coalesces in a soft radiance in a 30-foot radius around you. Creatures of your choice in that radius when you cast this spell shed dim light in a 5-foot radius and have advantage on all saving throws, and other creatures have disadvantage on attack rolls against them until the spell ends. In addition, when a fiend or an undead hits an affected creature with a melee attack, the aura flashes with brilliant light. The attacker must succeed on a Constitution saving throw or be blinded until the spell ends.', classes: ['cleric'], savingThrow: 'con', tags: ['buff', 'defense'] },
  { id: 'illusory-dragon', name: 'Illusory Dragon', level: 8, school: 'Illusion', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'By gathering threads of shadow material from the Shadowfell, you create a Huge shadowy dragon in an unoccupied space you can see within range. The illusion lasts for the spell\'s duration. The dragon takes up a 15-foot cube. As a bonus action, you can move it. It can also unleash a 60-foot cone breath weapon.', classes: ['wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'illusion'] },
  { id: 'incendiary-cloud', name: 'Incendiary Cloud', level: 8, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A swirling cloud of smoke shot through with white-hot embers appears in a 20-foot-radius sphere centered on a point within range. When the cloud appears, each creature in it must make a Dexterity save, taking 10d8 fire damage on a failed save.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'maddening-darkness', name: 'Maddening Darkness', level: 8, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '150 feet', components: ['V', 'M'], materialComponent: 'a drop of pitch mixed with a drop of mercury', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Magical darkness spreads from a point you choose within range to fill a 60-foot-radius sphere until the spell ends. Whispers and unholy laughter can be heard in the darkness. Whenever a creature starts its turn in the sphere, it must make a Wisdom save, taking 8d8 psychic damage on failed save.', classes: ['warlock', 'wizard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'aoe', 'control'] },
  { id: 'maze', name: 'Maze', level: 8, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze. The target can use its action to attempt to escape, making a DC 20 Intelligence check.', classes: ['wizard'], tags: ['control', 'teleportation'] },
  { id: 'mighty-fortress', name: 'Mighty Fortress', level: 8, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 minute', range: '1 mile', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 500 gp, which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: false, description: 'A fortress of stone rises up from the ground at a point you choose within range. Your conception of the fortress determines its appearance and exact dimensions: up to 120 feet on a side. The fortress remains until cast as Dispel Magic.', classes: ['wizard'], tags: ['utility'] },
  { id: 'mind-blank', name: 'Mind Blank', level: 8, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: '24 hours', concentration: false, ritual: false, description: 'Until the spell ends, one willing creature you touch is immune to psychic damage, any effect that would sense its emotions or read its thoughts, divination spells, and the charmed condition.', classes: ['bard', 'wizard'], tags: ['buff', 'defense'] },
  { id: 'sunburst', name: 'Sunburst', level: 8, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'fire and a piece of sunstone', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Brilliant sunlight flashes in a 60-foot radius centered on a point you choose within range. Each creature in that light must make a Constitution saving throw. On a failed save, a creature takes 12d6 radiant damage and is blinded for 1 minute. On a successful save, it takes half as much damage and isn\'t blinded by this spell. Undead and oozes have disadvantage on this saving throw.\n\nA creature blinded by this spell makes another Constitution saving throw at the end of each of its turns. On a successful save, it is no longer blinded.\n\nThis spell dispels any darkness in its area that was created by a spell.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'telepathy', name: 'Telepathy', level: 8, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Unlimited', components: ['V', 'S', 'M'], materialComponent: 'a pair of linked silver rings', duration: '24 hours', concentration: false, ritual: false, description: 'You create a telepathic link between yourself and a willing creature with which you are familiar. The creature can be anywhere on the same plane of existence. The spell ends if you or the target are no longer on the same plane.', classes: ['wizard'], tags: ['utility'] },
  { id: 'tsunami', name: 'Tsunami', level: 8, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 minute', range: 'Sight', components: ['V', 'S'], duration: 'Concentration, up to 6 rounds', concentration: true, ritual: false, description: 'A wall of water springs into existence at a point you choose within range. You can make the wall up to 300 feet long, 300 feet high, and 50 feet thick. The wall lasts for the duration. When the wall appears, each creature within its area must make a Strength saving throw, taking 6d10 bludgeoning damage on a failed save.', classes: ['druid'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'aoe'] },

  // ── LEVEL 9 SPELLS ────────────────────────────────────────────────────
  { id: 'astral-projection', name: 'Astral Projection', level: 9, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'for each creature you affect with this spell, you must provide one jacinth worth at least 1,000 gp and one ornately carved bar of silver worth at least 100 gp, all of which the spell consumes', duration: 'Special', concentration: false, ritual: false, description: 'You and up to eight willing creatures within range project your astral bodies into the Astral Plane. The material body you leave behind is unconscious and in a state of suspended animation. The duration of the spell is special; it ends when you return to your body.', classes: ['cleric', 'warlock', 'wizard'], tags: ['utility', 'teleportation'] },
  { id: 'foresight', name: 'Foresight', level: 9, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a hummingbird feather', duration: '8 hours', concentration: false, ritual: false, description: 'You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can\'t be surprised and has advantage on attack rolls, ability checks, and saving throws. Other creatures have disadvantage on attack rolls against the target.', classes: ['bard', 'druid', 'warlock', 'wizard'], tags: ['buff'] },
  { id: 'gate', name: 'Gate', level: 9, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a diamond worth at least 5,000 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening 5 to 20 feet in diameter. You can also name a particular creature to be drawn through.', classes: ['cleric', 'sorcerer', 'wizard'], tags: ['teleportation', 'summoning'] },
  { id: 'imprisonment', name: 'Imprisonment', level: 9, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a vellum depiction or carved statuette of the target, plus a special component varies based on the version of the spell, all of which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: false, description: 'You create a magical restraint to hold a creature that you can see within range. The target must succeed on a Wisdom save or be bound by the spell. Choose one of the following forms of imprisonment: Burial, Chaining, Hedged Prison, Minimus Containment, or Slumber.', classes: ['warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'invulnerability', name: 'Invulnerability', level: 9, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a small adamantine sphere worth 500 gp', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You are immune to all damage until the spell ends.', classes: ['wizard'], tags: ['defense'] },
  { id: 'mass-heal', name: 'Mass Heal', level: 9, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A flood of healing energy flows from you into injured creatures around you. You restore up to 700 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell are also cured of all diseases and any conditions like blindness and deafness.', classes: ['cleric'], tags: ['healing'] },
  { id: 'mass-polymorph', name: 'Mass Polymorph', level: 9, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a caterpillar cocoon', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You transform up to ten creatures of your choice that you can see within range. An unwilling creature must make a Wisdom save. Each target assumes a beast form of your choice with a CR of 4 or lower.', classes: ['bard', 'sorcerer', 'wizard'], savingThrow: 'wis', tags: ['control', 'utility'] },
  { id: 'power-word-heal', name: 'Power Word Heal', level: 9, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'A wave of healing energy washes over the creature you touch. The target regains all its hit points. If the creature is charmed, frightened, paralyzed, or stunned, the condition ends. If it is prone, it can use its reaction to stand up.', classes: ['bard'], tags: ['healing'] },
  { id: 'prismatic-wall', name: 'Prismatic Wall', level: 9, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: false, description: 'A shimmering, multicolored plane of light forms a vertical opaque wall within range. The wall has seven layers, each with a different color. When a creature tries to cross the wall, each layer affects it in different ways.', classes: ['bard', 'wizard'], damageType: 'fire', tags: ['damage', 'defense'] },
  { id: 'psychic-scream', name: 'Psychic Scream', level: 9, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You unleash the power of your mind to blast the intellect of up to ten creatures of your choice that you can see within range. Each target must make an Intelligence save, taking 14d6 psychic damage and being stunned on failed save, or half damage on success.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'control'] },
  { id: 'shapechange', name: 'Shapechange', level: 9, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a jade circlet worth at least 1,500 gp, which you must place on your head before you cast the spell', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You assume the form of a different creature for the duration. The new form can be of any creature with a challenge rating equal to your level or lower. You can\'t take the form of a construct or undead, and you must have seen the kind of creature before.', classes: ['druid', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'storm-of-vengeance', name: 'Storm of Vengeance', level: 9, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Sight', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A churning storm cloud forms, centered on a point you can see and spreading to a radius of 360 feet. Lightning, thunder, acid rain, and hailstones rain down. Each round has a different effect, escalating in destructive power.', classes: ['druid'], damageType: 'thunder', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'time-stop', name: 'Time Stop', level: 9, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal. The spell ends if one of the actions you take during this period affects a creature other than you or an object being worn or carried by someone other than you.', classes: ['sorcerer', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'true-polymorph', name: 'True Polymorph', level: 9, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of mercury, a dollop of gum arabic, and a wisp of smoke', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Choose one creature or nonmagical object that you can see within range. You transform the creature into a different creature, the creature into an object, or the object into a creature. The transformation lasts for the duration, or until the target drops to 0 hit points or dies. If you concentrate for the full hour, the transformation becomes permanent.', classes: ['bard', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'utility'] },
  { id: 'true-resurrection', name: 'True Resurrection', level: 9, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a sprinkle of holy water and diamonds worth at least 25,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a creature that has been dead for no longer than 200 years and that died for any reason except old age. If the creature\'s soul is free and willing, the creature is restored to life with all its hit points. This spell closes all wounds, neutralizes any poison, cures all diseases, and lifts any curses.', classes: ['cleric', 'druid'], tags: ['healing'] },
  { id: 'weird', name: 'Weird', level: 9, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Drawing on the deepest fears of a group of creatures, you create illusory creatures in their minds. Each creature in a 30-foot-radius sphere centered on a point within range must make a Wisdom save. On a failed save, a target becomes frightened for the duration. At the end of each of its turns, it must succeed on a Wisdom save or take 4d10 psychic damage.', classes: ['wizard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'control', 'aoe'] },

  // ── EGtW: Dunamancy Spells ──────────────────────────────────────────────
  // Cantrip
  { id: 'sapping-sting', name: 'Sapping Sting', level: 0, school: 'Necromancy', sourceBook: 'EGtW', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You drain the life force of a creature you can see within range. The target must succeed on a Constitution saving throw or take 1d4 necrotic damage and fall prone.\n\nThis spell\'s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', classes: ['wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage', 'control'] },

  // Level 1
  { id: 'magnify-gravity', name: 'Magnify Gravity', level: 1, school: 'Transmutation', sourceBook: 'EGtW', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'The gravity in a 10-foot-radius sphere centered on a point you can see within range increases dramatically for a moment. Each creature in the sphere must make a Constitution saving throw. On a failed save, a creature takes 2d8 force damage, and its speed is halved until the end of its next turn. On a successful save, a creature takes half as much damage and suffers no reduction to its speed.\n\nAll nonmagical objects in the sphere that are not being worn or carried take 2d8 force damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d8 for each slot level above 1st.', classes: ['sorcerer', 'wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'control', 'aoe'] },

  // Level 2
  { id: 'fortunes-favor', name: "Fortune's Favor", level: 2, school: 'Divination', sourceBook: 'EGtW', castingTime: '1 minute', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a white pearl worth at least 100 gp, which the spell consumes', duration: '1 hour', concentration: false, ritual: false, description: 'You impart latent luck to yourself or one willing creature you can see within range. When the chosen creature makes an attack roll, an ability check, or a saving throw before the spell ends, it can roll an additional d20 and choose which of the d20s to use. The spell then ends.\n\nA creature can be affected by only one Fortune\'s Favor spell at a time; if a second casting is applied, the first one ends.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], tags: ['buff', 'utility'] },
  { id: 'immovable-object', name: 'Immovable Object', level: 2, school: 'Transmutation', sourceBook: 'EGtW', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'gold dust worth at least 25 gp, which the spell consumes', duration: '1 hour', concentration: false, ritual: false, description: 'You touch an object that weighs no more than 10 pounds and cause it to become magically fixed in place. You and the creatures you designate when you cast this spell can move the object normally. You can also set a password that, when spoken within 5 feet of the object, suppresses this spell for 1 minute.\n\nIf the object is fixed in the air, it can hold up to 4,000 pounds of weight. More weight causes the object to fall. Otherwise, a creature can use an action to make a Strength check against your spell save DC. On a success, the creature can move the object up to 10 feet.', atHigherLevels: 'If you cast this spell using a spell slot of 4th or 5th level, the DC to move the object increases by 5. If you use a 6th or 7th level slot, the weight the spell can support increases to 8,000 lbs. If you use a 8th or 9th level slot, the weight increases to 20,000 lbs and the DC increases by 10.', classes: ['wizard'], tags: ['utility', 'control'] },
  { id: 'wristpocket', name: 'Wristpocket', level: 2, school: 'Conjuration', sourceBook: 'EGtW', castingTime: '1 action', range: 'Self', components: ['S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: true, description: 'You flick your wrist, causing one object in your hand to vanish. The object, which only you can be holding and can weigh no more than 5 pounds, is transported to an extradimensional space, where it remains for the duration.\n\nUntil the spell ends, you can use your bonus action to summon the object to your free hand, and you can use your bonus action to return the object to the extradimensional space. An object still in the pocket when the spell ends appears in your space, at your feet.', classes: ['wizard'], tags: ['utility'] },

  // Level 3
  { id: 'pulse-wave', name: 'Pulse Wave', level: 3, school: 'Evocation', sourceBook: 'EGtW', castingTime: '1 action', range: 'Self (30-foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create intense pressure, unleash it in a 30-foot cone, and decide whether the force of the wave pulls or pushes creatures and objects. Each creature in that cone must make a Constitution saving throw. On a failed save, the creature takes 6d6 force damage and is pulled toward you or pushed away from you (your choice) by 15 feet. On a successful save, the creature takes half as much damage and isn\'t moved.\n\nAny object that isn\'t being worn or carried in the cone is also pushed or pulled 15 feet.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 2d6 and the distance pulled or pushed increases by 5 feet for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },

  // Level 4
  { id: 'gravity-sinkhole', name: 'Gravity Sinkhole', level: 4, school: 'Evocation', sourceBook: 'EGtW', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'a black marble', duration: 'Instantaneous', concentration: false, ritual: false, description: 'A 20-foot-radius sphere of crushing force forms at a point you can see within range and pulls those nearby toward it. Each creature in the sphere must make a Constitution saving throw. On a failed save, the creature takes 5d10 force damage and is pulled in a straight line toward the center of the sphere, ending in an unoccupied space as close to the center as possible (even if that space is in the air). On a successful save, the creature takes half as much damage and isn\'t pulled.', atHigherLevels: 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d10 for each slot level above 4th.', classes: ['sorcerer', 'wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },

  // Level 5
  { id: 'temporal-shunt', name: 'Temporal Shunt', level: 5, school: 'Transmutation', sourceBook: 'EGtW', castingTime: '1 reaction, which you take when a creature makes an attack roll or casts a spell', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You target the triggering creature, which must make a Wisdom saving throw. On a failed save, the creature is briefly shunted to a different point in time, causing the attack or spell to fail and be wasted. At the start of its next turn, the shunted creature reappears in the space it left or in the nearest unoccupied space if that space is occupied.\n\nA shunted creature is unaware of its brief departure from the normal timeline.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, you can target one additional creature for each slot level above 5th. All targets must be within 30 feet of each other.', classes: ['sorcerer', 'wizard'], savingThrow: 'wis', tags: ['reaction', 'control', 'counter'] },

  // Level 6
  { id: 'gravity-fissure', name: 'Gravity Fissure', level: 6, school: 'Evocation', sourceBook: 'EGtW', castingTime: '1 action', range: 'Self (100-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a fistful of iron filings', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You manifest a ravine of gravitational energy in a line originating from you that is 100 feet long and 5 feet wide. Each creature in that line must make a Constitution saving throw. On a failed save, a creature takes 8d8 force damage and is pulled toward you to the nearest unoccupied space within the line. On a successful save, a creature takes half as much damage and isn\'t moved.\n\nEach creature within 10 feet of the line but not in it must succeed on a Constitution saving throw or take 8d8 force damage and be pulled toward the line.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d8 for each slot level above 6th.', classes: ['sorcerer', 'wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'tether-essence', name: 'Tether Essence', level: 7, school: 'Transmutation', sourceBook: 'EGtW', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a spool of platinum thread worth at least 250 gp, which the spell consumes', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Two creatures of your choice within range must each make a Constitution saving throw; a willing creature can choose to fail. If both saves fail, each creature is bound to the other for the duration. While bound in this way, if either creature takes damage, it and the other creature each take that damage. Likewise, if either creature is healed, both creatures are healed for the same amount. If either creature bound by the spell is reduced to 0 hit points, the spell ends. The spell ends early if the two creatures ever end their turns more than 30 feet apart.', classes: ['wizard'], savingThrow: 'con', tags: ['control', 'utility'] },

  // Level 8
  { id: 'dark-star', name: 'Dark Star', level: 8, school: 'Evocation', sourceBook: 'EGtW', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a shard of onyx and a drop of the caster\'s blood, both of which the spell consumes', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'This spell creates a sphere centered on a point you choose within range. The sphere can have a radius of up to 40 feet. The area within this sphere is filled with magical darkness and crushing gravitational force.\n\nFor the duration, the spell\'s area is difficult terrain. A creature in the sphere when you cast the spell must make a Constitution saving throw. On a failed save, the creature takes 8d10 force damage, and every spell or magical effect of 8th level or lower ends in the sphere. A creature that starts its turn in the sphere must also make this saving throw.\n\nThe gravitational force makes the area within the sphere magically dark (as per the Darkness spell), and no light can illuminate the area.', classes: ['wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'reality-break', name: 'Reality Break', level: 8, school: 'Conjuration', sourceBook: 'EGtW', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a crystal prism', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You shatter the barriers between realities for a creature you can see within range. The target must make a Wisdom saving throw. On a failed save, the creature is lost in a fragmenting multiverse of alternate realities for the duration.\n\nWhile affected, the target can\'t take reactions, and at the start of each of its turns, it must roll a d10 and consult the Reality Break table:\n1–2: Vision of the Far Realm. The target takes 6d12 psychic damage, and it is stunned until the end of the turn.\n3–5: Rending Rift. The target must make a Dexterity saving throw, taking 8d12 force damage on a failed save, or half damage on a success.\n6–8: Wormhole. The target is teleported, along with everything it is wearing and carrying, up to 30 feet in a random direction. The target then takes 10d12 force damage.\n9–10: Chill of the Dark Void. The target takes 14d12 cold damage, and it is blinded until the end of the turn.', classes: ['sorcerer', 'wizard'], savingThrow: 'wis', tags: ['damage', 'control'] },

  // Level 9
  { id: 'ravenous-void', name: 'Ravenous Void', level: 9, school: 'Evocation', sourceBook: 'EGtW', castingTime: '1 action', range: '1,000 feet', components: ['V', 'S', 'M'], materialComponent: 'a small, nine-pointed star made of iron', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of destructive gravitational force centered on a point you can see within range. For the duration, the sphere and all space within 100 feet of it are difficult terrain, and nonmagical objects fully inside the sphere are destroyed if they aren\'t being worn or carried.\n\nWhen a creature enters the sphere for the first time on a turn or starts its turn there, that creature must make a Constitution saving throw. On a failed save, the creature takes 5d10 force damage and is restrained until the start of its next turn. On a successful save, the creature takes half as much damage and isn\'t restrained.\n\nCreatures and objects restrained by this spell are pulled 50 feet toward the center of the sphere at the start of each of their turns.', classes: ['wizard'], damageType: 'force', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'time-ravage', name: 'Time Ravage', level: 9, school: 'Necromancy', sourceBook: 'EGtW', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'an hourglass filled with diamond dust worth at least 5,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You target a creature you can see within range, putting its physical form through the devastation of rapid aging. The target must make a Constitution saving throw, taking 10d12 necrotic damage on a failed save, or half as much damage on a successful one. If the save fails, the target also suffers the frailties of old age: it has disadvantage on attack rolls, ability checks, and saving throws that use Strength, Dexterity, or Constitution; its speed is halved; and it can\'t take reactions.\n\nThese effects last until the creature is targeted by the greater restoration spell or similar magic.', classes: ['wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage', 'control'] },

  // === MISSING PHB SPELLS (added in audit) ===

  // Cantrip
  { id: 'thorn-whip', name: 'Thorn Whip', level: 0, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'the stem of a plant with thorns', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a long, vine-like whip covered in thorns that lashes out at your command toward a creature in range. Make a melee spell attack against the target. If the attack hits, the creature takes 1d6 piercing damage, and if the creature is Large or smaller, you pull the creature up to 10 feet closer to you.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['druid'], damageType: 'piercing', tags: ['damage', 'control'] },

  // 1st Level
  { id: 'compelled-duel', name: 'Compelled Duel', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 bonus action', range: '30 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You attempt to compel a creature into a duel. One creature that you can see within range must make a Wisdom saving throw. On a failed save, the creature is drawn to you, compelled by your divine demand. For the duration, it has disadvantage on attack rolls against creatures other than you, and must make a Wisdom saving throw each time it attempts to move to a space that is more than 30 feet away from you; if it succeeds on this saving throw, this spell doesn\'t restrict the target\'s movement for that turn.\n\nThe spell ends if you attack any other creature, if you cast a spell that targets a hostile creature other than the target, if a creature friendly to you damages the target or casts a harmful spell on it, or if you end your turn more than 30 feet away from the target.', classes: ['paladin'], savingThrow: 'wis', tags: ['control'] },
  { id: 'create-or-destroy-water', name: 'Create or Destroy Water', level: 1, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of water if creating water, or a few grains of sand if destroying it', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You either create or destroy water.\n\nCreate Water. You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot cube within range, extinguishing exposed flames in the area.\n\nDestroy Water. You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot cube within range.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, you create or destroy 10 additional gallons of water, or the size of the cube increases by 5 feet, for each slot level above 1st.', classes: ['cleric', 'druid'], tags: ['utility'] },
  { id: 'detect-evil-and-good', name: 'Detect Evil and Good', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'For the duration, you know if there is an aberration, celestial, elemental, fey, fiend, or undead within 30 feet of you, as well as where the creature is located. Similarly, you know if there is a place or object within 30 feet of you that has been magically consecrated or desecrated.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', classes: ['cleric', 'paladin'], tags: ['detection'] },
  { id: 'detect-poison-and-disease', name: 'Detect Poison and Disease', level: 1, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a yew leaf', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: true, description: 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you. You also identify the kind of poison, poisonous creature, or disease in each case.\n\nThe spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', classes: ['cleric', 'druid', 'paladin', 'ranger'], tags: ['detection'] },
  { id: 'dissonant-whispers', name: 'Dissonant Whispers', level: 1, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You whisper a discordant melody that only one creature of your choice within range can hear, wracking it with terrible pain. The target must make a Wisdom saving throw. On a failed save, it takes 3d6 psychic damage and must immediately use its reaction, if available, to move as far as its speed allows away from you. The creature doesn\'t move into obviously dangerous ground, such as a fire or a pit. On a successful save, the target takes half as much damage and doesn\'t have to move away.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', classes: ['bard'], damageType: 'psychic', savingThrow: 'wis', tags: ['damage', 'control'] },

  // 2nd Level
  { id: 'alter-self', name: 'Alter Self', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You assume a different form. When you cast the spell, choose one of the following options, the effects of which last for the duration of the spell. While the spell lasts, you can end one option as an action to gain the benefits of a different one.\n\nAquatic Adaptation. You adapt your body to an aquatic environment, sprouting gills and growing webbing between your fingers. You can breathe underwater and gain a swimming speed equal to your walking speed.\n\nChange Appearance. You transform your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and distinguishing characteristics, if any. You can make yourself appear as a member of another race, though none of your statistics change.\n\nNatural Weapons. You grow claws, fangs, spines, horns, or a different natural weapon of your choice. Your unarmed strikes deal 1d6 bludgeoning, piercing, or slashing damage, as appropriate to the natural weapon you chose, and you are proficient with your unarmed strikes.', classes: ['artificer', 'sorcerer', 'wizard'], tags: ['utility', 'shapeshift'] },
  { id: 'animal-messenger', name: 'Animal Messenger', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a morsel of food', duration: '24 hours', concentration: false, ritual: true, description: 'By means of this spell, you use an animal to deliver a message. Choose a Tiny beast you can see within range, such as a squirrel, a blue jay, or a bat. You specify a location, which you must have visited, and a recipient who matches a general description, such as "a man or woman dressed in the uniform of the town guard" or "a red-haired dwarf wearing a pointed hat." You also speak a message of up to twenty-five words. The target beast travels for the duration of the spell toward the specified location, covering about 50 miles per 24 hours for a flying messenger, or 25 miles for other animals.\n\nWhen the messenger arrives, it delivers your message to the creature that you described, replicating the sound of your voice. The messenger speaks only to a creature matching the description you gave. If the messenger doesn\'t reach its destination before the spell ends, the message is lost, and the beast makes its way back to where you cast this spell.', atHigherLevels: 'If you cast this spell using a spell slot of 3rd level or higher, the duration of the spell increases by 48 hours for each slot level above 2nd.', classes: ['bard', 'druid', 'ranger'], tags: ['utility', 'communication'] },
  { id: 'arcane-lock', name: 'Arcane Lock', level: 2, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'gold dust worth at least 25 gp, which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: false, description: 'You touch a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and the creatures you designate when you cast this spell can open the object normally. You can also set a password that, when spoken within 5 feet of the object, suppresses this spell for 1 minute. Otherwise, it is impassable until it is broken or the spell is dispelled or suppressed. Casting knock on the object suppresses arcane lock for 10 minutes.\n\nWhile affected by this spell, the object is more difficult to break or force open; the DC to break it or pick any locks on it increases by 10.', classes: ['artificer', 'wizard'], tags: ['utility', 'protection'] },
  { id: 'augury', name: 'Augury', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 minute', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'specially marked sticks, bones, or similar tokens worth at least 25 gp', duration: 'Instantaneous', concentration: false, ritual: true, description: 'By casting gem-inlaid sticks, rolling dragon bones, laying out ornate cards, or employing some other divining tool, you receive an omen from an otherworldly entity about the results of a specific course of action that you plan to take within the next 30 minutes. The DM chooses from the following possible omens:\n\nWeal, for good results\nWoe, for bad results\nWeal and woe, for both good and bad results\nNothing, for results that aren\'t especially good or bad\n\nThe spell doesn\'t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.\n\nIf you cast the spell two or more times before completing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The DM makes this roll in secret.', classes: ['cleric'], tags: ['divination', 'ritual'] },
  { id: 'barkskin', name: 'Barkskin', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a handful of oak bark', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You touch a willing creature. Until the spell ends, the target\'s skin has a rough, bark-like appearance, and the target\'s AC can\'t be less than 16, regardless of what kind of armor it is wearing.', classes: ['druid', 'ranger'], tags: ['buff', 'protection'] },
  { id: 'beast-sense', name: 'Beast Sense', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['S'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: true, description: 'You touch a willing beast. For the duration of the spell, you can use your action to see through the beast\'s eyes and hear what it hears, and continue to do so until you use your action to return to your normal senses. While perceiving through the beast\'s senses, you gain the benefits of any special senses possessed by that creature, though you are blinded and deafened to your own surroundings.', classes: ['druid', 'ranger'], tags: ['divination', 'utility'] },
  { id: 'crown-of-madness', name: 'Crown of Madness', level: 2, school: 'Enchantment', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'One humanoid of your choice that you can see within range must succeed on a Wisdom saving throw or become charmed by you for the duration. While the target is charmed in this way, a twisted crown of jagged iron appears on its head, and a madness glows in its eyes.\n\nThe charmed target must use its action before moving on each of its turns to make a melee attack against a creature other than itself that you mentally choose. The target can act normally on its turn if you choose no creature or if none are within its reach.\n\nOn your subsequent turns, you must use your action to maintain control over the target, or the spell ends. Also, the target can make a Wisdom saving throw at the end of each of its turns. On a success, the spell ends.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control'] },
  { id: 'find-traps', name: 'Find Traps', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator. Thus the spell would sense an area affected by the alarm spell, a glyph of warding, or a mechanical pit trap, but it would not reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole.\n\nThis spell merely reveals that a trap is present. You don\'t learn the location of each trap, but you do learn the general nature of the danger posed by a trap you sense.', classes: ['cleric', 'druid', 'ranger'], tags: ['detection', 'utility'] },
  { id: 'gentle-repose', name: 'Gentle Repose', level: 2, school: 'Necromancy', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a pinch of salt and one copper piece placed on each of the corpse\'s eyes, which must remain there for the duration', duration: '10 days', concentration: false, ritual: true, description: 'You touch a corpse or other remains. For the duration, the target is protected from decay and can\'t become undead.\n\nThe spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don\'t count against the time limit of spells such as raise dead.', classes: ['cleric', 'wizard'], tags: ['utility', 'ritual'] },
  { id: 'locate-animals-or-plants', name: 'Locate Animals or Plants', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur from a bloodhound', duration: 'Instantaneous', concentration: false, ritual: true, description: 'Describe or name a specific kind of beast or plant. Concentrating on the voice of nature in your surroundings, you learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.', classes: ['bard', 'cleric', 'druid', 'ranger'], tags: ['detection', 'tracking'] },
  { id: 'locate-object', name: 'Locate Object', level: 2, school: 'Divination', sourceBook: 'PHB', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a forked twig', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Describe or name an object that is familiar to you. You sense the direction to the object\'s location, as long as that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement.\n\nThe spell can locate a specific object known to you, as long as you have seen it up close—within 30 feet—at least once. Alternatively, the spell can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon.\n\nThis spell can\'t locate an object if any thickness of lead, even a thin sheet, separates you from the object.', classes: ['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard'], tags: ['detection', 'tracking'] },
  { id: 'magic-mouth', name: 'Magic Mouth', level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 minute', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a small bit of honeycomb and jade dust worth at least 10 gp, which the spell consumes', duration: 'Until dispelled', concentration: false, ritual: true, description: 'You implant a message within an object in range, a message that is uttered when a trigger condition is met. Choose an object that you can see and that isn\'t being worn or carried by another creature. Then speak the message, which must be 25 words or less, though it can be delivered over as long as 10 minutes. Finally, determine the circumstance that will trigger the spell to deliver your message.\n\nWhen that circumstance occurs, a magical mouth appears on the object and recites the message in your voice and at the same volume you spoke. If the object you chose has a mouth or something that looks like a mouth (for example, the mouth of a statue), the magical mouth appears there so that words appear to come from the object\'s mouth. When you cast this spell, you can have the spell end after it delivers its message, or it can remain and repeat its message whenever the trigger occurs.', classes: ['artificer', 'bard', 'wizard'], tags: ['utility', 'communication'] },
  { id: 'nystuls-magic-aura', name: "Nystul's Magic Aura", level: 2, school: 'Illusion', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a small square of silk', duration: '24 hours', concentration: false, ritual: false, description: 'You place an illusion on a creature or an object you touch so that divination spells reveal false information about it. The target can be a willing creature or an object that isn\'t being carried or worn by another creature.\n\nWhen you cast the spell, choose one or both of the following effects. The effect lasts for the duration. If you cast this spell on the same creature or object every day for 30 days, placing the same effect on it each time, the illusion lasts until it is dispelled.\n\nFalse Aura. You change the way the target appears to spells and magical effects, such as detect magic, that detect magical auras. You can make a nonmagical object appear magical, a magical object appear nonmagical, or change the object\'s magical aura so that it appears to belong to a specific school of magic that you choose.\n\nMask. You change the way the target appears to spells and magical effects that detect creature types, such as a paladin\'s Divine Sense or the trigger of a symbol spell. You choose a creature type and other spells and magical effects treat the target as if it were a creature of that type or of that alignment.', classes: ['wizard'], tags: ['utility', 'deception'] },
  { id: 'spider-climb', name: 'Spider Climb', level: 2, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a drop of bitumen and a spider', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'movement'] },

  // 3rd Level
  { id: 'blinding-smite', name: 'Blinding Smite', level: 3, school: 'Evocation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a melee weapon attack during this spell\'s duration, you and the weapon are briefly surrounded by a brilliant light, and the attack deals an extra 3d8 radiant damage to the target. Additionally, the target must succeed on a Constitution saving throw or be blinded until the spell ends.\n\nA creature blinded by this spell makes another Constitution saving throw at the end of each of its turns. On a successful save, it is no longer blinded.', classes: ['paladin'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'smite', 'control'] },
  { id: 'conjure-barrage', name: 'Conjure Barrage', level: 3, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (60-foot cone)', components: ['V', 'S', 'M'], materialComponent: 'one piece of ammunition or a thrown weapon', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You throw a nonmagical weapon or fire a piece of nonmagical ammunition into the air to create a cone of identical weapons that shoot forward and then disappear. Each creature in a 60-foot cone must succeed on a Dexterity saving throw. A creature takes 3d8 damage on a failed save, or half as much damage on a successful one. The damage type is the same as that of the weapon or ammunition used as a component.', classes: ['ranger'], savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'lightning-arrow', name: 'Lightning Arrow', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you make a ranged weapon attack during the spell\'s duration, the weapon\'s ammunition, or the weapon itself if it\'s a thrown weapon, transforms into a bolt of lightning. Make the attack roll as normal. The target takes 4d8 lightning damage on a hit, or half as much damage on a miss, instead of the weapon\'s normal damage. Whether you hit or miss, each creature within 10 feet of the target must make a Dexterity saving throw. Each of these creatures takes 2d8 lightning damage on a failed save, or half as much damage on a successful one.\n\nThe piece of ammunition or weapon then returns to its normal form.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage for both effects of the spell increases by 1d8 for each slot level above 3rd.', classes: ['ranger'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'ranged'] },
  { id: 'magic-circle', name: 'Magic Circle', level: 3, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 minute', range: '10 feet', components: ['V', 'S', 'M'], materialComponent: 'holy water or powdered silver and iron worth at least 100 gp, which the spell consumes', duration: '1 hour', concentration: false, ritual: false, description: 'You create a 10-foot-radius, 20-foot-tall cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear wherever the cylinder intersects with the floor or other surface.\n\nChoose one or more of the following types of creatures: celestials, elementals, fey, fiends, or undead. The circle affects a creature of the chosen type in the following ways:\n\nThe creature can\'t willingly enter the cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a Charisma saving throw.\n\nThe creature has disadvantage on attack rolls against targets within the cylinder.\n\nTargets within the cylinder can\'t be charmed, frightened, or possessed by the creature.\n\nWhen you cast this spell, you can elect to cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the cylinder and protecting targets outside it.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the duration increases by 1 hour for each slot level above 3rd.', classes: ['cleric', 'paladin', 'warlock', 'wizard'], savingThrow: 'cha', tags: ['protection', 'control'] },
  { id: 'speak-with-plants', name: 'Speak with Plants', level: 3, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V', 'S'], duration: '10 minutes', concentration: false, ritual: false, description: 'You imbue plants within 30 feet of you with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell\'s area within the past day, gaining information about creatures that have passed, weather, and other circumstances.\n\nYou can also turn difficult terrain caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into difficult terrain that lasts for the duration, causing vines and branches to hinder pursuers, for example.\n\nPlants might be able to perform other tasks on your behalf, at the DM\'s discretion. The spell doesn\'t enable plants to uproot themselves and move about, but they can freely move branches, tendrils, and stalks.\n\nIf a plant creature is in the area, you can communicate with it as if you shared a common language, but you gain no magical ability to influence it.', classes: ['bard', 'druid', 'ranger'], tags: ['utility', 'communication'] },

  // 4th Level
  { id: 'aura-of-life', name: 'Aura of Life', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Life-preserving energy radiates from you in an aura with a 30-foot radius. Until the spell ends, the aura moves with you, centered on you. Each nonhostile creature in the aura (including you) has resistance to necrotic damage, and its hit point maximum can\'t be reduced. In addition, a nonhostile, living creature in the aura regains 1 hit point when it starts its turn there with 0 hit points.', classes: ['paladin'], tags: ['buff', 'healing', 'aoe'] },
  { id: 'aura-of-purity', name: 'Aura of Purity', level: 4, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 action', range: 'Self (30-foot radius)', components: ['V'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Purifying energy radiates from you in an aura with a 30-foot radius. Until the spell ends, the aura moves with you, centered on you. Each nonhostile creature in the aura (including you) can\'t become diseased, has resistance to poison damage, and has advantage on saving throws against effects that cause any of the following conditions: blinded, charmed, deafened, frightened, paralyzed, poisoned, and stunned.', classes: ['paladin'], tags: ['buff', 'protection', 'aoe'] },

  // 5th Level
  { id: 'banishing-smite', name: 'Banishing Smite', level: 5, school: 'Abjuration', sourceBook: 'PHB', castingTime: '1 bonus action', range: 'Self', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The next time you hit a creature with a weapon attack before this spell ends, your weapon crackles with force, and the attack deals an extra 5d10 force damage to the target. Additionally, if this attack reduces the target to 50 hit points or fewer, you banish it. If the target is native to a different plane of existence than the one you\'re on, the target disappears, returning to its home plane. If the target is native to the plane you\'re on, the creature vanishes into a harmless demiplane. While there, the target is incapacitated. It remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.', classes: ['paladin'], damageType: 'force', tags: ['damage', 'smite', 'control'] },
  { id: 'cloudkill', name: 'Cloudkill', level: 5, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create a 20-foot-radius sphere of poisonous, yellow-green fog centered on a point you choose within range. The fog spreads around corners. It lasts for the duration or until strong wind disperses the fog, ending the spell. Its area is heavily obscured.\n\nWhen a creature enters the spell\'s area for the first time on a turn or starts its turn there, that creature must make a Constitution saving throw. The creature takes 5d8 poison damage on a failed save, or half as much damage on a successful one. Creatures are affected even if they hold their breath or don\'t need to breathe.\n\nThe fog moves 10 feet away from you at the start of each of your turns, rolling along the surface of the ground. The vapors, being heavier than air, sink to the lowest level of the land, even pouring down openings.', atHigherLevels: 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', classes: ['sorcerer', 'wizard'], damageType: 'poison', savingThrow: 'con', tags: ['damage', 'aoe', 'control'] },
  { id: 'reincarnate', name: 'Reincarnate', level: 5, school: 'Transmutation', sourceBook: 'PHB', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'rare oils and unguents worth at least 1,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You touch a dead humanoid or a piece of a dead humanoid. Provided that the creature has been dead no longer than 10 days, the spell forms a new adult body for it and then calls the soul to enter that body. If the target\'s soul isn\'t free or willing to do so, the spell fails.\n\nThe magic fashions a new body for the creature to inhabit, which likely causes the creature\'s race to change. The DM rolls a d100 and consults the Reincarnate table to determine what form the creature takes when restored to life.\n\nThe reincarnated creature recalls its former life and experiences. It retains the capabilities it had in its original form, except it exchanges its original race for the new one and changes its racial traits accordingly.', classes: ['druid'], tags: ['resurrection'] },

  // 6th Level
  { id: 'transport-via-plants', name: 'Transport via Plants', level: 6, school: 'Conjuration', sourceBook: 'PHB', castingTime: '1 action', range: '10 feet', components: ['V', 'S'], duration: '1 round', concentration: false, ritual: false, description: 'This spell creates a magical link between a Large or larger inanimate plant within range and another plant, at any distance, on the same plane of existence. You must have seen or touched the destination plant at least once before. For the duration, any creature can step into the target plant and exit from the destination plant by using 5 feet of movement.', classes: ['druid'], tags: ['teleportation', 'utility'] },

  // ── TCE CANTRIPS ────────────────────────────────────────────────────────
  { id: 'lightning-lure', name: 'Lightning Lure', level: 0, school: 'Evocation', sourceBook: 'TCE', alsoIn: ['SCAG'], castingTime: '1 action', range: 'Self (15-foot radius)', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a lash of lightning energy that strikes at one creature of your choice that you can see within 15 feet of you. The target must succeed on a Strength saving throw or be pulled up to 10 feet in a straight line toward you and then take 1d8 lightning damage if it is within 5 feet of you.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['artificer', 'sorcerer', 'warlock', 'wizard'], damageType: 'lightning', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'mind-sliver', name: 'Mind Sliver', level: 0, school: 'Enchantment', sourceBook: 'TCE', castingTime: '1 action', range: '60 feet', components: ['V'], duration: '1 round', concentration: false, ritual: false, description: 'You drive a disorienting spike of psychic energy into the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'debuff'] },

  // ── TCE LEVEL 1 ─────────────────────────────────────────────────────────
  { id: 'tashas-caustic-brew', name: "Tasha's Caustic Brew", level: 1, school: 'Evocation', sourceBook: 'TCE', castingTime: '1 action', range: 'Self (30-foot line)', components: ['V', 'S', 'M'], materialComponent: 'a bit of rotten food', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A stream of acid emanates from you in a line 30 feet long and 5 feet wide in a direction you choose. Each creature in the line must succeed on a Dexterity saving throw or be covered in acid for the spell\'s duration or until a creature uses its action to scrape or wash the acid off itself or another creature. A creature covered in the acid takes 2d4 acid damage at the start of each of its turns.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 2d4 for each slot level above 1st.', classes: ['artificer', 'sorcerer', 'wizard'], damageType: 'acid', savingThrow: 'dex', tags: ['damage', 'aoe'] },

  // ── TCE LEVEL 2 ─────────────────────────────────────────────────────────
  { id: 'summon-beast', name: 'Summon Beast', level: 2, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a feather, tuft of fur, and fish tail inside a gilded acorn worth at least 200 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a bestial spirit. It manifests in an unoccupied space that you can see within range. This corporeal form uses the Bestial Spirit stat block. When you cast the spell, choose an environment: Air, Land, or Water. The creature resembles an animal of your choice that is native to the chosen environment, which determines certain traits in its stat block. The creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe creature is an ally to you and your companions. In combat, the creature shares your initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don\'t issue any, it takes the Dodge action and uses its move to avoid danger.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, use the higher level wherever the spell\'s level appears in the stat block.', classes: ['druid', 'ranger'], tags: ['summoning', 'conjuration'] },
  { id: 'tashas-mind-whip', name: "Tasha's Mind Whip", level: 2, school: 'Enchantment', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V'], duration: '1 round', concentration: false, ritual: false, description: 'You psychically lash out at one creature you can see within range. The target must make an Intelligence saving throw. On a failed save, the target takes 3d6 psychic damage, and it can\'t take a reaction until the end of its next turn. Moreover, on its next turn, it must choose whether it gets a move, an action, or a bonus action; it gets only one of the three. On a successful save, the target takes half as much damage and suffers none of the spell\'s other effects.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd. The creatures must be within 30 feet of each other when you target them.', classes: ['sorcerer', 'wizard'], damageType: 'psychic', savingThrow: 'int', tags: ['damage', 'control', 'debuff'] },

  // ── TCE LEVEL 3 ─────────────────────────────────────────────────────────
  { id: 'spirit-shroud', name: 'Spirit Shroud', level: 3, school: 'Necromancy', sourceBook: 'TCE', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You call forth spirits of the dead, which flit around you for the spell\'s duration. The spirits are intangible and invulnerable.\n\nUntil the spell ends, any attack you make deals 1d8 extra damage when you hit a creature within 10 feet of you. This damage is radiant, necrotic, or cold (your choice when you cast the spell). Any creature that takes this damage can\'t regain hit points until the start of your next turn.\n\nIn addition, any creature of your choice that you can see that starts its turn within 10 feet of you has its speed reduced by 10 feet until the start of your next turn.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for every two slot levels above 3rd.', classes: ['cleric', 'paladin', 'warlock', 'wizard'], tags: ['damage', 'buff', 'control'] },
  { id: 'summon-shadowspawn', name: 'Summon Shadowspawn', level: 3, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'tears inside a gem worth at least 300 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a shadowy spirit. It manifests in an unoccupied space that you can see within range. This corporeal form uses the Shadow Spirit stat block. When you cast the spell, choose an emotion: Fury, Despair, or Fear. The creature resembles a misshapen biped marked by the chosen emotion, which determines certain traits in its stat block. The creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe creature is an ally to you and your companions. In combat, the creature shares your initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don\'t issue any, it takes the Dodge action and uses its move to avoid danger.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, use the higher level wherever the spell\'s level appears in the stat block.', classes: ['warlock', 'wizard'], tags: ['summoning', 'conjuration'] },
  { id: 'summon-undead', name: 'Summon Undead', level: 3, school: 'Necromancy', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a gilded skull worth at least 300 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth an undead spirit. It manifests in an unoccupied space that you can see within range. This corporeal form uses the Undead Spirit stat block. When you cast the spell, choose the creature\'s form: Ghostly, Putrid, or Skeletal. The spirit resembles an undead creature with the chosen form, which determines certain traits in its stat block. The creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe creature is an ally to you and your companions. In combat, the creature shares your initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don\'t issue any, it takes the Dodge action and uses its move to avoid danger.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, use the higher level wherever the spell\'s level appears in the stat block.', classes: ['warlock', 'wizard'], tags: ['summoning', 'necromancy'] },
  { id: 'summon-fey', name: 'Summon Fey', level: 3, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a gilded flower worth at least 300 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a fey spirit. It manifests in an unoccupied space that you can see within range. This corporeal form uses the Fey Spirit stat block. When you cast the spell, choose a mood: Fuming, Mirthful, or Tricksy. The creature resembles a fey creature of your choice marked by the chosen mood, which determines one of the traits in its stat block. The creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe creature is an ally to you and your companions. In combat, the creature shares your initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don\'t issue any, it takes the Dodge action and uses its move to avoid danger.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, use the higher level wherever the spell\'s level appears in the stat block.', classes: ['druid', 'ranger', 'warlock', 'wizard'], tags: ['summoning', 'conjuration'] },

  // ── TCE LEVEL 6 ─────────────────────────────────────────────────────────
  { id: 'summon-fiend', name: 'Summon Fiend', level: 6, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'humanoid blood inside a ruby vial worth at least 600 gp', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You call forth a fiendish spirit. It manifests in an unoccupied space that you can see within range. This corporeal form uses the Fiendish Spirit stat block. When you cast the spell, choose Demon, Devil, or Yugoloth. The creature resembles a fiend of the chosen type, which determines certain traits in its stat block. The creature disappears when it drops to 0 hit points or when the spell ends.\n\nThe creature is an ally to you and your companions. In combat, the creature shares your initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don\'t issue any, it takes the Dodge action and uses its move to avoid danger.', atHigherLevels: 'When you cast this spell using a spell slot of 7th level or higher, use the higher level wherever the spell\'s level appears in the stat block.', classes: ['warlock', 'wizard'], tags: ['summoning', 'conjuration'] },
  { id: 'tashas-otherworldly-guise', name: "Tasha's Otherworldly Guise", level: 6, school: 'Transmutation', sourceBook: 'TCE', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'an object engraved with a symbol of the Outer Planes, worth at least 500 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Choose Lower Planes or Upper Planes. Until the spell ends you gain all of the following:\n\n• Lower Planes only: immunity to fire and poison damage; immunity to the poisoned condition.\n• Upper Planes only: immunity to radiant and necrotic damage; immunity to the charmed condition.\n• Flying speed of 40 feet (spectral wings).\n• +2 bonus to AC.\n• Your weapon attacks are magical; you can use your spellcasting ability modifier instead of Strength or Dexterity for attack and damage rolls.\n• You can attack twice instead of once when you take the Attack action (ignored if you already have Extra Attack or similar).', classes: ['sorcerer', 'warlock', 'wizard'], tags: ['buff', 'transformation'] },

  // ── TCE LEVEL 7 ─────────────────────────────────────────────────────────
  { id: 'dream-of-the-blue-veil', name: 'Dream of the Blue Veil', level: 7, school: 'Conjuration', sourceBook: 'TCE', castingTime: '10 minutes', range: '20 feet', components: ['V', 'S', 'M'], materialComponent: 'a magic item or a willing creature from the destination world', duration: '6 hours', concentration: false, ritual: false, description: 'You and up to eight willing creatures within range fall unconscious for the spell\'s duration and experience visions of another world on the Material Plane, such as Oerth, Toril, Krynn, or Eberron. If the spell reaches its full duration, the visions conclude with each of you encountering and pulling back a mysterious blue curtain. The spell then ends with you mentally and physically transported to the world that was in the visions.\n\nTo cast this spell, you must have a magic item that originated on the world you wish to reach, and you must be aware of the world\'s existence. Your destination is a safe location within 1 mile of where the magic item was created. Alternatively, you can cast the spell if one of the affected creatures was born on the other world.\n\nThe spell ends early on a creature if that creature takes any damage, and the creature isn\'t transported. If you take any damage, the spell ends for you and all the other creatures, with none of you being transported.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['teleportation', 'utility'] },

  // ── XGtE LEVEL 1 ────────────────────────────────────────────────────────
  { id: 'beast-bond', name: 'Beast Bond', level: 1, school: 'Divination', sourceBook: 'XGtE', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a bit of fur wrapped in a cloth', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You establish a telepathic link with one beast you touch that is friendly to you or charmed by you. The spell fails if the beast\'s Intelligence score is 4 or higher. Until the spell ends, the link is active while you and the beast are within line of sight of each other. Through the link, the beast can understand your telepathic messages to it, and it can telepathically communicate simple emotions and concepts back to you. While the link is active, the beast gains advantage on attack rolls against any creature within 5 feet of you that you can see.', classes: ['druid', 'ranger'], tags: ['utility', 'communication'] },
  { id: 'ceremony', name: 'Ceremony', level: 1, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: '25 gp worth of powdered silver, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: true, description: 'You perform a special religious ceremony infused with magic. When you cast the spell, choose one of the following rites, the target of which must be within 10 feet of you:\n\nAtonement. You touch one willing creature whose alignment has changed, and make a DC 20 Wisdom (Insight) check. On a success, you restore the target to its original alignment.\n\nBless Water. You touch one vial of water and cause it to become holy water.\n\nComing of Age. You touch one humanoid who is a young adult. For the next 24 hours, whenever the target makes an ability check, it can roll a d4 and add the number rolled to the check. A creature can benefit from this rite only once.\n\nDedication. You touch one humanoid who wishes to be dedicated to your god\'s service. For the next 24 hours, whenever the target makes a saving throw, it can roll a d4 and add the number rolled to the save. A creature can benefit from this rite only once.\n\nFuneral Rite. You touch one corpse, and for the next 7 days, the target can\'t become undead by any means short of a wish spell.\n\nWedding. You touch adult humanoids willing to be bonded in marriage. For the next 7 days, each target gains a +2 bonus to AC while within 30 feet of each other.', classes: ['cleric', 'paladin'], tags: ['utility', 'ritual'] },

  // ── XGtE LEVEL 2 ────────────────────────────────────────────────────────
  { id: 'dragons-breath', name: "Dragon's Breath", level: 2, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 bonus action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a hot pepper', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one willing creature and imbue it with the power to spew magical energy from its mouth, provided it has one. Choose acid, cold, fire, lightning, or poison. Until the spell ends, the creature can use an action to exhale energy of the chosen type in a 15-foot cone. Each creature in that area must make a Dexterity saving throw, taking 3d6 damage of the chosen type on a failed save, or half as much on a successful one.', atHigherLevels: 'The damage increases by 1d6 for each slot level above 2nd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage', 'buff'] },
  { id: 'warding-wind', name: 'Warding Wind', level: 2, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A strong wind (20 miles per hour) blows around you in a 10-foot radius and moves with you, remaining centered on you. The wind has the following effects:\n• It deafens you and other creatures in its area.\n• It extinguishes unprotected flames torch-sized or smaller.\n• It hedges out vapor, gas, and fog that can be dispersed by strong wind.\n• The area is difficult terrain for creatures other than you.\n• Attack rolls of ranged weapon attacks have disadvantage if the attacks pass in or out of the wind.', classes: ['bard', 'druid', 'sorcerer', 'wizard'], tags: ['utility', 'defense'] },

  // ── XGtE LEVEL 3 ────────────────────────────────────────────────────────
  { id: 'catnap', name: 'Catnap', level: 3, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['S', 'M'], materialComponent: 'a pinch of sand', duration: '10 minutes', concentration: false, ritual: false, description: 'You make a calming gesture, and up to three willing creatures of your choice that you can see within range fall unconscious for the spell\'s duration. The spell ends on a target early if it takes damage or someone uses an action to shake or slap it awake. If a target remains unconscious for the full duration, that target gains the benefit of a short rest, and it can\'t be affected by this spell again until it finishes a long rest.', atHigherLevels: 'You can target one additional willing creature for each slot level above 3rd.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['utility', 'rest'] },
  { id: 'melfs-minute-meteors', name: "Melf's Minute Meteors", level: 3, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'niter, sulfur, and pine tar formed into a bead', duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'You create six tiny meteors in your space. They float in the air and orbit you for the spell\'s duration. When you cast the spell — and as a bonus action on each of your turns thereafter — you can expend one or two of the meteors, sending them streaking toward a point or points you choose within 120 feet of you. Once a meteor reaches its destination or impacts against a solid surface, the meteor explodes. Each creature within 5 feet of the point where the meteor explodes must make a Dexterity saving throw. A creature takes 2d6 fire damage on a failed save, or half as much on a successful one.', atHigherLevels: 'The number of meteors created increases by two for each slot level above 3rd.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'dex', tags: ['damage'] },
  { id: 'tiny-servant', name: 'Tiny Servant', level: 3, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 minute', range: 'Touch', components: ['V', 'S'], duration: '8 hours', concentration: false, ritual: false, description: 'You touch one Tiny, nonmagical object that isn\'t attached to another object or a surface and isn\'t being carried by another creature. The target animates and sprouts little arms and legs, becoming a creature under your control until the spell ends or the creature drops to 0 hit points. As a bonus action, you can mentally command the creature if it is within 120 feet of you. You decide what action the creature will take and where it will move during its next turn, or you can issue a simple, general command. When the creature drops to 0 hit points, it reverts to its original form, and any remaining damage carries over to that form.', atHigherLevels: 'You can animate two additional objects for each slot level above 3rd.', classes: ['artificer', 'wizard'], tags: ['utility', 'summoning'] },

  // ── XGtE LEVEL 4 ────────────────────────────────────────────────────────
  { id: 'charm-monster', name: 'Charm Monster', level: 4, school: 'Enchantment', sourceBook: 'XGtE', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: '1 hour', concentration: false, ritual: false, description: 'You attempt to charm a creature you can see within range. It must make a Wisdom saving throw, and it does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature is friendly to you. When the spell ends, the creature knows it was charmed by you.', atHigherLevels: 'You can target one additional creature for each slot level above 4th. The creatures must be within 30 feet of each other when you target them.', classes: ['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['control', 'charm'] },
  { id: 'shadow-of-moil', name: 'Shadow of Moil', level: 4, school: 'Necromancy', sourceBook: 'XGtE', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'an undead eyeball encased in a gem worth at least 150 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Flame-like shadows wreathe your body until the spell ends, causing you to become heavily obscured to others. The shadows turn dim light within 10 feet of you into darkness, and bright light in the same area to dim light. Until the spell ends, you have resistance to radiant damage. In addition, whenever a creature within 10 feet of you hits you with an attack, the shadows lash out at that creature, dealing it 2d8 necrotic damage.', classes: ['warlock'], damageType: 'necrotic', tags: ['defense', 'buff'] },
  { id: 'sickening-radiance', name: 'Sickening Radiance', level: 4, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Dim, greenish light spreads within a 30-foot-radius sphere centered on a point you choose within range. The light spreads around corners, and it lasts until the spell ends. When a creature moves into the spell\'s area for the first time on a turn or starts its turn there, that creature must succeed on a Constitution saving throw or take 4d10 radiant damage, and it suffers one level of exhaustion and emits a dim, greenish light in a 5-foot radius. This light makes it impossible for the creature to benefit from being invisible. The light and any levels of exhaustion caused by this spell go away when the spell ends.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'control', 'aoe'] },
  { id: 'storm-sphere', name: 'Storm Sphere', level: 4, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '150 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'A 20-foot-radius sphere of whirling air springs into existence, centered on a point you choose within range. Each creature in the sphere when it appears or that ends its turn there must succeed on a Strength saving throw or take 2d6 bludgeoning damage. The sphere\'s space is difficult terrain.\n\nUntil the spell ends, you can use a bonus action on each of your turns to cause a bolt of lightning to leap from the center of the sphere toward one creature you choose within 60 feet of the center. Make a ranged spell attack. You have advantage on the attack roll if the target is in the sphere. On a hit, the target takes 4d6 lightning damage.\n\nCreatures within 30 feet of the sphere have disadvantage on Wisdom (Perception) checks made to listen.', atHigherLevels: 'The damage for each of its effects increases by 1d6 for each slot level above 4th.', classes: ['sorcerer', 'wizard'], damageType: 'lightning', savingThrow: 'str', tags: ['damage', 'control', 'aoe'] },
  { id: 'summon-greater-demon', name: 'Summon Greater Demon', level: 4, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a vial of blood from a humanoid killed within the past 24 hours', duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'You utter foul words, summoning one demon from the chaos of the Abyss. You choose the demon\'s type, which must be one of challenge rating 5 or lower. The demon appears in an unoccupied space you can see within range, and disappears when it drops to 0 hit points or when the spell ends.\n\nRoll initiative for the demon, which has its own turns. You can issue a verbal command to it on each of your turns (no action required). At the end of each of the demon\'s turns, it makes a Charisma saving throw. On a failed save, the demon continues to obey you. On a successful save, your control ends and the demon pursues and attacks the nearest non-demons for the rest of the duration.\n\nAs part of casting the spell, you can form a circle on the ground with the blood used as a material component. While the spell lasts, the summoned demon can\'t cross the circle or target anyone within it.', atHigherLevels: 'The challenge rating increases by 1 for each slot level above 4th.', classes: ['warlock', 'wizard'], tags: ['summoning', 'conjuration'] },
  { id: 'vitriolic-sphere', name: 'Vitriolic Sphere', level: 4, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '150 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of giant slug bile', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You point at a location within range, and a glowing, 1-foot-diameter ball of emerald acid streaks there and explodes in a 20-foot-radius sphere. Each creature in that area must make a Dexterity saving throw. On a failed save, a creature takes 10d4 acid damage and another 5d4 acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage and no damage at the end of its next turn.', atHigherLevels: 'The initial damage increases by 2d4 for each slot level above 4th.', classes: ['sorcerer', 'wizard'], damageType: 'acid', savingThrow: 'dex', tags: ['damage', 'aoe'] },
  { id: 'watery-sphere', name: 'Watery Sphere', level: 4, school: 'Conjuration', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V', 'S', 'M'], materialComponent: 'a droplet of water', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You conjure up a sphere of water with a 5-foot radius at a point you can see within range. The sphere can hover but no more than 10 feet off the ground.\n\nAny creature in the sphere\'s space must make a Strength saving throw. On a successful save, a creature is ejected to the nearest unoccupied space of its choice outside the sphere. A Huge or larger creature succeeds automatically, and a Large or smaller creature can choose to fail. On a failed save, a creature is restrained by the sphere and engulfed by the water. At the end of each of its turns, a restrained target can repeat the saving throw.\n\nThe sphere can restrain up to four Medium or smaller creatures or one Large creature. As an action, you can move the sphere up to 30 feet in a straight line and ram it into creatures. When the spell ends, the sphere falls and extinguishes all normal flames within 30 feet.', classes: ['druid', 'sorcerer', 'wizard'], savingThrow: 'str', tags: ['control', 'conjuration'] },

  // ── XGtE LEVEL 5 ────────────────────────────────────────────────────────
  { id: 'dawn', name: 'Dawn', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a sunburst pendant worth at least 100 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'The light of dawn shines down on a location you specify within range. Until the spell ends, a 30-foot-radius, 40-foot-high cylinder of bright light glimmers there. This light is sunlight.\n\nWhen the cylinder appears, each creature in it must make a Constitution saving throw, taking 4d10 radiant damage on a failed save, or half as much on a successful one. A creature must also make this saving throw whenever it ends its turn in the cylinder.\n\nIf you\'re within 60 feet of the cylinder, you can move it up to 60 feet as a bonus action on your turn.', classes: ['cleric', 'wizard'], damageType: 'radiant', savingThrow: 'con', tags: ['damage', 'aoe'] },
  { id: 'immolation', name: 'Immolation', level: 5, school: 'Evocation', sourceBook: 'XGtE', castingTime: '1 action', range: '90 feet', components: ['V'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'Flames wreathe one creature you can see within range. The target must make a Dexterity saving throw. It takes 8d6 fire damage on a failed save, or half as much on a successful one. On a failed save, the target also burns for the spell\'s duration. The burning target sheds bright light in a 30-foot radius and dim light for an additional 30 feet. At the end of each of its turns, the target repeats the saving throw. It takes 4d6 fire damage on a failed save, and the spell ends on a successful one. These magical flames can\'t be extinguished by nonmagical means. If damage from this spell kills a target, the target is turned to ash.', classes: ['sorcerer'], damageType: 'fire', savingThrow: 'dex', tags: ['damage'] },

  // ── XGtE LEVEL 6 ────────────────────────────────────────────────────────
  { id: 'create-homunculus', name: 'Create Homunculus', level: 6, school: 'Transmutation', sourceBook: 'XGtE', castingTime: '1 hour', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'clay, ash, and mandrake root (consumed), and a jewel-encrusted dagger worth at least 1,000 gp', duration: 'Instantaneous', concentration: false, ritual: false, description: 'While speaking an intricate incantation, you cut yourself with a jewel-encrusted dagger, taking 2d4 piercing damage that can\'t be reduced in any way. You then drip your blood on the spell\'s other components and touch them, transforming them into a homunculus.\n\nThe homunculus is your faithful companion, and it dies if you die. Whenever you finish a long rest, you can spend up to half your Hit Dice if the homunculus is on the same plane of existence as you. When you do so, roll each die and add your Constitution modifier to it. Your hit point maximum is reduced by the total, and the homunculus\'s hit point maximum and current hit points are both increased by the same amount. This reduction can\'t be removed before your next long rest, except by the homunculus\'s death.\n\nYou can have only one homunculus at a time. If you cast this spell while your homunculus lives, the spell fails.', classes: ['wizard'], tags: ['summoning', 'utility'] },
  { id: 'druid-grove', name: 'Druid Grove', level: 6, school: 'Abjuration', sourceBook: 'XGtE', castingTime: '10 minutes', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'mistletoe (consumed) harvested with a golden sickle under a full moon', duration: '24 hours', concentration: false, ritual: false, description: 'You invoke the spirits of nature to protect an area outdoors or underground, up to a 90-foot cube. Buildings are excluded. If you cast this spell in the same area every day for a year, the spell lasts until dispelled.\n\nYou can specify creatures as friends immune to the effects, or a password that grants immunity when spoken. The spell creates effects you choose within the area: Solid Fog fills designated squares with heavily obscuring fog (difficult terrain). Grasping Undergrowth restrains creatures as if by the entangle spell. Grove Guardians animates up to four trees as awakened trees that attack intruders and obey your spoken commands. Additionally, you can place one of the following effects: a constant gust of wind in two locations, spike growth in one location, or wind wall in two locations.\n\nA dispel magic cast on the area removes only one effect at a time.', classes: ['druid'], tags: ['utility', 'defense', 'aoe'] },

  // ── TCE LEVEL 9 ─────────────────────────────────────────────────────────
  { id: 'blade-of-disaster', name: 'Blade of Disaster', level: 9, school: 'Conjuration', sourceBook: 'TCE', castingTime: '1 bonus action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You create a blade-shaped planar rift about 3 feet long in an unoccupied space you can see within range. The blade lasts for the duration. When you cast this spell, you can make up to two melee spell attacks with the blade, each one against a creature, loose object, or structure within 5 feet of the blade. On a hit, the target takes 4d12 force damage. This attack scores a critical hit if the number on the d20 is 18 or higher. On a critical hit, the blade deals an extra 8d12 force damage (for a total of 12d12 force damage).\n\nAs a bonus action on your turn, you can move the blade up to 30 feet to an unoccupied space you can see and then make up to two melee spell attacks with it again.\n\nThe blade can harmlessly pass through any barrier, including a wall of force.', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'force', tags: ['damage'] },
  // ── Tides of Blood (ToB) ───────────────────────────────────────────────────

  // Cantrips
  { id: 'tob-blood-bolt', name: 'Blood Bolt', level: 0, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '100 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of blood, a piece of flint', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You fling a globule of corrupted blood at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d8 necrotic damage, and they are blinded until the end of their next turn.\n\nThis spell\'s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', classes: ['warlock'], damageType: 'necrotic', tags: ['damage', 'debuff'] },
  { id: 'tob-blood-lash', name: 'Blood Lash', level: 0, school: 'Necromancy', sourceBook: 'ToB', castingTime: '1 action', range: '20 feet', components: ['V', 'S', 'M'], materialComponent: 'a drop of blood, a piece of leather twine', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a swirling, liquid whip of your own blood and lash out towards a creature within range. Make a ranged spell attack against the target. If the spell hits, they take 1d6 necrotic damage, and they take a -1 penalty to their AC. If their AC is reduced in this way, it cannot be reduced further by any other use of the Blood Lash spell, cast by you or any other creature. This reduction lasts for 1 minute.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', classes: ['warlock'], damageType: 'necrotic', tags: ['damage', 'debuff'] },
  { id: 'tob-salt-spray', name: 'Salt Spray', level: 0, school: 'Conjuration', sourceBook: 'ToB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You extend your hand toward a creature you can see within range and conjure a spray of seawater from your fingertips. The creature must succeed on a Dexterity saving throw or take 1d6 cold damage. The creature then takes another 1d6 piercing damage from the salt in the water at the beginning of their next turn.\n\nThis spell\'s damage increases by 1d6 when you reach 5th level (2d6 × 2), 11th level (3d6 × 2), and 17th level (4d6 × 2).', classes: ['sorcerer', 'warlock', 'wizard'], damageType: 'cold', savingThrow: 'dex', tags: ['damage'] },

  // Level 1
  { id: 'tob-aquatic-volley', name: 'Aquatic Volley', level: 1, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a sea shell', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create 3 orbs of water that float around you before hurling themselves at nearby creatures. You choose a target for each of the orbs of water. On a hit the target takes 1d10 magical bludgeoning damage.\n\nAt higher levels: When you cast this spell using a spell slot of 2nd or higher, you create one additional orb for each slot level above 1st. If this spell is cast at 5th level or higher, each orb deals an additional 1d6 cold damage.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd or higher, you create one additional orb for each slot level above 1st. At 5th level each orb deals an additional 1d6 cold damage.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'bludgeoning', tags: ['damage', 'ranged'] },
  { id: 'tob-cold-rebuke', name: 'Cold Rebuke', level: 1, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 reaction, taken when struck by a melee attack', range: '10 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'When you are struck by a creature with a melee attack you can create a blast of cold energy to immediately retaliate. The creature must make a Constitution saving throw or suffer 2d12 cold damage, half as much on a successful save.\n\nAt higher levels: When you cast this spell using a spell slot of 2nd or higher, the damage increases by 1d12 for each slot level above 1st.', atHigherLevels: 'When you cast this spell using a spell slot of 2nd or higher, the damage increases by 1d12 for each slot level above 1st.', classes: ['druid', 'sorcerer', 'warlock'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'reaction'] },
  { id: 'tob-screaming-wind', name: 'Screaming Wind', level: 1, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '60 feet', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'A terrible wind begins to whip around in the air 30 feet above you, circling you in a 30 foot radius. This spell fails if there is not enough space for the wind to move. When you cast the spell choose a point you can see within range. Each creature within 10 feet of that point must make a Strength saving throw or suffer 2d12 magical bludgeoning damage. On each of your turns you can use an action to invoke the wind again, targeting the same or a new point. If you are beneath an open sky the radius affected increases to 15 feet.\n\nAt higher levels: When you cast this spell using a spell slot of 4th or higher, the spell reduces the creature\'s movement to 0 instead of half. At 7th level or higher the spell also knocks creatures prone on a failed save.', atHigherLevels: 'At 4th level or higher, creatures\' movement is reduced to 0 instead of half. At 7th level creatures are also knocked prone on a failed save. Damage increases by 1d12 per slot above 3rd.', classes: ['druid'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control', 'aoe'] },

  // Level 2
  { id: 'tob-crushing-smite', name: 'Crushing Smite', level: 2, school: 'Enchantment', sourceBook: 'ToB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: "You imbue your weapon with the power of the ocean's weight. The next time you hit a creature with a melee attack you deal an additional 2d8 magical bludgeoning damage. Additionally the creature must make a Strength saving throw. On a failed save the creature has its movement speed reduced by half. The creature can repeat this saving throw at the end of its turn.\n\nAt higher levels: When you cast this spell using a spell slot of 4th or higher, the spell reduces the creature's movement to 0 instead of half.", atHigherLevels: "When you cast this spell using a spell slot of 4th or higher, the spell reduces the creature's movement to 0 instead of half.", classes: ['paladin'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'smite', 'control'] },
  { id: 'tob-crushing-wave', name: 'Crushing Wave', level: 2, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a sea shell', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You summon a wall of water 30 foot long, 10 foot high and 1 foot thick starting within 60 feet of you. If there isn\'t space to summon this wall, the spell fails. When you cast this spell you can have the wall fall in either direction causing any creatures within 10 ft of that side of the wall to make Dexterity saving throws. A creature hit by this wave takes 4d8 magical bludgeoning damage and is knocked prone. On a successful save they take half damage and are not knocked prone.\n\nAt higher levels: When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', classes: ['druid', 'sorcerer', 'warlock', 'wizard'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },
  { id: 'tob-howling-winds', name: 'Howling Winds', level: 2, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '30 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send wind hurtling towards a creature from every direction. The creature must make a Strength saving throw or take 4d8 damage and be thrown 15 feet in a random direction. On a successful save the creature takes half damage and is not thrown.\n\nAt higher levels: When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', classes: ['druid', 'warlock'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control'] },
  { id: 'tob-hungering-smite', name: 'Hungering Smite', level: 2, school: 'Enchantment', sourceBook: 'ToB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You imbue your weapon with vampiric hunger. The next time you hit a creature with a melee attack you deal an additional 2d8 necrotic damage. You regain hit points equal to that additional damage.\n\nAt higher levels: When you cast this spell using a spell slot of 4th or higher, the spell reduces the creature\'s movement to 0 instead of half.', atHigherLevels: "When you cast this spell using a spell slot of 4th or higher, the spell reduces the creature's movement to 0 instead of half.", classes: ['paladin'], damageType: 'necrotic', tags: ['damage', 'smite', 'healing'] },
  { id: 'tob-hydro-jet', name: 'Hydro Jet', level: 2, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: 'Self (20 foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You send a blast of water in a 20 ft cone in front of you. All creatures in the area must make Strength saving throws or suffer 2d8 magical bludgeoning damage and be knocked prone. On a successful save the target takes half as much damage and is not knocked prone.\n\nAt higher levels: When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd or higher, the damage increases by 1d8 for every level above 2nd.', classes: ['druid', 'warlock'], damageType: 'bludgeoning', savingThrow: 'str', tags: ['damage', 'control', 'aoe'] },
  { id: 'tob-rain', name: 'Rain', level: 2, school: 'Transmutation', sourceBook: 'ToB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You create a downpour of heavy rain in a 30 foot radius in every direction from where you stand. Whenever a creature in this area takes fire damage, they can reduce that damage by your level.', classes: ['druid', 'sorcerer'], tags: ['utility', 'aoe'] },

  // Level 3
  { id: 'tob-swell', name: 'Swell', level: 3, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'dried seaweed', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You create a brief whirlpool of water that pulls everyone together. You choose a point within 60 feet of you. All creatures within 20 feet of that point must make a Strength saving throw or be pulled 20 feet towards the centre. Until the start of your next turn the affected area is considered difficult terrain.', classes: ['druid'], savingThrow: 'str', tags: ['control', 'aoe'] },
  { id: 'tob-thunderous-rebuke', name: 'Thunderous Rebuke', level: 3, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '20 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'When you take damage from an attack you can return the damage with thunderous force. The creature who hit you suffers 2d12 thunder damage.\n\nAt higher levels: The damage increases by 1d12 for each slot level above 2nd.', atHigherLevels: 'The damage increases by 1d12 for each slot level above 2nd.', classes: ['druid'], damageType: 'thunder', tags: ['damage', 'reaction'] },

  // Level 4
  { id: 'tob-fountain-of-istishia', name: 'Fountain of Istishia', level: 4, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: '1 minute', concentration: false, ritual: false, description: 'You summon five 5 foot wide pillars of water that erupt from the ground and reach 30 ft into the air. Creatures standing in the pillars\' area must make Dexterity saving throws when the spell is cast or take 2d10 bludgeoning damage and be thrown 30 ft into the air. On a success the creature takes half damage and is moved 5 feet. If the creature hits a creature or ceiling on the way up, both take an additional 1d10 bludgeoning damage. When the spell ends any creature elevated by the spell falls 30 feet.', classes: ['druid'], damageType: 'bludgeoning', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },
  { id: 'tob-storm-aura', name: 'Storm Aura', level: 4, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Lightning crackles across your body for the duration. You can end the spell early by using an action to dismiss it. The aura provides you with a Thunderous Shield (resistance to Thunder damage) or a Lightning Shield (resistance to Lightning damage), as you choose. Whenever a creature within 5 feet of you hits you with a melee attack, the Shield erupts with the power of a storm: the attacker takes 2d8 thunder damage from a Thunderous Shield, or 2d8 lightning damage from a Lightning Shield.', classes: ['druid'], damageType: 'lightning', tags: ['defense', 'damage', 'aoe'] },
  { id: 'tob-storm-sprint', name: 'Storm Sprint', level: 4, school: 'Enchantment', sourceBook: 'ToB', castingTime: '1 action', range: 'Self', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You imbue yourself with the power of a storm to blast past your enemies. You dash in a 30 foot line, forcing every creature in your path to make a Strength saving throw. On a failed save the creature suffers 3d10 thunder damage and is knocked prone. On a successful save the creature suffers half damage and is not knocked prone.\n\nAt higher levels: The damage increases by 1d6 for each slot level above 2nd.', atHigherLevels: 'The damage increases by 1d6 for each slot level above 2nd.', classes: ['druid', 'wizard'], damageType: 'thunder', savingThrow: 'str', tags: ['damage', 'movement', 'control'] },

  // Level 5
  { id: 'tob-drowning-smite', name: 'Drowning Smite', level: 5, school: 'Enchantment', sourceBook: 'ToB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: "You imbue your weapon with the power of the ocean's depths. The next time you hit a creature with a melee attack you deal an additional 5d8 cold damage. Additionally the creature must make a Constitution saving throw. On a failed save the creature begins vomiting sea water for 1 minute. Any spell attack roll or ability check that requires a verbal component is made with disadvantage. The creature can repeat this saving throw at the end of its turn.", classes: ['paladin'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'smite', 'debuff'] },
  { id: 'tob-midian-touch', name: 'Midian Touch', level: 5, school: 'Transmutation', sourceBook: 'ToB', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'Gold dust worth 10 gp, which the spell consumes', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You touch one creature or object up to two size categories larger than you, and attempt to transmute them into gold. The target takes 3d6 fire damage, and if the target is a creature, it must make a Constitution saving throw. On a failed save, it is restrained as liquid gold begins to cover its body. On a successful save, the creature isn\'t affected. Constructs have disadvantage on all saving throws related to this spell, while any fiend, fey or celestial has advantage. If the target was a non-magical object, it is immediately turned to gold.\n\nA creature restrained by this spell must make another saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails three times, it is turned into a golden statue (petrified) for the duration. The successes and failures don\'t need to be consecutive.', classes: ['sorcerer', 'wizard'], damageType: 'fire', savingThrow: 'con', tags: ['damage', 'control'] },
  { id: 'tob-raging-storm', name: 'Raging Storm', level: 5, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: 'Self (60 foot cone)', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You summon forth a massive wave of lightning that explodes from your hands in a massive 60 foot cone. All creatures in the area must make Dexterity saving throws or suffer 6d8 lightning damage, half as much on a successful save. Any creature that rolls a 5 or lower on the die is also stunned until the end of their next turn.\n\nAt higher levels: When you cast this spell using a spell slot of 6th or higher, the spell deals an additional 1d8 lightning damage and the number required to stun a creature is increased by 1 for each slot level above 5th.', atHigherLevels: 'When you cast this spell using a spell slot of 6th or higher, the spell deals an additional 1d8 lightning damage and the number required to stun a creature is increased by 1 for each slot level above 5th.', classes: ['cleric', 'druid', 'sorcerer', 'warlock'], damageType: 'lightning', savingThrow: 'dex', tags: ['damage', 'control', 'aoe'] },
  { id: 'tob-reaching-cold', name: 'Reaching Cold', level: 5, school: 'Evocation', sourceBook: 'ToB', castingTime: '1 action', range: '120 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You summon forth tendrils of frost that reach out to a creature, freezing its body. You choose a target for the initial attack. On a successful hit the creature takes 8d8 cold damage. After hitting the creature a wave of frost surges out from that creature. All creatures of your choosing within 30 feet of that creature must make Constitution saving throws. On a failed save each creature suffers 4d8 cold damage, half as much on a successful save.\n\nAt higher levels: When you cast this spell using a spell slot of 6th or higher, range of the frost wave is increased by 10 feet for each slot level above 5th.', atHigherLevels: 'When you cast this spell using a spell slot of 6th or higher, range of the frost wave is increased by 10 feet for each slot level above 5th.', classes: ['druid', 'sorcerer'], damageType: 'cold', savingThrow: 'con', tags: ['damage', 'aoe'] },

  // Level 6
  { id: 'tob-investiture-of-the-ocean', name: 'Investiture of the Ocean', level: 6, school: 'Transmutation', sourceBook: 'ToB', castingTime: '1 bonus action', range: 'Self', components: ['V', 'S'], duration: 'Concentration, up to 10 minutes', concentration: true, ritual: false, description: 'Your body becomes made entirely of water, like a sea nymph of legend. Until the spell ends, you gain the following benefits: You are immune to cold damage and have resistance to fire damage. Your speed while underwater is doubled. You are completely invisible while underwater.', classes: ['druid', 'sorcerer'], tags: ['buff', 'transformation'] },

  // Acquisitions Incorporated spells
  // Level 1
  { id: 'acqinc-distort-value', name: 'Distort Value', level: 1, school: 'Illusion', sourceBook: 'AcqInc', castingTime: '1 minute', range: 'Touch', components: ['V'], duration: '8 hours', concentration: false, ritual: false, description: "You cast this spell on an object no more than 1 foot on a side, either doubling its perceived value by adding illusory flourishes or polish to it, or reducing its perceived value by half with illusory scratches, dents, and other unsightly features. Anyone examining the object can ascertain its true value with a successful Intelligence (Investigation) check against your spell save DC.", atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the maximum size of the object increases by 1 foot for each slot level above 1st.', classes: ['bard', 'sorcerer', 'warlock', 'wizard'], tags: ['utility', 'illusion', 'social'] },
  { id: 'acqinc-jims-magic-missile', name: "Jim's Magic Missile", level: 1, school: 'Evocation', sourceBook: 'AcqInc', castingTime: '1 action', range: '120 feet', components: ['V', 'S', 'M'], materialComponent: 'Royalty component: 1 gp magically transferred to the spell\'s creator upon casting', duration: 'Instantaneous', concentration: false, ritual: false, description: "You create three twisting, whistling, hypoallergenic, gluten-free darts of magical force. Each dart targets a creature of your choice that you can see within range. Make a ranged spell attack for each missile. On a hit, a missile deals 2d4 force damage to its target.\n\nIf the attack roll scores a critical hit, the target of that missile takes 5d4 force damage instead of rolling damage twice. If the attack roll for any missile is a 1, all missiles miss their targets and blow up in your face, dealing 1 force damage per missile to you.", atHigherLevels: 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart, and the royalty component increases by 1 gp, for each slot level above 1st.', classes: ['wizard'], damageType: 'force', tags: ['damage'] },

  // Level 2
  { id: 'acqinc-gift-of-gab', name: 'Gift of Gab', level: 2, school: 'Enchantment', sourceBook: 'AcqInc', castingTime: '1 reaction, taken when you speak to another creature', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'Royalty component: 2 gp magically transferred to the spell\'s creator upon casting', duration: 'Instantaneous', concentration: false, ritual: false, description: 'When you cast this spell, you skillfully reshape the memories of listeners in your immediate area, so that each creature of your choice within 5 feet of you forgets everything you said within the last 6 seconds. Those creatures then remember that you actually said the words you speak as the verbal component of the spell.', classes: ['bard', 'wizard'], tags: ['utility', 'social', 'memory'] },
  { id: 'acqinc-jims-glowing-coin', name: "Jim's Glowing Coin", level: 2, school: 'Enchantment', sourceBook: 'AcqInc', castingTime: '1 action', range: '60 feet', components: ['S', 'M'], materialComponent: 'a coin; royalty component: 2 gp magically transferred to the spell\'s creator upon casting', duration: '1 minute', concentration: false, ritual: false, description: 'When you cast the spell, you hurl the coin (the material component) to any spot within range. The coin lights up as if under the effect of a light spell. Each creature of your choice that you can see within 30 feet of the coin must succeed on a Wisdom saving throw or be distracted for the duration. While distracted, a creature has disadvantage on Wisdom (Perception) checks and initiative rolls.', classes: ['wizard'], savingThrow: 'wis', tags: ['utility', 'control', 'debuff'] },

  // Level 3
  { id: 'acqinc-fast-friends', name: 'Fast Friends', level: 3, school: 'Enchantment', sourceBook: 'AcqInc', castingTime: '1 action', range: '30 feet', components: ['V'], duration: 'Concentration, up to 1 hour', concentration: true, ritual: false, description: 'When you cast this spell, choose one humanoid within range that can see and hear you, and that can understand you. The creature must succeed on a Wisdom saving throw or become charmed by you for the duration. While the creature is charmed in this way, it undertakes to perform any services or activities you ask of it in a friendly manner, to the best of its ability.\n\nYou can set the creature new tasks when a previous task is completed, or if you decide to end its current task. If the service or activity might cause harm to the creature, or if it conflicts with the creature\'s normal activities and desires, the creature can make another Wisdom saving throw to try to end the effect. This save is made with advantage if you or your companions are fighting the creature. If the activity would result in certain death for the creature, the spell ends.\n\nWhen the spell ends, the creature knows it was charmed by you.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', classes: ['bard', 'cleric', 'wizard'], savingThrow: 'wis', tags: ['social', 'charm', 'control'] },
  { id: 'acqinc-incite-greed', name: 'Incite Greed', level: 3, school: 'Enchantment', sourceBook: 'AcqInc', castingTime: '1 action', range: '30 feet', components: ['V', 'S', 'M'], materialComponent: 'a gem worth at least 50 gp', duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'When you cast this spell, you present the gem used as the material component and choose any number of creatures within range that can see you. Each target must succeed on a Wisdom saving throw or be charmed by you until the spell ends, or until you or your companions do anything harmful to it. While charmed in this way, a creature can do nothing but use its movement to approach you in a safe manner. While an affected creature is within 5 feet of you, it cannot move, but simply stares greedily at the gem you present.\n\nAt the end of each of its turns, an affected target can make a Wisdom saving throw. If it succeeds, this effect ends for that target.', classes: ['cleric', 'sorcerer', 'warlock', 'wizard'], savingThrow: 'wis', tags: ['social', 'charm', 'control', 'aoe'] },
  { id: 'acqinc-motivational-speech', name: 'Motivational Speech', level: 3, school: 'Enchantment', sourceBook: 'AcqInc', castingTime: '1 minute', range: '60 feet', components: ['V'], duration: '1 hour', concentration: false, ritual: false, description: 'You address allies, staff, or innocent bystanders to exhort and inspire them to greatness, whether they have anything to get excited about or not. Choose up to five creatures within range that can hear you. For the duration, each affected creature gains 5 temporary hit points and has advantage on Wisdom saving throws. If an affected creature is hit by an attack, it has advantage on the next attack roll it makes. Once an affected creature loses the temporary hit points granted by this spell, the spell ends for that creature.', atHigherLevels: 'When you cast this spell using a spell slot of 4th level or higher, the temporary hit points increase by 5 for each slot level above 3rd.', classes: ['bard', 'cleric'], tags: ['buff', 'support', 'aoe'] },

  // ── SJA: Spelljammer Spells ─────────────────────────────────────────────
  { id: 'sja-air-bubble', name: 'Air Bubble', level: 2, school: 'Conjuration', sourceBook: 'SJA', castingTime: '1 action', range: '60 feet', components: ['S'], duration: '24 hours', concentration: false, ritual: false, description: 'You create a spectral globe around the head of a willing creature you can see within range. The globe is filled with fresh air that lasts until the spell ends. If the creature has more than one head, the globe of air appears around only one of its heads (which is all the creature needs to avoid suffocation, assuming that all its heads share the same respiratory system).', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, you can create two additional globes of fresh air for each slot level above 2nd.', classes: ['artificer', 'druid', 'ranger', 'sorcerer', 'wizard'], tags: ['utility', 'survival'] },
  { id: 'sja-create-spelljamming-helm', name: 'Create Spelljamming Helm', level: 5, school: 'Transmutation', sourceBook: 'SJA', castingTime: '1 action', range: 'Touch', components: ['V', 'S', 'M'], materialComponent: 'a crystal rod worth at least 5,000 gp, which the spell consumes', duration: 'Instantaneous', concentration: false, ritual: false, description: 'Holding the rod used in the casting of the spell, you touch a Large or smaller chair that is unoccupied. The rod disappears, and the chair is transformed into a spelljamming helm (see the Astral Adventurer\'s Guide). A spelljamming helm is a magic item that allows its attuned user to propel and steer a ship through space and air.', classes: ['artificer', 'wizard'], tags: ['utility', 'crafting'] },

  // ── SCoC: Strixhaven Spells ─────────────────────────────────────────────
  { id: 'scoc-silvery-barbs', name: 'Silvery Barbs', level: 1, school: 'Enchantment', sourceBook: 'SCoC', castingTime: '1 reaction, which you take when a creature you can see within 60 feet of yourself succeeds on an attack roll, an ability check, or a saving throw', range: '60 feet', components: ['V'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You magically distract the triggering creature and turn its momentary uncertainty into encouragement for another creature. The triggering creature must reroll the d20 and use the lower roll.\n\nYou can then choose a different creature you can see within range (you can choose yourself). The chosen creature has advantage on the next attack roll, ability check, or saving throw it makes within 1 minute. A creature can be empowered by only one use of this spell at a time.', classes: ['bard', 'sorcerer', 'wizard'], tags: ['control', 'utility'] },
  { id: 'scoc-borrowed-knowledge', name: 'Borrowed Knowledge', level: 2, school: 'Divination', sourceBook: 'SCoC', castingTime: '1 action', range: 'Self', components: ['V', 'S', 'M'], materialComponent: 'a book worth at least 25 gp', duration: '1 hour', concentration: false, ritual: false, description: 'You draw on knowledge from spirits of the past. Choose one skill in which you lack proficiency. For the spell\'s duration, you have proficiency in the chosen skill. The spell ends early if you cast it again.', classes: ['bard', 'cleric', 'warlock', 'wizard'], tags: ['utility', 'buff'] },
  { id: 'scoc-kinetic-jaunt', name: 'Kinetic Jaunt', level: 2, school: 'Transmutation', sourceBook: 'SCoC', castingTime: '1 bonus action', range: 'Self', components: ['S'], duration: 'Concentration, up to 1 minute', concentration: true, ritual: false, description: 'You magically empower your movement with dance-like steps, giving yourself the following benefits for the duration:\n• Your walking speed increases by 10 feet.\n• You don\'t provoke opportunity attacks.\n• You can move through the space of another creature, and it doesn\'t count as difficult terrain. If you end your turn in another creature\'s space, you are shunted to the last unoccupied space you occupied, and you take 1d8 force damage.', classes: ['artificer', 'bard', 'sorcerer', 'wizard'], tags: ['movement', 'buff'] },
  { id: 'scoc-vortex-warp', name: 'Vortex Warp', level: 2, school: 'Conjuration', sourceBook: 'SCoC', castingTime: '1 action', range: '90 feet', components: ['V', 'S'], duration: 'Instantaneous', concentration: false, ritual: false, description: 'You magically twist space around another creature you can see within range. The target must succeed on a Constitution saving throw (the target can choose to fail), or the target is teleported to an unoccupied space of your choice that you can see within range. The chosen space must be on a surface or in a liquid that can support the target without the target having to squeeze.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the range of the spell increases by 30 feet for each slot level above 2nd.', classes: ['artificer', 'sorcerer', 'wizard'], savingThrow: 'con', tags: ['teleportation', 'control'] },
  { id: 'scoc-wither-and-bloom', name: 'Wither and Bloom', level: 2, school: 'Necromancy', sourceBook: 'SCoC', castingTime: '1 action', range: '60 feet', components: ['V', 'S', 'M'], materialComponent: 'a withered vine twisted into a loop', duration: 'Instantaneous', concentration: false, ritual: false, description: 'You invoke both death and life upon a 10-foot-radius sphere centered on a point within range. Each creature of your choice in that area must make a Constitution saving throw, taking 2d6 necrotic damage on a failed save, or half as much damage on a successful one. Nonmagical vegetation in that area withers.\n\nIn addition, one creature of your choice in that area can spend and roll one of its unspent Hit Dice and regain a number of hit points equal to the roll plus your spellcasting ability modifier.', atHigherLevels: 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d6 for each slot above 2nd, and the number of Hit Dice that can be spent and added to the healing roll increases by one for each slot above 2nd.', classes: ['druid', 'sorcerer', 'wizard'], damageType: 'necrotic', savingThrow: 'con', tags: ['damage', 'healing', 'area'] },
];

export function getSpell(id: string): Spell | undefined {
  return ALL_SPELLS.find(s => s.id === id);
}

export function getSpellsByClass(classId: string): Spell[] {
  return ALL_SPELLS.filter(s => s.classes.includes(classId));
}
